-- Poems batch 330
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('19ca8c89-7933-46fe-a776-2a218cec2c35','第六郭將求詩久未暇今以寄之','李之儀','宋','宋诗','song-poetry','','[]','烏延一揮手，歲月如奔流。',252,'全唐诗/poet.song.55000.json','["烏延一揮手，歲月如奔流。", "誰知頭半白，重見須雙虬。", "面冷龐一鐵，氣雄吞九州。", "門庭外雖設，毫髮終無留。", "此時可見者，如君實難求。", "人固不易親，而我獨見酬。", "半年話疇昔，論極非謬悠。", "但云置是事，可質爲冥幽。", "功名本何爲，入手如上鈎。", "我每壯其言，心肯屢回頭。", "別來已七月，悵望逾三秋。", "近聞復來此，只尺不相投。", "元戎奉天討，知與造化謀。", "化城兩馳突，直控咽與喉。", "乂斬萬餘級，少快姑蹔休。", "此銳且就養，彼生豈容偷。", "君謂乃吾射，含笑纏臂鞲。", "今秋取天祁，明年入興州。", "遂復都護府，再見萬里遊。", "汾陽異世勳，子政如綴旒。", "未或便相襲，且作仲升侯。"]'),
('4b62ecfe-4b02-488d-b512-e87e84afcf90','送靈臺尉徐舜舉','李之儀','宋','宋诗','song-poetry','','[]','靈臺右鶉首，南北兩山間。',72,'全唐诗/poet.song.55000.json','["靈臺右鶉首，南北兩山間。", "我來春未幾，紅葉繞斑斑。", "與君早相求，携手問兩山。", "折花飲清泉，共此一日閒。", "君才真健敏，詩句如芝蘭。", "娟好秀且靜，馥郁若可餐。"]'),
('003522e5-bc07-4cc7-8756-70c80cfb4a21','赦到後雨遂大作','李之儀','宋','宋诗','song-poetry','','[]','昨夜聞有赦，今朝遂得雨。',289,'全唐诗/poet.song.55000.json','["昨夜聞有赦，今朝遂得雨。", "天澤隨君恩，一灑遍寰宇。", "彼玩尚逋誅，吾土久未還。", "皇靈實神謀，剪復笑談間。", "崢嶸若化城，掃蕩如破竹。", "開田一百里，得土千萬族。", "不雨三四月，壠畝猶燒畬畬。", "禱祈略無應，居哭行嘆嗟。", "豈知有此待，城就師振旅。", "上不輟板築，下不妨野處。", "秋種蓋未晚，及此壯者歸。", "懽呼各著業，賣刀買耕犁。", "山頭夜叱牛，山下婦亦斸。", "老稚旦出耘，勤勞莫歸宿。", "待我土盡墾，俟爾日有餘。", "歸來笑相向，共樂生無虞。", "又聞赦書中，逋欠皆除免。", "更放一年租，其細及移變。", "天公固愛我，吾君豈違天。", "乃知父子間，事事必關連。", "野人語可書，使我喜不寐。", "誰謂彼無知，况欲迷向背。", "我歌本民言，未愧中興詩。", "聞者足以戒，可是轍趨時。"]'),
('2b3157db-7651-4f64-a808-c3164a47b600','端午睡起和韵','李之儀','宋','宋诗','song-poetry','','[]','豈復記佳節，飽食睡亭午。',120,'全唐诗/poet.song.55000.json','["豈復記佳節，飽食睡亭午。", "雖不負此身，倦聽亦良苦。", "念初入此門，只作十日數。", "那知如忍炎，倏爾到角黍。", "本非來質秦，蓋異行怨楚。", "端爲城旦拘，獨與縲紲語。", "深坑偶未埋，大鑊僅逃煮。", "凈持諸願力，妙地叩初祖。", "會當縱奔鹿，遂與搏猛虎。", "蹇余愧平生，何適非齟齬。"]'),
('fd82543b-9b51-423a-a74a-87a35450a696','大雨','李之儀','宋','宋诗','song-poetry','','[]','向晚雲驟合，雨點如車輪。',204,'全唐诗/poet.song.55000.json','["向晚雲驟合，雨點如車輪。", "入夜勢轉暴，對面語不聞。", "初疑坤軸裂，漸覺河海翻。", "傾注恣豪放，溝瀆莫吐吞。", "平地忽五尺，呼叫均四鄰。", "下堰上輒隙，東塞西遽奔。", "一身應百給，坐卧不得申。", "旦自秉鍤刀，彳亍意已昏。", "念茲嗷嗷農，拱手過一春。", "入夏又將半，寸苗無宿根。", "祈禱備衆伎，杳杳天九閽。", "饑殍漫狼藉，極目無煙村。", "及此滂沛澤，一洗瘡痍痕。", "勞我敢有詞，故喜氣已溫。", "置酒會賓客，耕輟翁語孫。", "爾年非可期，我責亦粗伸。", "欲赴固踴躍，感慨扃重門。"]'),
('6660475a-eff3-4af3-8d5d-c68788921a8e','睡起','李之儀','宋','宋诗','song-poetry','','[]','數日不吟語，已覺舌本强。',228,'全唐诗/poet.song.55000.json','["數日不吟語，已覺舌本强。", "熟處自難忘，是乃真苦相。", "簾空睡起足，物我兩俱喪。", "舉頭見南山，依舊禿相向。", "解衣遶屋行，未巾已踉蹌。", "翻書試遮眼，一抹如白浪。", "目足身所先，二者輒相抗。", "生理從可知，何用更惆悵。", "獨有梁上燕，憐我本癡惷。", "時時作好語，似欲致勸奬。", "見爾初銜泥，生子已頡頏。", "而我猶未歸，茲事固難諒。", "安用苦烟塵，無勞獨悽愴。", "俯仰即陳跡，未易煩度量。", "一樽試有求，傳來如鵲盎。", "頓味毒酒酷，猛釂投晚餉。", "倦懷豈復有，舌爛腹斗漲。", "抱薪救烈火，自取將誰讓。", "夜分方半生，劣過逃屬纊。"]'),
('1b1985d6-e7f0-47b5-bd44-c30809c057d6','試郭底泉和韵','李之儀','宋','宋诗','song-poetry','','[]','午睡不覺久，起坐獨捫腹。',168,'全唐诗/poet.song.55000.json','["午睡不覺久，起坐獨捫腹。", "眊矂相苦魔，眩瞀遂爲族。", "永懷建溪春，偶爾得藏畜。", "品第雖非貂，猶勝狗尾續。", "虛堂無纖塵，百轉紛擊筑。", "破碾頓愕眙，屑紛隨輪蹙。", "被褐而懷璧，凡眼真褻凟。", "聊資定碗黑，豈待無托綠。", "久聞城西角，有泉湛寒玉。", "名因所居傳，廉惠纔可僕。", "殷勤持小罌，甘瑩來一掬。", "蟹眼方轉旋，色味相芬馥。", "邇來棘荆生，未易梨栗熟。", "一啜便超騰，庾愁空萬斛。"]'),
('ca847525-b47b-48a0-a553-3e53333ca6c0','晚起和韵','李之儀','宋','宋诗','song-poetry','','[]','今日起差晚，持課幾到午。',144,'全唐诗/poet.song.55000.json','["今日起差晚，持課幾到午。", "饑飽雖難醫，葷酒且入務。", "脫粟快一飯，白眼視寰宇。", "固知等浮沉，要在極纖縷。", "聒耳林鳩嘷，舉頭梁燕乳。", "我亦盡輪回，何必高下數。", "緬懷故山中，泉石潄深塢。", "萬壑響松風，千巖澄月露。", "胡爲不歸去，乃與朱墨侶。", "只記入門時，未有還家路。", "我生詎應爾，炳炳莫我顧。", "彼心豈易同，吾首莫易俯。"]'),
('847d2a9a-9a33-498f-b0ee-fea4f323f7b1','讀淵明詩效其體十首  其一','李之儀','宋','宋诗','song-poetry','','[]','歲月忽云徂，人事只如此。',48,'全唐诗/poet.song.55000.json','["歲月忽云徂，人事只如此。", "胡不及此時，斗酒勞鄰里。", "有田半荒蕪，有屋亦傾圯。", "强顔賓客後，畢竟如何爾。"]'),
('c4b34b0e-4469-474a-804f-4289e986b8e9','讀淵明詩效其體十首  其二','李之儀','宋','宋诗','song-poetry','','[]','淵明棄官歸，議者見各別。',48,'全唐诗/poet.song.55000.json','["淵明棄官歸，議者見各別。", "去就須有名，豈獨爲卑褻。", "折腰分當爾，柴米豈無說。", "舍彼而處此，亦不苟自潔。"]'),
('ba1a053e-fd76-4ff0-b8f2-352859985388','讀淵明詩效其體十首  其三','李之儀','宋','宋诗','song-poetry','','[]','扶疏草木長，茲時豈無情。',48,'全唐诗/poet.song.55000.json','["扶疏草木長，茲時豈無情。", "未論身得去，想像心已清。", "童山久不雨，湯熱氣鬰蒸。", "遣懷一開卷，便覺凉風生。"]'),
('9df76dd5-6feb-43d8-962f-e3a70a23d6af','讀淵明詩效其體十首  其四','李之儀','宋','宋诗','song-poetry','','[]','操檄烏延府，已復十五年。',48,'全唐诗/poet.song.55000.json','["操檄烏延府，已復十五年。", "年當三十餘，事事隨精堅。", "非惟會興靈，兼欲還幽燕。", "誰知今白首，獄吏輒差肩。"]'),
('64083a04-c6d8-4415-b54f-70c8b6bf5ab9','讀淵明詩效其體十首  其五','李之儀','宋','宋诗','song-poetry','','[]','晚來風稍回，漸見布陰雲。',48,'全唐诗/poet.song.55000.json','["晚來風稍回，漸見布陰雲。", "乘時得尺雨，吾農實難勤。", "不願生邊地，報施豈無因。", "我雖不在事，未能忘戚欣。"]'),
('36d4cb1f-e5ec-4fcb-be92-4ed1555c7065','讀淵明詩效其體十首  其六','李之儀','宋','宋诗','song-poetry','','[]','用舍繫臨時，金玉與蒿萊。',48,'全唐诗/poet.song.55000.json','["用舍繫臨時，金玉與蒿萊。", "塵埃混瓦礫，燔燎參樽罍。", "何云長興公，陳迹獨歸來。", "一跌竟不起，念之有餘哀。"]'),
('ce31562d-14dd-4282-ae94-55f7c361af72','讀淵明詩效其體十首  其七','李之儀','宋','宋诗','song-poetry','','[]','我聞瘴癘地，去者無生還。',48,'全唐诗/poet.song.55000.json','["我聞瘴癘地，去者無生還。", "吾凡三十口，歸來盡頹顔。", "死生非人能，得喪亦非天。", "張毅與單豹，要之皆偶然。"]'),
('cad9fd04-2c76-48c0-b35e-b97ae7caa253','讀淵明詩效其體十首  其八','李之儀','宋','宋诗','song-poetry','','[]','朝從空儋出，莫逐頳顔歸。',48,'全唐诗/poet.song.55000.json','["朝從空儋出，莫逐頳顔歸。", "既謝爨無烟，此外將何爲。", "堂堂十六年，子孫反無依。", "莫作如是見，隨遇聊差池。"]'),
('ced270f8-1a7b-4d20-ab60-b1fd8135035a','讀淵明詩效其體十首  其九','李之儀','宋','宋诗','song-poetry','','[]','吾亦愛吾廬，此亦未爲得。',48,'全唐诗/poet.song.55000.json','["吾亦愛吾廬，此亦未爲得。", "死即瘞路傍，要是不免或。", "隨流認得性，有念乃吾賊。", "是以方丈間，千偈終一默。"]'),
('4c7b7db8-4589-41f2-8227-9fc89d47514a','讀淵明詩效其體十首  其一○','李之儀','宋','宋诗','song-poetry','','[]','吾友傅子淵，每見常熙熙。',48,'全唐诗/poet.song.55000.json','["吾友傅子淵，每見常熙熙。", "人固莫我高，我固不人低。", "問其何因爾，我蓋不自知。", "孰爲第一義，只此是菩提。"]'),
('95481648-83f7-4a2d-a625-9ebc35c4b133','烏牙義禪師退居金陵與予有都城之舊能詩喜說修養年七十餘貌類三四十許人以詩道舊因次韵報之','李之儀','宋','宋诗','song-poetry','','[]','幻化如空花，建立等修竹。',96,'全唐诗/poet.song.55000.json','["幻化如空花，建立等修竹。", "四海不離身，一笑長滿掬。", "相逢亦何有，展轉猶所獨。", "攀緣過九上，圓頓繫一宿。", "歲月屈身臂，到此非問卜。", "心清聞妙香，老句俱三復。", "何當會實際，超然發吾覆。", "未爾且逡巡，更待梨早熟。"]'),
('4b93c8b5-b43f-4f41-903b-6509d2e70e77','五雲觀','李之儀','宋','宋诗','song-poetry','','[]','五雲會中天，衆山如朝宗。',96,'全唐诗/poet.song.55000.json','["五雲會中天，衆山如朝宗。", "相臣夙有約，標神期此宮。", "傍有洞天接，面直積金峰。", "常言五百間，斯地將修崇。", "廢興果冥符，變化如雲龍。", "緬懷祥符後，天意固莫窮。", "一言不可復，此興猶未終。", "知國如知葬，尤難邀此翁。"]'),
('83b1f563-986d-47b8-a3d1-7d500e3f4f2c','崇壽宮梁昭明太子修行之地','李之儀','宋','宋诗','song-poetry','','[]','鴻禧已不凡，崇壽氣尤古。',72,'全唐诗/poet.song.55000.json','["鴻禧已不凡，崇壽氣尤古。", "經始天監謀，餘力保大舉。", "十圍人何在，烏鵲尚如睹。", "井泉翳荆棘，像設半塵土。", "視今猶視昔，一笑纔仰俯。", "有媿所坐峰，安得參鶴羽。"]'),
('51d1fac7-c96b-4165-a9d1-11ca439d5cf4','喜客泉','李之儀','宋','宋诗','song-poetry','','[]','取逕輒林莽，得地三尺餘。',72,'全唐诗/poet.song.55000.json','["取逕輒林莽，得地三尺餘。", "名曰喜客泉，客至如湧珠。", "初驚一穗起，逡巡周四隅。", "酌之甘勝醖，瀹茗尤敷腴。", "物理不可詰，感歎常躊躇。", "于焉知福地，未易世眼拘。"]'),
('bc7ba427-0aa6-46f6-afe8-5483fc1cdbce','撫掌泉','李之儀','宋','宋诗','song-poetry','','[]','泓渟宿寒藻，正占山一曲。',96,'全唐诗/poet.song.55000.json','["泓渟宿寒藻，正占山一曲。", "平時常湛然，撫掌珠可掬。", "喜怒去千里，氣類若相屬。", "如何輒示異，乃爾分遲速。", "霜風鼓橐籥，巖樹響絲竹。", "語出若有答，路轉疑絕續。", "幽尋力恨短，博採日苦促。", "便擬寄無餘，捨策遂留宿。"]'),
('b8f7c9e3-cddc-4e2b-8f7b-16b550f18ec1','白鶴觀','李之儀','宋','宋诗','song-poetry','','[]','白鶴不復見，荒臺煨燼餘。',96,'全唐诗/poet.song.55000.json','["白鶴不復見，荒臺煨燼餘。", "昔時三茅君，鶴駕常相於。", "一歲許一會，此地幾其廬。", "倏然自一境，歷攬莫與俱。", "兄弟兩羽人，玉骨太古鬚。", "燒丹云未暇，彈琴聊自娛。", "日佇駕鶴來，夤緣參玉虛。", "身世久已忘，況復話里閭。"]'),
('19a02860-9abb-4425-89d8-19d70a6f2539','九錫庵','李之儀','宋','宋诗','song-poetry','','[]','强臣欲竊命，九錫乃所僭。',96,'全唐诗/poet.song.55000.json','["强臣欲竊命，九錫乃所僭。", "奈何得道人，亦復有此念。", "是非固不同，等欲示其漸。", "石地鑿龍趺，穹載極該贍。", "漫滅半可讀，以足表龜監。", "名存物何在，遺製不少欠。", "帝意豈無謂，人事徒妄占。", "何適非偶然，隨遇始弛擔。"]'),
('aa3df646-5380-4af2-9ab0-22c2f9daff63','華陽洞天','李之儀','宋','宋诗','song-poetry','','[]','洞天名此山，于此實第八。',120,'全唐诗/poet.song.55000.json','["洞天名此山，于此實第八。", "東將秦嶽連，西與岷峨軋。", "磴道端可通，足亦若相戛。", "我欲踵其武，苔徑特見滑。", "屢試輒復却，宛似物初遏。", "周行半天下，是等三四閱。", "有無終可疑，雷同慙小黠。", "退之固頡頑，桃源蓋强說。", "卒謂武陵傳，何殊眼着楔。", "孔子亦獵較，此理信難輟。"]'),
('c9fccc45-e005-45bb-a319-e970eb37effd','玉簫庵今名天聖庵','李之儀','宋','宋诗','song-poetry','','[]','白髮不我貸，青山亦世情。',96,'全唐诗/poet.song.55000.json','["白髮不我貸，青山亦世情。", "斧斤借羨力，遂易當時名。", "吹簫人可想，有念應難平。", "從茲定相忘，那更隨戲成。", "松門插天半，竹逕梳晶熒。", "所期茅茨永，丹碧豈願營。", "含悽振落日，拊事悲頹齡。", "吾生儻與歸，境界滋光明。"]'),
('a6ba486a-e633-4cdf-94cb-056ef2c3b862','陶隠居書堂','李之儀','宋','宋诗','song-poetry','','[]','山雲自往來，人事久蕭索。',96,'全唐诗/poet.song.55000.json','["山雲自往來，人事久蕭索。", "誰爲插小松，記此常棲泊。", "坡陀披淺麓，窈窕带遠壑。", "著書方呻吟，誰與會所樂。", "鸞凰耿莫追，歲月儼如昨。", "隠約玉簫聲，憔悴金匕藥。", "風來萬籟奏，一笑竟難約。", "尚友徒此心，相期在寥廓。"]'),
('3faeaa20-1c56-4e5e-be3a-453fa84426c1','比部文承制移竹贈初秀才堯民有詩因次其韵  其一','李之儀','宋','宋诗','song-poetry','','[]','古人偏愛竹，種不虛一席。',72,'全唐诗/poet.song.55000.json','["古人偏愛竹，種不虛一席。", "相將共忘年，敢憚培且植。", "君家占何方，容易來秀色。", "薙草出明軒，翛然聳修碧。", "剪梢畏風摧，留葉期鳳食。", "從茲兩繭足，閉戶忘所適。"]'),
('ff617b1d-7b4b-4783-bcec-c815c8ab6767','比部文承制移竹贈初秀才堯民有詩因次其韵  其二','李之儀','宋','宋诗','song-poetry','','[]','增築貴堅厚，抨繩避欹側。',84,'全唐诗/poet.song.55000.json','["增築貴堅厚，抨繩避欹側。", "朝灌暮復壓，深虞枯易得。", "勁節既能主，百蠹遂爲客。", "風微吟疏簧，日永齒客屐。", "此況倘可期，吾甘事潛默。", "晉人知自完，皎皎良未息。", "不材謝紛紜，斯言愧安國。"]'),
('3294ab62-ce0b-458d-afd6-2d51f71247bc','離潁昌張聖行獨出城相送','李之儀','宋','宋诗','song-poetry','','[]','黄昏促征鞍，別酒已沾醉。',120,'全唐诗/poet.song.55000.json','["黄昏促征鞍，別酒已沾醉。", "風威危破臘，雪意欲着地。", "超然氣類人，送我奄獨至。", "懸知必如此，恐終欲弗類。", "平生昧歸宿，恍若得所詣。", "胡床十餘語，彷彿京口例。", "此言固近俳，要之不無謂。", "覺夢猶在馬，解鞍定何地。", "百年誰見宰，一己乃許事。", "繾綣兒女情，回首端自愧。"]'),
('8bb40c52-8982-4274-a8c7-db4cfd1befd5','夜投臨潁陸周仲館待甚悉','李之儀','宋','宋诗','song-poetry','','[]','冥行眼忽明，乃是到臨潁。',120,'全唐诗/poet.song.55000.json','["冥行眼忽明，乃是到臨潁。", "倦馬倚風嘶，凍僕望門逞。", "初非敢此期，勢逼豈容傾。", "是身雖無難，從者固當省。", "主人頗料理，燈燭分炯炯。", "熾炭解噤頤，重帷護寒領。", "招魂幾剪紙，感惠非尚褧。", "粲然一笑開，那復嗟斷梗。", "我生且莫落，隨遇輒自警。", "轉盼已歸空，區區徒畫餠。"]'),
('dc3cc3fe-e304-4196-a8be-e81768a3e840','明日阻雪不得行蓋冬至前一日也','李之儀','宋','宋诗','song-poetry','','[]','纔冬即欲雪，醖釀非不久。',120,'全唐诗/poet.song.55000.json','["纔冬即欲雪，醖釀非不久。", "旅館黄昏風，半夜忽如晝。", "天公時謔戲，不在我先後。", "兒心見期心，咫尺弗得就。", "密洒良未已，兀坐幾忍灸。", "遂令相逢心，感慨若奔輳。", "紅爐慘無光，短氣猶發餾。", "況茲嚴報本，供衛何所售。", "風威果能神，排斥勿宿留。", "非獨寸草榮，萬里同錦繡。"]'),
('6a02c733-923c-42b0-9953-d1a958b4c6b9','三家店主人勸飲','李之儀','宋','宋诗','song-poetry','','[]','早飲欲過午，感此去路遙。',120,'全唐诗/poet.song.55000.json','["早飲欲過午，感此去路遙。", "解衣酒家牀，主人喜相招。", "逡巡出餖飣，勸我飲一瓢。", "舉手謝慇懃，宿酲猶未消。", "報言雪滿野，征轡相無聊。", "何如酩酊去，更可忘今朝。", "年來頗解官，徑欲隨所邀。", "端愧五漿期，未覺羣心摇。", "偷薄日益窘，妙論輕鴻毛。", "何當受一廛，醉倒同漁樵。"]'),
('7fcc542f-e261-4184-ad61-fa1601e93aac','得常州感慈邦長老書求詩兼寄鄰老','李之儀','宋','宋诗','song-poetry','','[]','清晨得君書，遠意來吳中。',180,'全唐诗/poet.song.55000.json','["清晨得君書，遠意來吳中。", "開緘一見面，頓覺百慮空。", "書詞若蕭屑，怪我情不通。", "我豈逐物者，君亦如冥鴻。", "便當永相忘，何計騧與驄。", "聞君奮鈐槌，喝下分華戎。", "晚魚會千指，一一麻中蓬。", "朝參月破牖，暮請燈在籠。", "坐令萬折異，沛然俱向東。", "緣契乃如此，想見圭璧叢。", "胡爲特垂手，千里尋龐公。", "龐公無伎倆，只這是家風。", "復如多聞師，亦在兜率宮。", "人間最勝處，何必顔如童。", "會當謝朝謁，爛漫游無窮。"]'),
('563ab523-b9c1-4e8e-8b8b-bcc96f980aa5','寄何德固','李之儀','宋','宋诗','song-poetry','','[]','元豐初得君，賜袍色可摘。',204,'全唐诗/poet.song.55000.json','["元豐初得君，賜袍色可摘。", "雍容戎馬間，爽氣凌秀色。", "十年不相逢，頷鬚已有白。", "京塵化人衣，歲月動阻隔。", "夏屋如深山，排日許連席。", "坐中多可人，一笑每墮幘。", "人皆指爲誇，我輩日所惜。", "于今已三見，爽氣若初得。", "同言胡乃爾，前致作嬌客。", "邊城久不雨，旱氣幾爍石。", "俯仰數刻間，咫尺便南北。", "寄聲不敢輒，問訊莫我獲。", "但問深閉門，鴟坐較定力。", "雙林舊家風，龐老真消息。", "莫作分別想，認子却爲賊。", "造門會有日，聊復銛戈戟。", "準擬詰朝見，無或但堅壁。"]'),
('9bd53b11-547b-46fe-8cba-4a1f2b79bc29','燕子和韵','李之儀','宋','宋诗','song-poetry','','[]','依依梁間燕，終日密相對。',96,'全唐诗/poet.song.55000.json','["依依梁間燕，終日密相對。", "本不欲爾期，何爲尚此會。", "得非緣所遭，又恐意有在。", "飛來復飛來，好語如湍瀨。", "我亦强維縶，爾豈知向背。", "萬事杳靄間，一笑沉吟外。", "玄妙第一義，爲爾降障礙。", "卷簾見天下，始信物有大。"]'),
('202f2c7e-0ccb-4a45-9743-5d3bdaf15c35','次韵方叔晚過湖上時積雨新霽夜色如晝傳聞余有興元之命','李之儀','宋','宋诗','song-poetry','','[]','釃水投過日，佳思生襟裳。',48,'全唐诗/poet.song.55000.json','["釃水投過日，佳思生襟裳。", "緬懷江上笛，相游共胡牀。", "星月弄疏明，草木來遠香。", "所得亦餉爾，端能謝炎凉。"]'),
('b5749c65-7cad-4f94-9103-f8fd412e93b8','方叔并用前韵復繼之','李之儀','宋','宋诗','song-poetry','','[]','蕭然傲環堵，心性嬾衣裳。',48,'全唐诗/poet.song.55000.json','["蕭然傲環堵，心性嬾衣裳。", "匝坐定何許，井井書滿牀。", "我每不欲去，鼻觀無盡香。", "未始有寒暑，彼哉自炎凉。"]'),
('89e0dfe4-5321-4c00-8364-d6118d2a2145','句容澄上人羣玉軒求詩','李之儀','宋','宋诗','song-poetry','','[]','日日不離山，愛山終不厭。',120,'全唐诗/poet.song.55000.json','["日日不離山，愛山終不厭。", "因地端有來，及此若尚欠。", "當軒出巑屼，昏膜遽效砭。", "枝撐簷楹窄，明滅煙雲蹔。", "幽禽時一鳴，隠約隔天塹。", "早聞羣玉峰，世境未易占。", "却應三昧力，易致茲可驗。", "便擬絕高深，兩足恐不贍。", "幻化浪攀緣，膠擾窘囊檻。", "會須揖清風，方暑對枕簟。"]'),
('03ed605d-68a6-4963-b6d5-db04fadc9a35','送忠禪老詣徑山請普覺住天寧萬壽新剎','李之儀','宋','宋诗','song-poetry','','[]','我初遊叢林，得人如滿月。',144,'全唐诗/poet.song.55000.json','["我初遊叢林，得人如滿月。", "細披雲霧間，桂影若可掇。", "旋轉二十年，相半分會別。", "暮途喜可掬，妙語等冰雪。", "告我第一義，光艷忽振發。", "老魔俱辟易，善類隨擊拂。", "是真萬里足，一舉安能輟。", "徑山光蹔韜，夜氣尤昭徹。", "異時摩聊老，薦藉意甚切。", "子果識至人，指顧石必裂。", "出我連城珍，郊廟冠前列。", "無令刖足翁，二獻文爲拙。"]'),
('d7add721-528d-49bb-a179-737f81a1d0cd','因服藥飲酒一盞','李之儀','宋','宋诗','song-poetry','','[]','東坡在黄州，飲酒只飲濕。',180,'全唐诗/poet.song.55000.json','["東坡在黄州，飲酒只飲濕。", "我今又過之，釃漿如虀汁。", "平生不喜酒，興來且莫縶。", "長虹偶爾放，因復投一吸。", "入口舌欲脫，下咽蟲爭泣。", "熇熇腹將裂，窣窣淚莫裛。", "頑涎雜血唾，心悸如鼓集。", "卓爾無一事，荆棘强自入。", "主人固好飲，宿興亦素緝。", "如何似見毒，使我卧復立。", "彷徨日欲落，稍寬困眼澀。", "夢覺天未明，齒頰猶習習。", "是邦居不非，奈此掩弗及。", "昔聞禁酒國，今見毒酒邑。", "作歌寄一笑，倦悶聊救急。"]'),
('7557e814-3686-4cd4-8cac-ac8e03ecd4b4','大暑不可逃偶携數友過湖上因詠老杜槐葉冷淘句凡十人以君王納凉晚此味亦時須得須字','李之儀','宋','宋诗','song-poetry','','[]','百年觀不足，一日樂有餘。',108,'全唐诗/poet.song.55000.json','["百年觀不足，一日樂有餘。", "況茲夏日長，而與君子俱。", "號呶謝呼笑，談論皆詩書。", "門外方爍石，坐上如冰壺。", "仰懷冥冥鴻，俯愧戢戢魚。", "我老百不堪，嗜好終蒲葅。", "殷勤相得心，黄昏尚躊躇。", "追隨自此始，莫厭頻招呼。", "何必得美酒，然後可將須。"]'),
('3b16d89f-cca5-4796-95dc-62f22dd1cecf','張聖行解官入京僚友餞別分韵勸酒得醇字','李之儀','宋','宋诗','song-poetry','','[]','密雪不着地，朔風煖如春。',144,'全唐诗/poet.song.55000.json','["密雪不着地，朔風煖如春。", "天公豈無心，慰此東歸人。", "吾人晚相投，每見每更親。", "踰年稻粱俱，未覺旦暮頻。", "欲識分淺深，蕩蕩風中雲。", "問其美如何，表裏無緇磷。", "深湛子雲默，高廣太丘真。", "汲汲惜日短，奄茲奉離樽。", "莫辭十分斟，酒薄情則醇。", "庶幾一舉盡，涇渭從此分。", "萬里自咫尺，百歲均埃塵。", "行人定向識，他年期問津。"]'),
('8e590393-f364-4985-b74e-98803e19a92e','常州感慈邦老相遇甚款聊復申敘','李之儀','宋','宋诗','song-poetry','','[]','十年不相見，一見情愈親。',216,'全唐诗/poet.song.55000.json','["十年不相見，一見情愈親。", "執手語半塞，但覺頻沾巾。", "別來事多矣，未易咫尺論。", "感君冒雨歸，知君意彌敦。", "邀我過其廬，燈火如春深。", "金碧炫境界，怳然驚一新。", "爲我時置浴，仍爲加柈飧。", "止我腹中饑，振我衣上塵。", "何勞强剪紙，已復收斷魂。", "漆爐接膝坐，軟語尤殷勤。", "閔我憂患餘，漂泊纔此身。", "勸我葬且居，生死相與鄰。", "清晨陟高座，四衆如雲屯。", "展轉敘契闊，博辨河海翻。", "句句不妄發，信矣靈巖孫。", "歲暮能幾何，繾綣誰我溫。", "非君美無度，涇渭那更分。", "相期在來日，擊節徒諄諄。"]'),
('b172ffa3-f4ff-4163-aa43-98010a9e7f04','子重相率遊任園','李之儀','宋','宋诗','song-poetry','','[]','蹈雪入窈窕，蓊蔚如深春。',168,'全唐诗/poet.song.55000.json','["蹈雪入窈窕，蓊蔚如深春。", "左右無佳色，老綠不改新。", "小愒茅茨下，園翁敘慇懃。", "主人謂此翁，好事絕等倫。", "養生惟養花，種種皆躬親。", "每到二三月，爛漫如錦茵。", "問翁何所有，品目如何分。", "翁云世間本，搜採無遺根。", "牡丹三萬株，兼取洛與陳。", "芍藥揚州來，密密攙魚鱗。", "雜花極目是，浩不知涯津。", "四序更代謝，顔色常相因。", "我適來非時，猶得聊逡巡。", "約翁待花開，許我論主賓。"]'),
('d5e1fb3e-7ef6-4554-a09a-ad09b98f7ac2','獨坐有懷張聖行王成伯偶讀摩詰詩因借其韵','李之儀','宋','宋诗','song-poetry','','[]','老鶴志千里，候蟲戒三秋。',132,'全唐诗/poet.song.55000.json','["老鶴志千里，候蟲戒三秋。", "此理定如何，宛在水中洲。", "我師南榮去，生從知北游。", "歲暮良鮮歡，不如狐首丘。", "寒燈伴岑寂，河漢窗間流。", "緬懷雙白璧，路斷水悠悠。", "摩詰頗解事，好語供我求。", "坐令不可遣，奄然隨遇收。", "歸程只旦暮，妙義思賡酬。", "君謂我輩人，吾匪斯人儔。", "且將有限力，相與窮深幽。"]'),
('4728aa52-ac16-4635-92bd-7b26b777cc84','久旱湫舍殆不可遣免一夕雷雨忽作','李之儀','宋','宋诗','song-poetry','','[]','半夜一濯雨，斷夢失炎蒸。',192,'全唐诗/poet.song.55000.json','["半夜一濯雨，斷夢失炎蒸。", "汗甑不復鼓，蚊雷爲之停。", "逡巡萬竅號，破窗風如傾。", "絺帷强主宰，庭砌已滿盈。", "極護老稚奔，懽呼閭里情。", "但覺萬里返，浩蕩隨滄溟。", "掠眼纔閃爍，劈耳俄掀轟。", "豈暇計飄溺，且護嬰兒驚。", "小休月在戶，却視斗挂甍。", "唧唧與啾啾，次第先秋鳴。", "粵從臘雪後，旱魃苦自明。", "焦枯病三農，芽田不滋榮。", "隴畝半坼裂，几席饒蠅虻。", "端若一大難，眊焉猶宿酲。", "點我讀書燈，凉宵聊與征。", "庶几簡牘中，暫寓蠻觸爭。"]'),
('3a8e2a86-117e-418f-b5d5-356e0696477c','讀東坡詩','李之儀','宋','宋诗','song-poetry','','[]','邊州守禦謝沈機，獨喜身閒是道師。',64,'全唐诗/poet.song.55000.json','["邊州守禦謝沈機，獨喜身閒是道師。", "獄吏難堪非素料，病懷無計復何辭。", "空慙南郡三家學，頼有東坡一集詩。", "永日風埃惟愜睡，到頭不比在家時。"]'),
('c426e68f-742f-4f8b-96cb-54d9e5bab02e','次韵見寄  其一','李之儀','宋','宋诗','song-poetry','','[]','矩不成方圓不規，倦途誰與相多儀。',64,'全唐诗/poet.song.55000.json','["矩不成方圓不規，倦途誰與相多儀。", "門深不擬睡教熟，舌强猶防語或知。", "無事且尋黄面老，關心休問碧雲姿。", "此身未必終如此，長日猶吟十首詩。"]'),
('55e9e3ac-09c4-4464-b62c-0db3d6443a2d','次韵見寄  其二','李之儀','宋','宋诗','song-poetry','','[]','東坡流落坐多言，我欲無言亦未全。',64,'全唐诗/poet.song.55000.json','["東坡流落坐多言，我欲無言亦未全。", "好辨懸知非獲己，力行到底信爲賢。", "抱琴有味無彭澤，沽酒何妨問玉川。", "只擬飲呼出門去，强麋置網豈當然。"]'),
('aafd76de-df09-49b1-a6c6-3678beef9a3a','罷官後旋營居舍寄贈存之','李之儀','宋','宋诗','song-poetry','','[]','常恨官居如傳舍，愛君池館葺初成。',64,'全唐诗/poet.song.55000.json','["常恨官居如傳舍，愛君池館葺初成。", "偶同罪垢歸無計，聊喜私巢得蹔營。", "闢戶開窗留晚日，栽花引水趁心情。", "此身何處不可老，況有吾人似弟兄。"]'),
('ef0cf75f-c179-465d-b2e2-54e807707fc7','次韵見問','李之儀','宋','宋诗','song-poetry','','[]','東西南北爲誰忙，蔡澤噤吟舊笑唐。',64,'全唐诗/poet.song.55000.json','["東西南北爲誰忙，蔡澤噤吟舊笑唐。", "路斷不妨頻打睡，心清何必更燒香。", "尋思有似黄州味，潦倒休嗟白髮郎。", "近免竹筒拘月費，主人時亦破慳囊。"]'),
('30964391-e696-4dcc-9800-6bce563f3038','五月旦日','李之儀','宋','宋诗','song-poetry','','[]','睡餘落莫肘難支，節物依然我自衰。',64,'全唐诗/poet.song.55000.json','["睡餘落莫肘難支，節物依然我自衰。", "已悟龍蛇終不爽，何須龜筴强稽疑。", "孤懷佛語雖能遣，歸路佳人已歎遲。", "共弔沉湘無數日，却嗟輕負習家池。"]'),
('830cf5fe-9906-46b6-a785-aebd915dda30','晚雨寄涇州劉晦叔','李之儀','宋','宋诗','song-poetry','','[]','晚來又有數點雨，聲入鄉人拭淚中。',64,'全唐诗/poet.song.55000.json','["晚來又有數點雨，聲入鄉人拭淚中。", "漸喜濃雲初蔽日，只愁深夜却回風。", "閔憐焦槁非無意，祈禱精虔信有功。", "聞不茹葷幾兩月，使君憂樂與民同。"]'),
('8cccd00f-322c-4eaf-a87b-235bc85eff82','端午  其一','李之儀','宋','宋诗','song-poetry','','[]','綵絲百縷紉爲佩，艾葉千窠結作人。',64,'全唐诗/poet.song.55000.json','["綵絲百縷紉爲佩，艾葉千窠結作人。", "散誕何妨兒女戲，漂流不覺歲時新。", "清歌尚記書裙带，舊恨安能弔放臣。", "角黍粉團矜節物，一樽聊與寄逡巡。"]'),
('815a2ec3-b0e7-4677-aaf6-bdaf73fd0ee2','端午  其二','李之儀','宋','宋诗','song-poetry','','[]','曾約佳人端午歸，又期僚友面南池。',64,'全唐诗/poet.song.55000.json','["曾約佳人端午歸，又期僚友面南池。", "誰知猶阻重門鎖，未擬輕爲故國悲。", "九節菖蒲應好在，十圍樗木正相宜。", "微行細約寧忘我，却話今朝會有期。"]'),
('5414340b-891a-4d10-a391-95e03e2c32f5','傅子昌歸興州','李之儀','宋','宋诗','song-poetry','','[]','嘉陵江水接天流，州據江流最上游。',64,'全唐诗/poet.song.55000.json','["嘉陵江水接天流，州據江流最上游。", "憶昔練衣隨跋馬，而今白髮任虛舟。", "慶門譽望聞來久，塞路殷勤得暫酬。", "見說明朝却西去，長亭揮手恨無由。"]'),
('2a13134e-45a1-4218-9419-0566790b2797','余入院二十日相知往往寄聲相勞獨何德固寂然無聞','李之儀','宋','宋诗','song-poetry','','[]','何郎本是風塵外，平日仍同般若因。',64,'全唐诗/poet.song.55000.json','["何郎本是風塵外，平日仍同般若因。", "有底新來便如此，定緣無事不相親。", "薰蕕何得同薝蔔，簡潔安能別孟津。", "會借天河三級浪，終須流出舊精神。"]'),
('27079153-7c26-46ff-b5b5-44c4169e814b','留別子淵','李之儀','宋','宋诗','song-poetry','','[]','等閒相見即相親，冉冉風流一段春。',64,'全唐诗/poet.song.55000.json','["等閒相見即相親，冉冉風流一段春。", "未論典刑思舊德，便知材業是當仁。", "他年雞黍情無限，此日詞章筆有神。", "落盡節旄氈未壓，疾風勁草定何人。"]'),
('fc9277d0-997b-4774-b9a9-695da8a437a4','送馮子莊赴秦州將官述其督詩之語以廣篇首','李之儀','宋','宋诗','song-poetry','','[]','我詩易得君休嘆，君節難攀我自知。',64,'全唐诗/poet.song.55000.json','["我詩易得君休嘆，君節難攀我自知。", "問會但嗟歸有日，奏功方看獨先時。", "簫笳部曲催驕馬，綿繡山川入綵旗。", "莫訝黄金偏滿手，平生□□是男兒。"]'),
('ef888b8d-550a-42e5-8472-a154ea00134b','重治寢榻更衣蔬食','李之儀','宋','宋诗','song-poetry','','[]','五月相將又下旬，依前深院度黄昏。',64,'全唐诗/poet.song.55000.json','["五月相將又下旬，依前深院度黄昏。", "頻看嶺路占家信，旋兀簾旌作燕門。", "抖擻衾裯防垢穢，湔除蚤虱斷兒孫。", "不因肉食脾難磨，且欲從今習菜根。"]'),
('35b032a2-316c-467e-a9f1-630009cec84b','周臣約過景裕第會飲先寄此詩卒章因以投誠也','李之儀','宋','宋诗','song-poetry','','[]','懸知昨過鄰家館，更挽明璫間玉釵。',64,'全唐诗/poet.song.55000.json','["懸知昨過鄰家館，更挽明璫間玉釵。", "雖喜黄姑論隔歲，偶陪摩詰事長齋。", "嘯歌未闋雲間接，鶑燕難逃席上猜。", "預悵醒醒獨回馬，何如爲賦酒如淮。"]'),
('c48de2db-8cf9-43c7-8266-e1f80645da33','次韵題隠居巖','李之儀','宋','宋诗','song-poetry','','[]','隠居何必在山巖，境界全歸指顧間。',64,'全唐诗/poet.song.55000.json','["隠居何必在山巖，境界全歸指顧間。", "能把軒裳爲外物，便應風月勝酡顔。", "地連紫禁千重邃，石繞清泉五色斑。", "從此夢魂猶可到，定知衰廢不容攀。"]'),
('50584e2c-98e3-47f4-b705-9323bb5c2d55','次韵見懷','李之儀','宋','宋诗','song-poetry','','[]','林泉廢疾固難除，杳杳觚稜寄夢餘。',64,'全唐诗/poet.song.55000.json','["林泉廢疾固難除，杳杳觚稜寄夢餘。", "已到東山知不免，須由北海本來疏。", "功名漫笑乘軒鶴，事業終歸種樹書。", "聞道江樓巢已穩，未應長鋏歎無魚。"]'),
('31635aa6-38c5-4f7d-937c-d83cb9478d7c','次韵病起','李之儀','宋','宋诗','song-poetry','','[]','天時人事不相尋，遽食蒸豚廢古吟。',64,'全唐诗/poet.song.55000.json','["天時人事不相尋，遽食蒸豚廢古吟。", "誰感親顔前約短，常知聖日後緣深。", "風雲亹亹天邊路，霜露愔愔壁上琴。", "我亦臨風頻拭目，看懸金印到山林。"]'),
('e5a3b8c0-a40d-4e89-9006-5cde89bd57ab','次韵子椿見寄','李之儀','宋','宋诗','song-poetry','','[]','一逢佳節一消魂，青徹江山綠滿園。',64,'全唐诗/poet.song.55000.json','["一逢佳節一消魂，青徹江山綠滿園。", "又把鋤犁聊自遣，却嗟身世獨難論。", "三鍾切幸資三徑，九奏時猶夢九門。", "勝處何能偏見憶，便應佳思襲香蓀。"]'),
('fe0347c4-67fa-4b14-b90e-e793ca77e812','次韵子椿同關聖源吳思道贈董無求有懷米元章','李之儀','宋','宋诗','song-poetry','','[]','海嶽仙人不我期，碧雲幽恨獨心知。',64,'全唐诗/poet.song.55000.json','["海嶽仙人不我期，碧雲幽恨獨心知。", "坐間優孟已難別，筆下羊欣更出奇。", "自是人才空立異，當知臣叔本非癡。", "重輕到了存公議，揮扇何勞强執葵。"]'),
('fd9c9285-69fd-4e84-a631-642115c7da47','次韵思道子椿題仲强樗亭','李之儀','宋','宋诗','song-poetry','','[]','王門平昔早相求，幾向樗亭得趣幽。',64,'全唐诗/poet.song.55000.json','["王門平昔早相求，幾向樗亭得趣幽。", "從別風光應似舊，每懷勝麗只搔頭。", "麈毛抗論傾終日，玉指挼花泛晚秋。", "老盡鄒陽還憶否，密移空自感藏舟。"]'),
('f92b924c-0829-4362-a161-2652450dbb6b','次韵子椿九日登高見懷兼呈君俞相約尋春','李之儀','宋','宋诗','song-poetry','','[]','重陽曾記客京埃，江國相逢又七回。',64,'全唐诗/poet.song.55000.json','["重陽曾記客京埃，江國相逢又七回。", "感舊只如春夢斷，登高未許壯心摧。", "方嗟陳迹何時見，底事新詩到眼來。", "便好扶携披節物，猶勝落木對空罍。"]'),
('9a11a1f4-d184-4566-b75d-b83e34966147','次韵關聖源送董無求','李之儀','宋','宋诗','song-poetry','','[]','何勞楚些爲招魂，是處春風似僻園。',64,'全唐诗/poet.song.55000.json','["何勞楚些爲招魂，是處春風似僻園。", "可復京塵難共樂，却應江月要深論。", "燈花昨夜占行館，鵲語今朝報里門。", "想見慈顔問行李，一樽浮蟻侑芳蓀。"]'),
('87ae87d9-de24-4fbf-8b43-45d91d545a9b','次韵聖源無求兼懷元章','李之儀','宋','宋诗','song-poetry','','[]','羨門不見見安期，流水高山獨我知。',64,'全唐诗/poet.song.55000.json','["羨門不見見安期，流水高山獨我知。", "門徑踏穿行復爾，靈丹救活信能奇。", "換雖得辨纔三紙，借恐終還是兩癡。", "不用艱難成發塚，紅樓親共賦烹葵。"]'),
('c78cc12e-8a6d-468f-91e6-fbdc88da3b54','次韵思道送董無求兼寄思道','李之儀','宋','宋诗','song-poetry','','[]','骯髒從來不易儔，低徊身世亦悠悠。',64,'全唐诗/poet.song.55000.json','["骯髒從來不易儔，低徊身世亦悠悠。", "離羣斷雁雖難偶，得兩明珠豈待求。", "强挹餘塵時琢句，問尋陳迹自經丘。", "清時醉尉知何在，似是人多識故侯。"]'),
('99f4940b-630a-44fd-a7be-e9ed38ebb37d','和人臘日','李之儀','宋','宋诗','song-poetry','','[]','又聽村村臘鼓鳴，年豐物阜慶清平。',64,'全唐诗/poet.song.55000.json','["又聽村村臘鼓鳴，年豐物阜慶清平。", "星霜陡覺歲華晚，時序祇傷今古情。", "裝景雪花飛點點，催詩雲葉亂英英。", "自慚伏臘尤多誤，和語煩公子細評。"]'),
('80fb58a9-06c8-4fe6-8a05-053cb89a9395','題壽椿軒','李之儀','宋','宋诗','song-poetry','','[]','江左風流不乏人，能將佳思洗埃塵。',64,'全唐诗/poet.song.55000.json','["江左風流不乏人，能將佳思洗埃塵。", "坐中煒燁當時士，庭下扶疏上古椿。", "日永清陰怒鵬翼，月明翠影鬧龍鱗。", "雲泥路絕無由到，猶欲乘槎一問津。"]'),
('018f68cd-d009-4832-bc50-ca512273eced','次韵米元章','李之儀','宋','宋诗','song-poetry','','[]','蹭蹬生涯可否間，强扶衰緒欲觀瀾。',64,'全唐诗/poet.song.55000.json','["蹭蹬生涯可否間，强扶衰緒欲觀瀾。", "蓬生雖託麻方直，器就寧嗟木是蟠。", "晚寄鄉閭端有謂，時容雞黍共論歡。", "連城未薦難爲璞，莫與堅珉一眼看。"]'),
('672680a6-a404-4317-bd5c-005b3fd15207','仲春季澤遠來相訪感往念今悵然有懷','李之儀','宋','宋诗','song-poetry','','[]','異鄉流落十三年，老日從誰寄往還。',64,'全唐诗/poet.song.55000.json','["異鄉流落十三年，老日從誰寄往還。", "久歎斷蓬飄世外，忽驚連璧下雲間。", "生涯已約同他日，詞筆端能慰蹔顔。", "準擬新秋便相見，爲君終日倚柴關。"]'),
('adaa6174-7214-4f07-8246-81a30d96c11f','書王子重閒軒壁','李之儀','宋','宋诗','song-poetry','','[]','經年問疾漫持想，今日登軒念自空。',64,'全唐诗/poet.song.55000.json','["經年問疾漫持想，今日登軒念自空。", "不能碌碌遽如許，定應剪剪將無同。", "人喧渡口似瓜步，木落沙頭疑渚宮。", "莫辭眼力徧沙界，回首臘盡還春風。"]'),
('45b61d72-6554-404e-a804-3cba7df34062','同子重望長蘆寺','李之儀','宋','宋诗','song-poetry','','[]','窣堵波寒對水東，坐來初報夕陽鐘。',64,'全唐诗/poet.song.55000.json','["窣堵波寒對水東，坐來初報夕陽鐘。", "回環桑柘疑無際，咫尺雲煙隔幾重。", "聽講有心陪寂寞，杖藜何日許從容。", "主人境界諸緣盡，應笑規規着畫龍。"]'),
('88f90148-cc1d-4d12-ad90-c627dab35f38','陪子重游長蘆寺','李之儀','宋','宋诗','song-poetry','','[]','行來思住覺城東，粥飯隨緣早晚鐘。',64,'全唐诗/poet.song.55000.json','["行來思住覺城東，粥飯隨緣早晚鐘。", "安得心田荒萬有，便驚眼界失千重。", "笑談喜接真摩詰，衰病休嗟老曼容。", "餿飲殘羹應不惜，聊分水墨爲成龍。"]'),
('b28f94ef-c583-4068-959a-237e060f1e1d','德山方老退院索詩送行即席口占','李之儀','宋','宋诗','song-poetry','','[]','應供都城今幾春，屢陪香火是前因。',64,'全唐诗/poet.song.55000.json','["應供都城今幾春，屢陪香火是前因。", "偶來清瀵堤邊住，重見東林社裏人。", "青眼略容談近事，白頭同喜得閒身。", "自言此去尋思大，便好乘時繼後塵。"]'),
('429d0dbf-b1e4-4ddf-8273-f776f81eff6e','朱伯宣才英昆仲見過曲相慰藉因留飲得花字','李之儀','宋','宋诗','song-poetry','','[]','新春窮巷幾傷嗟，聯璧俄來照蔀家。',64,'全唐诗/poet.song.55000.json','["新春窮巷幾傷嗟，聯璧俄來照蔀家。", "意厚旋傾新釀酒，眼明初見未開花。", "百尋自是松難老，什襲終慙玉有瑕。", "便覺賦成無用處，漫勞憔悴歎長沙。"]'),
('941054d4-f95e-48f7-bb27-8b56b887316a','題僧道符天游齋','李之儀','宋','宋诗','song-poetry','','[]','六鑿相攘不蹔休，超然誰復與天遊。',64,'全唐诗/poet.song.55000.json','["六鑿相攘不蹔休，超然誰復與天遊。", "醯雞甕裏自歌舞，野馬窗間空贅疣。", "妙境果從拈處得，生涯須向箇中求。", "逢場作戲由來事，可笑區區問髑髏。"]'),
('9b9845d0-890b-4a2f-b848-1aaf69554e3d','除夜寄王性之','李之儀','宋','宋诗','song-poetry','','[]','老戀窮年怯五更，可堪爆竹響新聲。',64,'全唐诗/poet.song.55000.json','["老戀窮年怯五更，可堪爆竹響新聲。", "但驚燈火如殘夢，豈有心情敵後生。", "餳競膠牙空對白，酒期分歲獨憐清。", "賜袍應有天香在，想見明朝奉九成。"]'),
('28ba6193-475b-4b6e-940f-f5407eec919f','又寄性之二首  其一','李之儀','宋','宋诗','song-poetry','','[]','霜髯雪鬢十分侵，舉盞常思蘸甲深。',64,'全唐诗/poet.song.55000.json','["霜髯雪鬢十分侵，舉盞常思蘸甲深。", "雖約依劉同漢上，猶虛訪戴似山陰。", "文章歆向傳家日，事業韋平奕世心。", "冰玉相輝方自表，何妨佳思屢追尋。"]'),
('4ac5a43a-508e-451e-b54d-dae2befc148c','又寄性之二首  其二','李之儀','宋','宋诗','song-poetry','','[]','平日鵷鸞接武中，汪汪每歎不能窮。',64,'全唐诗/poet.song.55000.json','["平日鵷鸞接武中，汪汪每歎不能窮。", "蹔煩朱轂圖遺愛，方信清時是至公。", "千載難期人物盛，一時休歎馬羣空。", "何妨坐嘯追陳迹，應有新詩襲素風。"]'),
('9e590836-18a5-42c5-bca1-9c24613aea4f','聽惠師琴','李之儀','宋','宋诗','song-poetry','','[]','牛鬭淹時兩耳昏，偶陪沈祝共僧軒。',64,'全唐诗/poet.song.55000.json','["牛鬭淹時兩耳昏，偶陪沈祝共僧軒。", "數聲抑按披香霧，雙屨分明在曉原。", "物節不堪催我老，賞心聊復爲誰論。", "初年記得山陰舊，又見夷中幾世孫。"]'),
('08478cf7-9b04-4798-91c8-7e69e0d6b16d','春日','李之儀','宋','宋诗','song-poetry','','[]','芊芊芳草望中迷，傳火樓臺麗日西。',64,'全唐诗/poet.song.55000.json','["芊芊芳草望中迷，傳火樓臺麗日西。", "飛絮輕翻遮柳陌，落花亂點暗桃溪。", "琉璃波凈沈魚藻，玳瑁簾疏阻燕泥。", "百五良辰最葱蒨，綠陰行馬過鶑啼。"]'),
('89daded5-03ca-477d-883d-acc0b93e7027','覺老求詩','李之儀','宋','宋诗','song-poetry','','[]','江南江北久相望，常負靈山一炷香。',64,'全唐诗/poet.song.55000.json','["江南江北久相望，常負靈山一炷香。", "會上拈花雖未笑，坐中持鉢頓生光。", "投針技倆空諸有，彈指莊嚴自一方。", "何必湯池能離垢，入門心地已清凉。"]'),
('aaf16332-0a37-486a-9ef0-dc8c47117297','覺老見和復次韵報之時雨行未得','李之儀','宋','宋诗','song-poetry','','[]','去隴回岡翼兩傍，舊緣來繼鶴林香。',64,'全唐诗/poet.song.55000.json','["去隴回岡翼兩傍，舊緣來繼鶴林香。", "隨時解致留客雨，涉世圓能出定光。", "運用投機疑有象，縱橫垂手固無方。", "倦遊累接通宵語，時覺楊枝灑面凉。"]'),
('5875e6cc-479d-4d68-9c53-b173654f2a7b','真師約過寄老菴雨不止兩日不得往小霽輒涉淖以契前約次其所示韵菴壁有孫莘老秦少游劉貢父諸君詩','李之儀','宋','宋诗','song-poetry','','[]','一接深言一點頭，離騷致處未爲幽。',64,'全唐诗/poet.song.55000.json','["一接深言一點頭，離騷致處未爲幽。", "不嫌壞路容連步，且欲他年作舊游。", "翰墨抑揚雖已晚，林泉棲止會終收。", "孤雲祗恐元無定，候我歸來共此丘。"]'),
('c8f5c360-c5e7-4cdc-950d-869a62f6671d','次韵陳致君題硃砂湯','李之儀','宋','宋诗','song-poetry','','[]','造化工夫豈偶然，一池如沸自澄鮮。',64,'全唐诗/poet.song.55000.json','["造化工夫豈偶然，一池如沸自澄鮮。", "論功但可資沐浴，有理不須深究研。", "流落未妨供凈社，升沉何用較溫泉。", "更宜場稼猶能就，凡占餘波盡美田。"]'),
('24717109-038d-4b05-aa49-19c25e2ba8f3','同祖燈過陳氏書齋主人留飯遂求詩','李之儀','宋','宋诗','song-poetry','','[]','一牛吼地得林坰，邂逅經行眼暫明。',64,'全唐诗/poet.song.55000.json','["一牛吼地得林坰，邂逅經行眼暫明。", "挾策讀書雖未暇，殺雞炊黍喜相迎。", "依依高柳來棲鵲，炯炯黄花弄晚晴。", "自是主人能好事，非關秋日解多情。"]'),
('6d2cba2a-4782-41ec-a30f-c07eebd3e337','石磧朱希仲館穀甚勤因題壁間','李之儀','宋','宋诗','song-poetry','','[]','主人好客久聞名，曾約江魚對酒烹。',64,'全唐诗/poet.song.55000.json','["主人好客久聞名，曾約江魚對酒烹。", "邂逅相逢同一笑，逡巡不覺到三更。", "屠龍手段元非策，畫虎工夫浪有聲。", "便欲與君論卒歲，却憂舟子報潮平。"]'),
('656db6e4-2e09-4c89-ae6a-1b0911581d3b','清凉寺覺海召飯出數帖相示覽之愴然求詩爲記','李之儀','宋','宋诗','song-poetry','','[]','潮去潮來知幾年，依然城郭带山川。',64,'全唐诗/poet.song.55000.json','["潮去潮來知幾年，依然城郭带山川。", "連虛玉骨元如虎，布地金沙舊種蓮。", "垂手鼎開香積供，傳家仍是乳峰禪。", "珠庭月角人何在，頼有遺蹤契宿緣。"]'),
('721e944d-7670-4326-a9ab-f7dd07b33ab9','崇寧求詩時正初老住爲初祖','李之儀','宋','宋诗','song-poetry','','[]','烏衣人物已成空，窣堵纔能記寶公。',64,'全唐诗/poet.song.55000.json','["烏衣人物已成空，窣堵纔能記寶公。", "請祝驟開新福地，全提還振舊家風。", "千巖日上春初到，萬里雲收月正中。", "欲識投機無意盡，江流入海幾時窮。"]'),
('16e88da7-017b-4415-9c1f-3769478357d9','范倅置酒雨花臺','李之儀','宋','宋诗','song-poetry','','[]','流傳勝致有無間，投老方能一倚欄。',64,'全唐诗/poet.song.55000.json','["流傳勝致有無間，投老方能一倚欄。", "千里江山來極目，萬家烟雨鎖初寒。", "姦雄幾許埋蓁莽，笑語何妨擁蕙蘭。", "便覺寸陰真可惜，須將酒戶爲君寬。"]'),
('06f4be26-2fdb-49b8-adb4-847e7ecec5f5','寄趙仰之','李之儀','宋','宋诗','song-poetry','','[]','傾蓋逢君亦偶然，塤篪今日似當年。',64,'全唐诗/poet.song.55000.json','["傾蓋逢君亦偶然，塤篪今日似當年。", "仙風宛是金華舊，詩句分明歷水傳。", "故國江山聊徙倚，深燈歌笑屢遷延。", "相思果許重相見，豫約嚴裝報此緣。"]'),
('fb4c75b5-81bf-4501-87cd-efb4a3706526','次韵邦老見貺','李之儀','宋','宋诗','song-poetry','','[]','高風疇昔在煙霞，末路芝蘭屬當家。',64,'全唐诗/poet.song.55000.json','["高風疇昔在煙霞，末路芝蘭屬當家。", "一句轉身元的確，千條差路任紛華。", "才疏意廣雖難契，語款情真特見嘉。", "只恐平明便分手，相看更待月西斜。"]'),
('31657312-ed45-4b39-aed6-dd43934e1eaa','宿無錫壽聖院贈明祖禪老','李之儀','宋','宋诗','song-poetry','','[]','靈山相別已多年，重把圓光信有緣。',64,'全唐诗/poet.song.55000.json','["靈山相別已多年，重把圓光信有緣。", "愧我天涯真斷梗，喜君居處似諸天。", "元無浮世多般事，只說我家一味禪。", "軟語綢繆霜夜永，停燈溫火共留連。"]'),
('a7d5c4b0-8594-4404-b230-851cd35f3da4','元白拏舟相訪出紙求書因書此以歸其紙','李之儀','宋','宋诗','song-poetry','','[]','小篷不卸遠相尋，頓喜忘年得斷金。',64,'全唐诗/poet.song.55000.json','["小篷不卸遠相尋，頓喜忘年得斷金。", "便覺雨華隨脫麈，更能操筆問來禽。", "投懷方寄朱弦直，摻袂還驚白髮深。", "獨幸南遊慰真賞，他年會見好叢林。"]'),
('813f3dbd-5518-4ea5-97e3-23724d6512d7','同熙績姪登有美堂','李之儀','宋','宋诗','song-poetry','','[]','雪晴時節臘窮天，湖海光浮萬井煙。',64,'全唐诗/poet.song.55000.json','["雪晴時節臘窮天，湖海光浮萬井煙。", "勝槩尚能驚老眼，曠懷無復似當年。", "難堪塞雁終聯翼，頼有龍駒特象賢。", "已約一廛須卜築，不妨當此共遷延。"]'),
('6c8a9dbe-5477-4b0b-ba9d-0a0dcaa629c5','錢塘教授宅飯眠齋次其韵','李之儀','宋','宋诗','song-poetry','','[]','饑時囓飯困時眠，任運騰騰信自然。',64,'全唐诗/poet.song.55000.json','["饑時囓飯困時眠，任運騰騰信自然。", "豈謂故人投此況，先來佳處作閒仙。", "寓懷何必開三徑，得句勝如食萬錢。", "只恐里門驚內史，不容同占好山川。"]'),
('885ea4dd-d6a6-420e-b5d9-8ea60e05a8ff','次韵錢塘節士見寄','李之儀','宋','宋诗','song-poetry','','[]','平日刳心欲致君，異時携手但論文。',64,'全唐诗/poet.song.55000.json','["平日刳心欲致君，異時携手但論文。", "興來只有歸田賦，老去何如背水軍。", "占勝已驚無不盡，卜鄰應許鎮相溫。", "形容豈敢輕酬酢，謝傅風流自出羣。"]'),
('ddb0b240-13ef-444f-887b-509f9ff56391','阿濫堆  其一','李之儀','宋','宋诗','song-poetry','','[]','鐵作驕幢不易摧，望林誰免渴趨梅。',64,'全唐诗/poet.song.55000.json','["鐵作驕幢不易摧，望林誰免渴趨梅。", "院門報鑰人初斷，天氣纔陰日又開。", "倦路已先衰鬢雪，思家難遣寸心灰。", "衝風正起還飛下，何物元非阿濫堆。"]'),
('7cf6f1d5-d4b0-4a33-835e-876b9f6adad6','阿濫堆  其二','李之儀','宋','宋诗','song-poetry','','[]','年來未覺壯心摧，昨夜偏傷三弄梅。',64,'全唐诗/poet.song.55000.json','["年來未覺壯心摧，昨夜偏傷三弄梅。", "不慣離家遽如許，自然昏眼亦慵開。", "蕭條寂寞思樗蔭，細繹華嚴謝劫灰。", "少味童山莫分別，直須真峭比離堆。"]'),
('317eea29-6abc-4080-aef3-ca4d315581c3','食牛炙','李之儀','宋','宋诗','song-poetry','','[]','西來誰爲炙牛心，惜事拘文不敢尋。',64,'全唐诗/poet.song.55000.json','["西來誰爲炙牛心，惜事拘文不敢尋。", "豈謂鄰邦無百里，驟令饞口得千金。", "登臺未論前人比，捫腹翻驚用思深。", "從此耒陽休弔古，便思白酒與同斟。"]'),
('54a58fd1-843d-4d8c-9ca2-3edf4cc30cea','元祐末宿秋試院曾和王敏父四詩是時以疾先出院方欲出而未得況味有類今日追用前韵再賦四首  其一','李之儀','宋','宋诗','song-poetry','','[]','階除又見日將斜，若此奔馳尚可誇。',64,'全唐诗/poet.song.55000.json','["階除又見日將斜，若此奔馳尚可誇。", "敢覬陰功踵定國，未應和藥困王嘉。", "門前禱雨頻催鼓，眼底無人但見花。", "不比貢闈當日鎖，病來有許便還家。"]'),
('0cfa82f9-623b-40f0-9f35-863453d065a3','元祐末宿秋試院曾和王敏父四詩是時以疾先出院方欲出而未得況味有類今日追用前韵再賦四首  其二','李之儀','宋','宋诗','song-poetry','','[]','兼材莫作尹翁歸，自鬻崎嶇不畏非。',64,'全唐诗/poet.song.55000.json','["兼材莫作尹翁歸，自鬻崎嶇不畏非。", "妄役土龍寧得雨，可堪芻狗强蒙衣。", "移文不報如沉井，行路皆疑鎮掩扉。", "早悟垂頭供立仗，好隨四牡去騑騑。"]'),
('3f2a805c-c290-47c8-b49e-552ed054ef82','元祐末宿秋試院曾和王敏父四詩是時以疾先出院方欲出而未得況味有類今日追用前韵再賦四首  其三','李之儀','宋','宋诗','song-poetry','','[]','沉沉深鎖出無涯，白盡于思豈復華。',64,'全唐诗/poet.song.55000.json','["沉沉深鎖出無涯，白盡于思豈復華。", "準擬歸期叩端午，那知此地見葵花。", "幽憂未論如陰府，倏忽翻驚走電車。", "久病元來最欺眼，蠅頭只覺似棲鴉。"]'),
('ff33b766-3ff4-4d79-9a6c-e6f13e483118','元祐末宿秋試院曾和王敏父四詩是時以疾先出院方欲出而未得況味有類今日追用前韵再賦四首  其四','李之儀','宋','宋诗','song-poetry','','[]','十年三拜東門敕，長是尋燈濯汙裾。',64,'全唐诗/poet.song.55000.json','["十年三拜東門敕，長是尋燈濯汙裾。", "贏得平安題報曆，不妨朋友校殘書。", "歌傳鵲鼠非行路，詠入烏狐愧大車。", "物物背馳將老矣，定知身世欲何如。"]'),
('d14efc20-0051-4520-b681-da4b9bcddde5','若禔告行再寄二詩  其一','李之儀','宋','宋诗','song-poetry','','[]','前日報君明日行，强憑詩句寫離情。',64,'全唐诗/poet.song.55000.json','["前日報君明日行，强憑詩句寫離情。", "懸知北海經旬別，須滯韶山半日程。", "環席已甘攙上首，餘罍應不負同傾。", "預期一笑東門外，剩記樽前醉裏聲。"]'),
('6bff570f-5464-423f-b7c3-43db54e7b5d1','若禔告行再寄二詩  其二','李之儀','宋','宋诗','song-poetry','','[]','醉裏新聲解記無，祗應琴意似相如。',64,'全唐诗/poet.song.55000.json','["醉裏新聲解記無，祗應琴意似相如。", "近來公道偏難得，從此佳期敢妄圖。", "玉室金堂有阻隔，兔葵燕麥恨扶疏。", "冥鴻不比尋常雁，試覓蕭娘一紙書。"]'),
('5921d7e6-42d9-4720-8552-76848a7cbc0d','陽翟道中有懷存之二首  其一','李之儀','宋','宋诗','song-poetry','','[]','頑陰將臘襲衣褠，倦轡臨風愧白頭。',64,'全唐诗/poet.song.55000.json','["頑陰將臘襲衣褠，倦轡臨風愧白頭。", "一事無成還歲晚，百年過半尚人謀。", "天邊漫鑄黄金印，月下何時紫綺裘。", "擬借東鄰分一徑，未應人物謝羊求。"]'),
('d9ee27b1-316f-4aee-92dc-27c294fa3900','陽翟道中有懷存之二首  其二','李之儀','宋','宋诗','song-poetry','','[]','夕陽風裏得君心，常約清香带月尋。',64,'全唐诗/poet.song.55000.json','["夕陽風裏得君心，常約清香带月尋。", "紅萼似披經幾嗅，綠條如弄已難禁。", "野狂不慣娉婷醉，蓬鬢偏宜蓓蕾侵。", "準擬歸時更浮動，瓊樽寧謝十分斟。"]'),
('1dc68981-c0ff-4dea-934a-95ccc12c23a8','次韵梅花  其一','李之儀','宋','宋诗','song-poetry','','[]','送臘迎春亦是常，獨高梅蘂報年芳。',64,'全唐诗/poet.song.55000.json','["送臘迎春亦是常，獨高梅蘂報年芳。", "風來彷彿逢荀令，月下分明見壽陽。", "開徧漫誇千種韵，天然別是一般香。", "從今漏泄東君意，直到霜前菊蘂黄。"]'),
('278e45ff-1cbf-47dc-97b5-9c6ca8729bfc','次韵梅花  其二','李之儀','宋','宋诗','song-poetry','','[]','嶺上纔分一寸光，羣花次第促來粧。',64,'全唐诗/poet.song.55000.json','["嶺上纔分一寸光，羣花次第促來粧。", "絕勝羣玉山頭見，須信昭儀體自香。", "妙賞不逢徒老去，佳期難得爲誰芳。", "定應癢處無人會，空怨相邀客姓王。"]'),
('00c8f43f-2207-48d2-b441-878cc768395e','智臣相過成小詩','李之儀','宋','宋诗','song-poetry','','[]','紺髮朱顔氣吐虹，崢嶸頭角振家風。',64,'全唐诗/poet.song.55000.json','["紺髮朱顔氣吐虹，崢嶸頭角振家風。", "千金自晦鄒王後，一笑時游管郭中。", "老子已應終汩沒，諸兒聊爲指窮通。", "他年朱紫相輝地，莫惜高軒訪此翁。"]'),
('c0d28ed5-9c6b-48d7-9be8-a34762bdfb52','瑛侍者欲再游方作此勉之','李之儀','宋','宋诗','song-poetry','','[]','精神秀發真獅子，聳壑昂霄似出林。',64,'全唐诗/poet.song.55000.json','["精神秀發真獅子，聳壑昂霄似出林。", "擊竹有聲先了悟，拈花微笑已知音。", "新詩富健疑披錦，妙字清奇不換金。", "往往秋高又飛錫，白雲來去本無心。"]'),
('307dc473-84af-47f7-b15e-0b275557fe9e','有送梅花者而彥行適在君俞來','李之儀','宋','宋诗','song-poetry','','[]','來時點滴纔彷彿，今日爛漫將飛揚。',64,'全唐诗/poet.song.55000.json','["來時點滴纔彷彿，今日爛漫將飛揚。", "春事不知尚多少，客懷空自成悲傷。", "新名侯喜足詩思，舊病維摩難藥方。", "共飲節食冷相對，少須陳子同飛觴。"]'),
('41b7b030-f388-4662-885f-9173f4072b81','失題九首  其一','李之儀','宋','宋诗','song-poetry','','[]','結束輕裝趁曉風，崎嶇行李偶難同。',64,'全唐诗/poet.song.55000.json','["結束輕裝趁曉風，崎嶇行李偶難同。", "他年誰謂雙成老，今日翻爲無是公。", "秪恐穰侯遲見事，固應原憲本非窮。", "洛陽煙靄因緣在，雞黍相期定不空。"]'),
('a0f29098-8c3e-4e09-a32c-e6164537a12d','失題九首  其二','李之儀','宋','宋诗','song-poetry','','[]','上番新梢與舊齊，啄殘紅腐半成泥。',64,'全唐诗/poet.song.55000.json','["上番新梢與舊齊，啄殘紅腐半成泥。", "畫船似覺去已晚，麗句猶堪手自題。", "氣候相催雖迅速，笑歌贏得暫招携。", "紅舒綠卷分前後，全勝當年白集西。"]'),
('5d491e8f-0eb2-42bd-bd13-bd537878d967','失題九首  其三','李之儀','宋','宋诗','song-poetry','','[]','君方陵愈我慙郊，大瓠爲舟浪自要。',64,'全唐诗/poet.song.55000.json','["君方陵愈我慙郊，大瓠爲舟浪自要。", "老矣獨期雲駃便，歸與長負桂叢招。", "崢嶸紅橘迎風密，點滴安榴掠望燒。", "多謝□萌滋味永，便思飛步到楊寥。"]'),
('991284b5-3601-4694-b123-ac4c4e5f304e','失題九首  其四','李之儀','宋','宋诗','song-poetry','','[]','佳禽百囀不驚風，午日濛濛睡眼中。',64,'全唐诗/poet.song.55000.json','["佳禽百囀不驚風，午日濛濛睡眼中。", "幾片猶飛殘臘白，數枝初見出牆紅。", "低回節物憐遷客，漂泊生涯難老翁。", "多謝春光相擊拂，一樽傾倒許誰同。"]'),
('618719b8-1a56-4bba-b94e-83d4d6a28dea','失題九首  其五','李之儀','宋','宋诗','song-poetry','','[]','窺豹曾容見一斑，孤高凜凜固難攀。',64,'全唐诗/poet.song.55000.json','["窺豹曾容見一斑，孤高凜凜固難攀。", "早應拔宅朝元去，猶有遺蹤在世間。", "舒嘯款談雖可想，賞風吟月未終閒。", "諸郎莫爲功名老，須信移文下北山。"]'),
('e6a76185-09c8-4990-9a4c-0cc3c8966742','失題九首  其六','李之儀','宋','宋诗','song-poetry','','[]','映月臨燈萬萼披，喜隨賓客宴芳菲。',64,'全唐诗/poet.song.55000.json','["映月臨燈萬萼披，喜隨賓客宴芳菲。", "諸姨隊合驪山曉，獵騎夜從雲夢歸。", "須把玉觴酬勝麗，徒勞彩筆强依稀。", "回頭便見飄紅雨，莫惜頻歌金縷衣。"]'),
('f02c9954-bdd8-46a5-8792-94e821a78b02','失題九首  其七','李之儀','宋','宋诗','song-poetry','','["\u897f\u6e56"]','映月西湖漾鴨頭，墮紅飄碧正飛浮。',64,'全唐诗/poet.song.55000.json','["映月西湖漾鴨頭，墮紅飄碧正飛浮。", "逢師來自日邊路，如我遂歸江上州。", "嵩嶺異花開未遍，洛川新燕語方柔。", "經行須作半年計，歸去當知難再求。"]'),
('448de237-3e4c-4cd0-9b19-d3e594b26ee6','失題九首  其八','李之儀','宋','宋诗','song-poetry','','[]','薄雲疏雨灑雕籠，槎拂銀潢月上弓。',64,'全唐诗/poet.song.55000.json','["薄雲疏雨灑雕籠，槎拂銀潢月上弓。", "紅淚半殘歌後燭，翠濤低湧夢回風。", "淬餘劍鍔雖爲利，解盡犀稜未見通。", "杳杳芝田定何許，斷魂無計脫驚鴻。"]'),
('784cc37c-637e-4668-a32e-291c29ba95be','失題九首  其九','李之儀','宋','宋诗','song-poetry','','[]','華榱曾記孔鸞棲，斷夢還來拂舊題。',64,'全唐诗/poet.song.55000.json','["華榱曾記孔鸞棲，斷夢還來拂舊題。", "妙悟從誰識無射，賞心空自感雌霓。", "干雲寶氣層霄外，埋玉孤墳落照西。", "千載相逢定何許，嘐嘐風雨獨鳴雞。"]'),
('b9177c62-fdff-4f39-bb06-821cc5e3c9d5','聞葬者','李之儀','宋','宋诗','song-poetry','','[]','鐃鈸高低與哭聲，同尋此路不相驚。',64,'全唐诗/poet.song.55000.json','["鐃鈸高低與哭聲，同尋此路不相驚。", "年來自是多傷感，簾外何須問晦明。", "未返耕桑真拙計，長縈韁鎖奈虛名。", "無名可戀何貪着，缾罄須休莫强傾。"]'),
('31a9798a-6aee-4ecc-9dbc-45be5ff4f832','過蒲地寺謁田承居','李之儀','宋','宋诗','song-poetry','','[]','蕭寺經行舊，騷人趣尚幽。',48,'全唐诗/poet.song.55000.json','["蕭寺經行舊，騷人趣尚幽。", "從來不妄許，相見若爲愁。", "稅駕終何地，乘桴可共舟。", "感君詩有味，老去復誰求。"]'),
('485caff7-a194-4a0a-88e2-c54ce5c2643a','子重見過夜話','李之儀','宋','宋诗','song-poetry','','[]','坐久日將落，窗前雲欲平。',120,'全唐诗/poet.song.55000.json','["坐久日將落，窗前雲欲平。", "倦遊淹歲月，旅悶等坻京。", "已謝長楊賦，猶懷古劍行。", "擁爐雖有味，琢句苦難成。", "一笑逢吾友，諸方舊著名。", "景山慙絕臏，擊節愧深耕。", "奧妙窮三際，堅剛敵萬兵。", "誰知俯冬杪，頓覺得春榮。", "繾綣桑榆恨，間關兒女情。", "金篦何足道，闇室斗光明。"]'),
('a4e70cf5-484a-42fb-b414-815d42050130','三家店早飲主人似喜余至而庭下殘花猶在也酒客輒見避余固止之因得攬其醉態  其一','李之儀','宋','宋诗','song-poetry','','[]','再過三家店，還投舊酒壚。',48,'全唐诗/poet.song.55000.json','["再過三家店，還投舊酒壚。", "重攀紅躑躅，爭認白髭鬚。", "所惜自拘束，無因同拍扶。", "他年遂卜築，終爲伴歌呼。"]'),
('909f2c65-4e7a-45d2-a104-533ad4dc4b60','三家店早飲主人似喜余至而庭下殘花猶在也酒客輒見避余固止之因得攬其醉態  其二','李之儀','宋','宋诗','song-poetry','','[]','醉人休見避，我恨未如君。',48,'全唐诗/poet.song.55000.json','["醉人休見避，我恨未如君。", "到了輸他樂，何須强自分。", "稻粱姑取足，雞鶩漫離羣。", "上馬衝寒去，回頭愧壟雲。"]'),
('8b374ff0-395c-4986-a463-7fb7eb6123ec','次韵真師移植新竹','李之儀','宋','宋诗','song-poetry','','[]','錦綳方有托，粉面轉相疑。',48,'全唐诗/poet.song.55000.json','["錦綳方有托，粉面轉相疑。", "漸露凌雲節，微分弄月枝。", "高僧開檻賞，野客带砧移。", "只恐成龍去，空來款此時。"]'),
('bb112b99-9ad3-4bd8-9794-db42c54b2bef','宿湯泉示真師二首  其一','李之儀','宋','宋诗','song-poetry','','[]','睡美不覺曉，蛻然猶戀牀。',48,'全唐诗/poet.song.55000.json','["睡美不覺曉，蛻然猶戀牀。", "未能忘夜旦，已自懶衣裳。", "供佛添新水，持經續舊香。", "不知門外路，何事有歸艎。"]'),
('ca353d5e-87c4-481d-84ea-748728999175','宿湯泉示真師二首  其二','李之儀','宋','宋诗','song-poetry','','[]','粥後復就枕，夢中還在家。',48,'全唐诗/poet.song.55000.json','["粥後復就枕，夢中還在家。", "老身知自妄，病厭事如麻。", "漸覺同芻狗，終當悟寶車。", "何妨驀直去，細啜趙州茶。"]'),
('cb9a2869-013e-40ad-b2e3-700159d004c6','朱希仲設榻溫密與真師榻相對明日雨止送過金陵','李之儀','宋','宋诗','song-poetry','','[]','居士留我宿，虛堂照一燈。',48,'全唐诗/poet.song.55000.json','["居士留我宿，虛堂照一燈。", "如逢永平夢，仍對竹蘭僧。", "彷彿三無慍，間關百不能。", "平明失簷溜，歡喜話金陵。"]'),
('c8096d05-0144-4ba4-9d2a-1c187b1459cf','真師自湯泉相送至石磧遂歸索詩爲別','李之儀','宋','宋诗','song-poetry','','[]','流落不我棄，如君能幾人。',48,'全唐诗/poet.song.55000.json','["流落不我棄，如君能幾人。", "寧辭迂驛路，且喜慰情親。", "蹭蹬還逢雨，因循懶問津。", "尤慙遠相送，誰謂白頭新。"]'),
('48190dc6-d25b-463d-a113-17b3a38064ae','石磧阻雨夜分睡覺枕上','李之儀','宋','宋诗','song-poetry','','[]','一夜雨不止，渡江還不能。',48,'全唐诗/poet.song.55000.json','["一夜雨不止，渡江還不能。", "誰知未歸客，獨自對孤燈。", "祿食强作主，生涯端是僧。", "都來如一夢，隨處且騰騰。"]'),
('4bf6dedd-cfa3-49eb-9c98-f38d9941aa59','遊石磧寺寺僧以牌求詩','李之儀','宋','宋诗','song-poetry','','[]','花石鎖風烟，軒楹半是山。',48,'全唐诗/poet.song.55000.json','["花石鎖風烟，軒楹半是山。", "門連虎溪路，橋接趙州關。", "屈曲深疑步，高低屢解顔。", "却應多是夢，不伴此身閒。"]'),
('d91470fd-ff1b-4676-b977-e9404f153db9','茅山道中抵莫投一客邸甚素雅主人喜客乃一善士爲待至厚既別留此致謝','李之儀','宋','宋诗','song-poetry','','[]','客緒如繰繭，山行似踏車。',48,'全唐诗/poet.song.55000.json','["客緒如繰繭，山行似踏車。", "方疑武陵宿，宛是德公家。", "傾蓋君何厚，論心我可嗟。", "祗應從此別，去路隔雲霞。"]'),
('ad2847fb-5d38-475f-8c9a-72b8c45f3e6f','除夜小舟中雨不止而作雪寄德麟','李之儀','宋','宋诗','song-poetry','','[]','醉侶今何在，寒燈倍黯然。',48,'全唐诗/poet.song.55000.json','["醉侶今何在，寒燈倍黯然。", "却應聽雨夢，猶是散花天。", "老境不自得，客程誰我憐。", "曉鐘催去路，明日又新年。"]'),
('d15601f9-4606-4a54-a4dd-b84dd777c9f7','腰痛醫者饋藥以酒爲使命酒對燈欲飲不能','李之儀','宋','宋诗','song-poetry','','[]','我固不善酒，醉中常獨顛。',96,'全唐诗/poet.song.55000.json','["我固不善酒，醉中常獨顛。", "不詞譏濩落，秪恐負妖妍。", "迹類懷沙悴，心馳濁世翩。", "空樽聊口誑，繼晷漫膏然。", "未分窮投魏，長思夜刷燕。", "蛇驚元有影，蟻慕本無羶。", "兀坐疑癡鶴，忘形已蛻蟬。", "滄溟雖可徑，何意逐鯨鱣。"]'),
('aed8763c-f56d-46ae-9975-1823556f18ab','燈下試婺源楊生筆和韵','李之儀','宋','宋诗','song-poetry','','[]','跼蹐數椽內，回旋蹞步中。',96,'全唐诗/poet.song.55000.json','["跼蹐數椽內，回旋蹞步中。", "艱生乃至此，吾道得非窮。", "詢鞠元無術，行移底是功。", "可堪追兔鼠，强學注魚蟲。", "未厭朝虀綠，生憎夜燭紅。", "呻吟慙杜老，感慨謝終童。", "奏剡何時發，微連幾日通。", "親知遙悵望，應是轉衰翁。"]'),
('422bab49-2b85-4d52-885a-aa70bc7cedd4','江上獨坐','李之儀','宋','宋诗','song-poetry','','[]','春至猶飄雪，江寒未有魚。',48,'全唐诗/poet.song.55000.json','["春至猶飄雪，江寒未有魚。", "無人慰青眼，盡日對紅爐。", "瑟瑟窗頻響，愔愔鳥强呼。", "潸然不自覺，豈待到窮途。"]'),
('cd0a9706-4c5e-40a4-bd3e-0b32a8e9d3b8','書崇寧觀黄道士火柜壁','李之儀','宋','宋诗','song-poetry','','[]','地肺聞名久，崇寧請祝初。',48,'全唐诗/poet.song.55000.json','["地肺聞名久，崇寧請祝初。", "仙家豈興廢，物理自乘除。", "羽客論歡舊，紅爐勸坐俱。", "斯須竟何有，聊復慰窮途。"]'),
('a3c8dc53-10da-48fb-8728-8d17352e43cc','同趙德麟宿長河堰僧房德麟適相送至此且約明春再相會有詩見及次其韵','李之儀','宋','宋诗','song-poetry','','[]','涔涔一夜雨，皎皎百年心。',48,'全唐诗/poet.song.55000.json','["涔涔一夜雨，皎皎百年心。", "歲路無多日，僧牀有剩衾。", "長卿空滌器，季子漫多金。", "頼有綈袍舊，春風定可尋。"]'),
('9212237f-6d72-4cc1-b2ac-dacf7fdd407f','大觀四年二月二日自采石過藏雲取路回遠少憩已入夜遂留宿明日聰師相邀登覽偶見西偏地真一方之勝也余方營葬庶幾得之以託妙緣既去因留此詩','李之儀','宋','宋诗','song-poetry','','[]','挑菜逢今日，藏雲訪近山。',48,'全唐诗/poet.song.55000.json','["挑菜逢今日，藏雲訪近山。", "路紆知晝永，心遠覺身閒。", "未信塵埃隔，猶疑夢寐間。", "佳城更何卜，便好輟孱顔。"]'),
('d7f13904-5745-4a33-8c46-696fcae6186f','書長干僧房二首  其一','李之儀','宋','宋诗','song-poetry','','[]','赤手能搏虎，青氈不與偷。',48,'全唐诗/poet.song.55000.json','["赤手能搏虎，青氈不與偷。", "真知外物重，未放此緣休。", "平地見山嶽，排空回斗牛。", "何須待塵劫，才許證前秋。"]'),
('74133e77-b90f-4b28-874f-2b68c8b867d3','書長干僧房二首  其二','李之儀','宋','宋诗','song-poetry','','[]','問訊無尺寸，順風留歲時。',48,'全唐诗/poet.song.55000.json','["問訊無尺寸，順風留歲時。", "傳聞萬金積，未嘆一生疲。", "突兀端可想，高明還此期。", "他年問初祖，却是寧馨兒。"]'),
('590dc371-5ed5-4ec1-a864-d48e221b7483','和東坡贈嶺上老人','李之儀','宋','宋诗','song-poetry','','[]','過眼崎嶇等劫灰，到頭榮悴本誰裁。',32,'全唐诗/poet.song.55000.json','["過眼崎嶇等劫灰，到頭榮悴本誰裁。", "須知此老心如鐵，看盡行人幾往回。"]'),
('6af5d80a-6a34-4c80-ad8c-f3e080d8aba3','大觀四年春夏之交閒居無事觸緒成咏得絕句五首  其一','李之儀','宋','宋诗','song-poetry','','[]','簷間百囀已鶑聲，枕上千山尚未明。',32,'全唐诗/poet.song.55000.json','["簷間百囀已鶑聲，枕上千山尚未明。", "老去只知難得睡，兒童何用報陰晴。"]'),
('e18a0696-f74c-4c4a-8355-e032c35b152c','大觀四年春夏之交閒居無事觸緒成咏得絕句五首  其二','李之儀','宋','宋诗','song-poetry','','[]','身世低回不自期，個中消息更誰知。',32,'全唐诗/poet.song.55000.json','["身世低回不自期，個中消息更誰知。", "江邊折盡青青柳，才見雲頭月畫眉。"]'),
('63c5a26f-6839-4b62-8b2f-1c004141a1a3','大觀四年春夏之交閒居無事觸緒成咏得絕句五首  其三','李之儀','宋','宋诗','song-poetry','','[]','楸花落盡楝花繁，門巷人稀半是村。',32,'全唐诗/poet.song.55000.json','["楸花落盡楝花繁，門巷人稀半是村。", "好事憑誰消濕熱，一簾疏雨下黄昏。"]'),
('46ded067-b76b-4b21-bb3d-ad84930f603c','大觀四年春夏之交閒居無事觸緒成咏得絕句五首  其四','李之儀','宋','宋诗','song-poetry','','[]','庭前日轉樹交陰，坐上風來境自深。',32,'全唐诗/poet.song.55000.json','["庭前日轉樹交陰，坐上風來境自深。", "度曲已嗟千里客，聽蟬已寄兩頭心。"]'),
('4e532d04-fcbd-477e-92fe-0cbdd637e24c','大觀四年春夏之交閒居無事觸緒成咏得絕句五首  其五','李之儀','宋','宋诗','song-poetry','','[]','江南塞北遍曾遊，一飯何方不可留。',32,'全唐诗/poet.song.55000.json','["江南塞北遍曾遊，一飯何方不可留。", "快筯舊嘗便蠻耳，垂涎安得飫饘頭。"]'),
('49b2cd60-9178-42b5-ad01-50e52fc5400b','題柳氏園','李之儀','宋','宋诗','song-poetry','','[]','昔年車馬遶芳叢，倒盡金缸卧醉紅。',32,'全唐诗/poet.song.55000.json','["昔年車馬遶芳叢，倒盡金缸卧醉紅。", "可惜穠華俱掃地，兔葵燕麥自春風。"]'),
('1783091a-6e0e-418a-abe6-14f49b93cd15','書真公軒','李之儀','宋','宋诗','song-poetry','','[]','松陰苔徑曲盤盤，古佛殘燈古殿間。',32,'全唐诗/poet.song.55000.json','["松陰苔徑曲盤盤，古佛殘燈古殿間。", "却羨老僧無個事，一生長伴白雲閒。"]'),
('007c8638-2463-4fb3-b679-bd8701274d59','偶題','李之儀','宋','宋诗','song-poetry','','[]','新荷點水麥花齊，一抹殘陽露淺暉。',32,'全唐诗/poet.song.55000.json','["新荷點水麥花齊，一抹殘陽露淺暉。", "回首西山歸未得，片心還逐暮雲飛。"]'),
('80789b78-33cf-4d13-816e-9426c9332239','首夏','李之儀','宋','宋诗','song-poetry','','[]','嬌紅掃盡綠陰成，便覺庭虛暑氣生。',32,'全唐诗/poet.song.55000.json','["嬌紅掃盡綠陰成，便覺庭虛暑氣生。", "旋拂藤床方竹枕，不妨鼻息作雷鳴。"]'),
('6fc37ca7-933c-497c-9670-6b2abc3896a5','晦迹','李之儀','宋','宋诗','song-poetry','','[]','晦迹丘園敢自圖，幸逢泉石作幽居。',32,'全唐诗/poet.song.55000.json','["晦迹丘園敢自圖，幸逢泉石作幽居。", "明窗隠几有餘樂，一炷清香卧勘書。"]'),
('aed91bc4-4fdf-4fd2-946e-94047e0abcb2','餉茶不容少待二絕  其一','李之儀','宋','宋诗','song-poetry','','[]','玉骨冰肌體自輕，非關茗飲覺神清。',32,'全唐诗/poet.song.55000.json','["玉骨冰肌體自輕，非關茗飲覺神清。", "無端墮落紅塵裏，碾就雲腴不許烹。"]'),
('aac83e2f-a29d-480f-97c7-3108f733ad00','餉茶不容少待二絕  其二','李之儀','宋','宋诗','song-poetry','','[]','厭厭酒病結春陰，鄰笛傳來恨更深。',32,'全唐诗/poet.song.55000.json','["厭厭酒病結春陰，鄰笛傳來恨更深。", "擬借春風聯袂去，遏雲佳處託知音。"]'),
('9f02f8c9-4d51-4a22-a618-15a3d496b71a','罷官後稍謝賓客十絕  其一','李之儀','宋','宋诗','song-poetry','','[]','過從頓謝懶尤添，倦卧終朝不捲簾。',32,'全唐诗/poet.song.55000.json','["過從頓謝懶尤添，倦卧終朝不捲簾。", "晚飯都無官米氣，始知身已是蒼黔。"]'),
('f9aae5b6-2fec-4437-a715-0cf8cae29a3e','罷官後稍謝賓客十絕  其二','李之儀','宋','宋诗','song-poetry','','[]','獨展離騷弔逐臣，尚存殘角報重闉。',32,'全唐诗/poet.song.55000.json','["獨展離騷弔逐臣，尚存殘角報重闉。", "時節自新人易老，未應閒處似他人。"]'),
('6bc6cf6d-bb4c-4256-8ddc-2abd776689e0','罷官後稍謝賓客十絕  其三','李之儀','宋','宋诗','song-poetry','','[]','憶逢新火客秦川，繡嶺歸來浴暖泉。',32,'全唐诗/poet.song.55000.json','["憶逢新火客秦川，繡嶺歸來浴暖泉。", "從古盛衰如反掌，纍纍何地不新阡。"]'),
('73371298-e853-4061-91a3-5b3c6484321e','罷官後稍謝賓客十絕  其四','李之儀','宋','宋诗','song-poetry','','[]','旋營香火拂塵埃，市井聲傳隠隠雷。',32,'全唐诗/poet.song.55000.json','["旋營香火拂塵埃，市井聲傳隠隠雷。", "頓覺林泉歸已晚，姑從閒處看花開。"]'),
('7db2b9fb-274e-4282-a558-ec8be1c492db','罷官後稍謝賓客十絕  其五','李之儀','宋','宋诗','song-poetry','','[]','貪着崎嶇信可羞，誤將鬼錄作天遊。',32,'全唐诗/poet.song.55000.json','["貪着崎嶇信可羞，誤將鬼錄作天遊。", "東山自是力不足，細論前途有底憂。"]'),
('be607398-4428-46b7-8509-505f1c93bfe6','罷官後稍謝賓客十絕  其六','李之儀','宋','宋诗','song-poetry','','[]','春風浩蕩思無涯，老病縈仍苦戀家。',32,'全唐诗/poet.song.55000.json','["春風浩蕩思無涯，老病縈仍苦戀家。", "推枕不知真早晚，小窗披雨一庭花。"]'),
('fb7f1434-0b81-4739-914f-807f4cab52f9','罷官後稍謝賓客十絕  其七','李之儀','宋','宋诗','song-poetry','','[]','極目湖光徹骨清，無風猶覺尚堅冰。',32,'全唐诗/poet.song.55000.json','["極目湖光徹骨清，無風猶覺尚堅冰。", "心安處處皆堪樂，未必西南是得朋。"]'),
('bc401f96-112a-4de0-b128-94079ef7f29c','罷官後稍謝賓客十絕  其八','李之儀','宋','宋诗','song-poetry','','[]','十仞驚湍拂面寒，恐人如在百勝竿。',32,'全唐诗/poet.song.55000.json','["十仞驚湍拂面寒，恐人如在百勝竿。", "飛雲舞鶴形容處，英爽端疑共此看。"]'),
('bdd2d901-860d-4843-ac9c-0840e3cfcbb7','罷官後稍謝賓客十絕  其九','李之儀','宋','宋诗','song-poetry','','[]','求田問舍本無期，廢棄衰年適此時。',32,'全唐诗/poet.song.55000.json','["求田問舍本無期，廢棄衰年適此時。", "未擬沃州那舊隠，且從新托試維持。"]'),
('e96b8b48-f697-449e-9b12-2026953da710','罷官後稍謝賓客十絕  其一○','李之儀','宋','宋诗','song-poetry','','[]','何須歎世鹿皮翁，得句真能發笑容。',32,'全唐诗/poet.song.55000.json','["何須歎世鹿皮翁，得句真能發笑容。", "誰謂祖風無與寄，寸莛終愧觸洪鐘。"]'),
('559c98c6-bb0a-481c-8551-7056ecbf74ce','次韵李方叔宋鎮立秋五絕  其一','李之儀','宋','宋诗','song-poetry','','[]','渡口人歸月上鈎，蕭蕭風葉荻花秋。',32,'全唐诗/poet.song.55000.json','["渡口人歸月上鈎，蕭蕭風葉荻花秋。", "因君指出詩人語，便向庭前欲買舟。"]'),
('314e9525-7e51-4afb-8ec2-8f3dd695a063','次韵李方叔宋鎮立秋五絕  其二','李之儀','宋','宋诗','song-poetry','','[]','雨闇煙昏蔚不開，時時白鳥去還來。',32,'全唐诗/poet.song.55000.json','["雨闇煙昏蔚不開，時時白鳥去還來。", "相逢都是江湖上，莫爲人聲却自猜。"]'),
('8d6f1f7f-6e84-482f-8cde-0a92d17a1eb6','次韵李方叔宋鎮立秋五絕  其三','李之儀','宋','宋诗','song-poetry','','[]','秋熱春寒花不老，雲濃日薄雨頻收。',32,'全唐诗/poet.song.55000.json','["秋熱春寒花不老，雲濃日薄雨頻收。", "共言今歲魚偏熟，舊網須教展一籌。"]'),
('8467b3d1-0a12-4bc0-aeea-2eaafe481c98','次韵李方叔宋鎮立秋五絕  其四','李之儀','宋','宋诗','song-poetry','','[]','撈蝦摸蜆幾回來，斗笠蓑衣安在哉。',32,'全唐诗/poet.song.55000.json','["撈蝦摸蜆幾回來，斗笠蓑衣安在哉。", "將謂此生緣已斷，登臨不覺眼重開。"]'),
('d1e40a04-601e-42d3-98c3-a6f4e949e8da','次韵李方叔宋鎮立秋五絕  其五','李之儀','宋','宋诗','song-poetry','','[]','南北區區浪自催，不妨隨遇且徘徊。',32,'全唐诗/poet.song.55000.json','["南北區區浪自催，不妨隨遇且徘徊。", "鱸魚白酒何須得，一醉端從好句來。"]'),
('26711899-301c-4090-a595-a1658b444942','與晉卿相別忽復春深得書見邀','李之儀','宋','宋诗','song-poetry','','[]','留陶淵明把酒椀，送陸修靜過虎溪。',32,'全唐诗/poet.song.55000.json','["留陶淵明把酒椀，送陸修靜過虎溪。", "胸次九流清似鏡，人間萬事醉如泥。"]'),
('7d7d4036-7be5-4426-a7f4-9945bdc54f4a','水僊花二絕  其一','李之儀','宋','宋诗','song-poetry','','[]','得水能僊天與奇，寒香寂寞動冰肌。',32,'全唐诗/poet.song.55000.json','["得水能僊天與奇，寒香寂寞動冰肌。", "仙風道骨今誰有，淡掃蛾眉簪一枝。"]'),
('332544f3-9149-4384-a53c-72f116b54228','水僊花二絕  其二','李之儀','宋','宋诗','song-poetry','','[]','借水開花亦自奇，冰沈爲骨玉爲肌。',32,'全唐诗/poet.song.55000.json','["借水開花亦自奇，冰沈爲骨玉爲肌。", "寒香自壓酴醾倒，只比江梅無好枝。"]'),
