('7340b9c9-ee3c-4d5a-ab02-71b0a1a38a80','失題二絕  其二','李之儀','宋','宋诗','song-poetry','','[]','楚國曾聞照乘珠，間因齊盜取爲娛。',32,'全唐诗/poet.song.55000.json','["楚國曾聞照乘珠，間因齊盜取爲娛。", "人亡人得何須計，端有龜腸恨晚厨。"]'),
('88fec3d3-d101-4a82-8158-372c76f5a0b8','次韵子椿五首  其一','李之儀','宋','宋诗','song-poetry','','[]','會次定多古語，筆端無復時流。',28,'全唐诗/poet.song.55000.json','["會次定多古語，筆端無復時流。", "骯髒若非投分，崎嶇肯共經丘。"]'),
('3c8bc5a2-90ca-4205-a077-2d206a9e4eb5','次韵子椿五首  其二','李之儀','宋','宋诗','song-poetry','','[]','昨夜中秋好月，今朝類試終場。',28,'全唐诗/poet.song.55000.json','["昨夜中秋好月，今朝類試終場。", "遙想客窗對酒，未知野飯同堂。"]'),
('55c6989c-d541-4c24-ace7-d946c14ae683','次韵子椿五首  其三','李之儀','宋','宋诗','song-poetry','','[]','踏碎瓊瑶聊步，行陪笑語多時。',28,'全唐诗/poet.song.55000.json','["踏碎瓊瑶聊步，行陪笑語多時。", "一段難逢佳事，五篇消得新詩。"]'),
('144827df-5af0-4beb-a1e1-2bec1b73c046','次韵子椿五首  其四','李之儀','宋','宋诗','song-poetry','','[]','龍欲興雲致雨，虎能墮地成斑。',28,'全唐诗/poet.song.55000.json','["龍欲興雲致雨，虎能墮地成斑。", "端是便騎賜馬，不須深戀家山。"]'),
('17020e15-e922-47d4-afb4-bcc9483ff218','次韵子椿五首  其五','李之儀','宋','宋诗','song-poetry','','[]','附見誰爲鄒湛，奬成無復山濤。',28,'全唐诗/poet.song.55000.json','["附見誰爲鄒湛，奬成無復山濤。", "豈敢遽名此地，不如且醉歸舠。"]'),
('8a72e7df-1212-4b25-890e-1abdc6f1a8e8','又次韵三絕  其一','李之儀','宋','宋诗','song-poetry','','[]','款步昔陪下澤，劇談今愧高流。',28,'全唐诗/poet.song.55000.json','["款步昔陪下澤，劇談今愧高流。", "又喜秋來相見，暫同南陌東丘。"]'),
('31f6ca5e-2200-4896-a4f5-21c03850e048','又次韵三絕  其二','李之儀','宋','宋诗','song-poetry','','[]','華屋暫離星斗，滄江歸弄波濤。',28,'全唐诗/poet.song.55000.json','["華屋暫離星斗，滄江歸弄波濤。", "可得遽通來信，便知却整還舠。"]'),
('3c1b59cc-c291-458f-93fd-d27750d381dd','又次韵三絕  其三','李之儀','宋','宋诗','song-poetry','','[]','旱日能詩傳信，新來投筆從班。',28,'全唐诗/poet.song.55000.json','["旱日能詩傳信，新來投筆從班。", "身世且依魏闕，煙雲休戀鍾山。"]'),
('60479cea-fbd3-4b7d-a661-d1375ba52054','旌德王承議挽詞','李之儀','宋','宋诗','song-poetry','','[]','彭蠡湖邊一笑初，綠衣相見論葭莩。',64,'全唐诗/poet.song.55000.json','["彭蠡湖邊一笑初，綠衣相見論葭莩。", "四千里外空搔首，三十年來屢攬鬚。", "方卜他時共蘭若，豈知今日奠生芻。", "窮途只有思君淚，無復吟君屋上烏。"]'),
('31877ac7-2be7-437c-a2a7-15742fd36a03','錢君倚夫人仙源郡君挽詞','李之儀','宋','宋诗','song-poetry','','[]','春生復秋落，物物猶帝力。',192,'全唐诗/poet.song.55000.json','["春生復秋落，物物猶帝力。", "哀哉劬勞恩，甘藟至誠實。", "棘心詠詩人，常恐一旦失。", "何乃不我報，皎皎如白日。", "痛哉胡爲生，每念氣填臆。", "仰君猶長庚，華髮萃衆德。", "歲時捧金樽，門戶幾萬石。", "常云我有子，未易先尺璧。", "伯仁非碌碌，到此輒自惑。", "庶幾德有相，睥睨莫我逼。", "頗聞君有言，既跌不見謫。", "李杜苟齊名，死且不足惜。", "孰不斯言愧，謂君壽無極。", "豈知屬纊書，何爲在吾側。", "堂堂古益友，千載同此室。", "撼鐸倘能參，我淚不虛滴。"]'),
('0afc4e13-5b7d-41cc-9384-ee4c503340b6','俞清老挽詞二首  其一','李之儀','宋','宋诗','song-poetry','','[]','生涯真斷梗，身世委虛舟。',48,'全唐诗/poet.song.55000.json','["生涯真斷梗，身世委虛舟。", "直欲超千劫，都將付一漚。", "縱橫無滯礙，遊戲任沈浮。", "報盡隨緣去，聊從一笑休。"]'),
('ee8b0b0f-3c0b-418e-bf8e-710c45c4998a','俞清老挽詞二首  其二','李之儀','宋','宋诗','song-poetry','','[]','寒食相披拂，方時欲適然。',48,'全唐诗/poet.song.55000.json','["寒食相披拂，方時欲適然。", "君應尋故約，我亦赴新阡。", "但怪沈來雁，那知已逝川。", "風流有千里，未愧昔人賢。"]'),
('c8b584ba-229c-41b5-b97f-f50cdf211a61','陳氏母夫人挽詞二首  其一','李之儀','宋','宋诗','song-poetry','','[]','白首嚴冰雪，清風逼里閭。',48,'全唐诗/poet.song.55000.json','["白首嚴冰雪，清風逼里閭。", "空殘貝葉偈，不見錦囊書。", "表表名終在，詵詵慶有餘。", "會如華夏約，他日看高車。"]'),
('a91b4849-e94a-4cb1-b74a-07ee129e709e','陳氏母夫人挽詞二首  其二','李之儀','宋','宋诗','song-poetry','','[]','子令人空毀，孫賢我故欽。',48,'全唐诗/poet.song.55000.json','["子令人空毀，孫賢我故欽。", "成家信如玉，傳世果非金。", "不作尋常去，方知積累深。", "天花長滿裓，應悟本來心。"]'),
('ac41592a-06d4-4060-b735-98d1df4feed6','雜挽詩四首  其一','李之儀','宋','宋诗','song-poetry','','[]','報地三千籙，年光八十春。',48,'全唐诗/poet.song.55000.json','["報地三千籙，年光八十春。", "却尋來處路，重接社中人。", "杖履空平日，幢幡想去塵。", "蓮開布金底，又見一番新。"]'),
('3776aa15-1ab9-4e17-9bd2-714d9d029025','雜挽詩四首  其二','李之儀','宋','宋诗','song-poetry','','[]','方報先同穴，俄聞改葬期。',48,'全唐诗/poet.song.55000.json','["方報先同穴，俄聞改葬期。", "祇應偕老約，不擬異他時。", "已矣如何憾，賢哉有剩悲。", "會看松柏路，賜篆聳豐碑。"]'),
('ecddf2fc-4db5-487f-a9d3-742307db911e','雜挽詩四首  其三','李之儀','宋','宋诗','song-poetry','','[]','漢室傳經後，唐朝舊族家。',48,'全唐诗/poet.song.55000.json','["漢室傳經後，唐朝舊族家。", "柔明惟典則，專靜輟紛華。", "得配同高壽，流光固未涯。", "定應知去路，門外列三車。"]'),
('2d883cdf-298e-46a1-be40-ccb10dc64da4','雜挽詩四首  其四','李之儀','宋','宋诗','song-poetry','','[]','子令欽平昔，多慙接俊遊。',48,'全唐诗/poet.song.55000.json','["子令欽平昔，多慙接俊遊。", "升堂稱有志，執奠嘆無由。", "逝水空歸壑，春風忽變秋。", "簫聲到原盡，千載想風流。"]'),
('7c202749-2e65-4878-892c-929c00096051','觀世音贊','李之儀','宋','宋诗','song-poetry','','[]','大慈大悲大威德，補陀落山住孤絕。',64,'全唐诗/poet.song.55000.json','["大慈大悲大威德，補陀落山住孤絕。", "三界輪迴若熱惱，一聞我名便清凉。", "名雖可聞見不得，隨所建立即如見。", "施者受者不退心，常如心在光明裏。"]'),
('67d69332-8cc1-4682-af39-21b79452916f','維摩居士贊','李之儀','宋','宋诗','song-poetry','','[]','毗耶離城，此去幾許。',50,'全唐诗/poet.song.55000.json','["毗耶離城，此去幾許。", "一睹慈光，如到其所。", "八萬四千，翻風駕雨。", "枯者即榮，墮者斯舉。", "周徧恒沙，了無一語。"]'),
('3e8fb0c7-4dad-452e-bd22-b846f814e81b','慧嚴永長老贊','李之儀','宋','宋诗','song-poetry','','[]','我昔同登法雲地，道場不異耆闇山。',64,'全唐诗/poet.song.55000.json','["我昔同登法雲地，道場不異耆闇山。", "指出後身自在通，當日曾聞新受記。", "秀眉明目壞色衣，誰其寫成比丘相。", "只這便是紫金容，在在處處咸恭敬。"]'),
('2bae7f28-c26f-4aa3-a69c-0913c6ec9cd7','西菴琳老真贊','李之儀','宋','宋诗','song-poetry','','[]','西菴老人，誰不贊歎。',63,'全唐诗/poet.song.55000.json','["西菴老人，誰不贊歎。", "東轍西蹊，路頭坐斷。", "維三昧力，化身千百。", "北雨南雲，青天霹靂。", "豈待形容，何處不見。", "須知鬧市裏，便是百草頭薦。"]'),
('b2cf6d10-485a-45c9-8d5b-5e1cddb7b314','常州薦福琄老真贊','李之儀','宋','宋诗','song-poetry','','[]','無形而襲人之鼻者香，不謀而同人之舌者名。',85,'全唐诗/poet.song.55000.json','["無形而襲人之鼻者香，不謀而同人之舌者名。", "名因香而及遠，香因名而有聲。", "然則紅梅老子固如是乎。", "投闇即闇，投明即明。", "隨波逐浪，應物觀形。", "夫是之謂馿手佛脚，而真得無學於保寧者也。"]'),
('9d095a88-d3e4-4d3a-8931-8ad934f36160','雲門大師真贊','李之儀','宋','宋诗','song-poetry','','[]','織得蒲鞋無脚著，大雪漫山却伸脚。',64,'全唐诗/poet.song.55000.json','["織得蒲鞋無脚著，大雪漫山却伸脚。", "嬲人枉了三則語，傳家只用一字錯。", "至今兒孫滿天下，伸頭縮頸如鸛鶴。", "捩轉嘴面有商量，學得馬騎被馿撲。"]'),
('32758660-a71b-40f6-b887-30253dc2bf72','雪峰真贊','李之儀','宋','宋诗','song-poetry','','[]','衮毬輸了一隻脚，答語失了一隻眼。',64,'全唐诗/poet.song.55000.json','["衮毬輸了一隻脚，答語失了一隻眼。", "却將兩隻殺人手，不妨撈蝦只摸蜆。", "踏翻船子月是誰，撞破烟樓如掣電。", "樹倒藤枯笑呵呵，春光更覺家家遍。"]'),
('701858f9-d19b-4bb8-8745-bf509edceda7','晦堂寶覺真贊','李之儀','宋','宋诗','song-poetry','','[]','不勉而中，不思而得。',100,'全唐诗/poet.song.55000.json','["不勉而中，不思而得。", "從容中道，是爲極則。", "胡來胡現，漢來漢現。", "隨所運用，莫非方便。", "在邇求遠，知深昧淺。", "頭上安頭，以口爲眼。", "以相而現，略無異同。", "一有所扣，則猶撞鐘。", "緣不我契，漫爾形容。", "稽首導師，如日方中。"]'),
('5c90e133-9e52-4cc1-aac9-a076cc96b63a','李太白贊','李之儀','宋','宋诗','song-poetry','','[]','龍不可收，虎不可縛。',60,'全唐诗/poet.song.55000.json','["龍不可收，虎不可縛。", "矯矯世路，彼自清濁。", "醉遣脫靴，孰貴孰賤。", "弄月滄波，萬頃一綫。", "圖畫如好，雖曰糟粕。", "對之超然，鯨尾欲捉。"]'),
('297f2b7e-3297-4fa0-9c62-41235e5474c9','姑溪自贊  其一','李之儀','宋','宋诗','song-poetry','','[]','蒿目以遊千世，鐵心以踐其志。',58,'全唐诗/poet.song.55000.json','["蒿目以遊千世，鐵心以踐其志。", "有時端委以即事，忽爾賣針而買醉，豈所謂逆行順行莫測者歟。", "蓋得之自是不得，是以聽天命而已。"]'),
('0440d28d-2709-4a64-9b87-c636015e1f95','姑溪自贊  其二','李之儀','宋','宋诗','song-poetry','','[]','偶乘扁舟，一日千里。',90,'全唐诗/poet.song.55000.json','["偶乘扁舟，一日千里。", "若遇勝境，終年不移。", "故能屈御手調羹而親餉，命力士脫靴而不疑。", "予私淑諸人也，故欲與之同歸。", "鴉然于腮而不售，羊然遶領而猶癡。", "人固欲其售，爾謂之癡也，予方遊戲以隨時。"]'),
('3f53af48-2edf-49aa-83a5-72c13a55cbc8','李伯時畫姑溪濯足圖贊','李之儀','宋','宋诗','song-poetry','','[]','濯余足兮寒泉，振余衣兮古丘。',42,'全唐诗/poet.song.55000.json','["濯余足兮寒泉，振余衣兮古丘。", "洞胸中之滯礙，眇雲散而水流。", "識此行之非禍，乃造物之予休。"]'),
('4ff77a7c-e9ec-4bd7-88e3-b31d1f12672e','董曼老畫姑溪贊','李之儀','宋','宋诗','song-poetry','','[]','野老形容，公子刷砑。',62,'全唐诗/poet.song.55000.json','["野老形容，公子刷砑。", "謂俗則數珠掛于臂上，謂僧則髭鬚滿于頷下。", "以我爲牛則爲之牛，以我爲馬則爲之馬。", "不妨隨俗流通，何必分真辨假。"]'),
('7e77cd64-de40-4dbe-9bf2-54fe30c10837','李伯時畫馬贊','李之儀','宋','宋诗','song-poetry','','[]','飲不以鼻，投不以趾。',80,'全唐诗/poet.song.55000.json','["飲不以鼻，投不以趾。", "雖夢亦然，理自應爾。", "吾師東坡，嘗有是語。", "天機所同，惟伯時父。", "東坡形容，伯時位置。", "曹韓少陵，俱落第二。", "吾私淑諸，限隔九泉。", "筆頭落處，幾至潸然。"]'),
('dd581cce-6e3c-4dcb-8d9c-dff7857ec3ba','送戴道人','李之儀','宋','宋诗','song-poetry','','[]','懶將身世問窮通，邂逅僧軒一席同。',64,'全唐诗/poet.song.55000.json','["懶將身世問窮通，邂逅僧軒一席同。", "已歎故家如墜葉，可堪白髮共飄蓬。", "冥搜固出能言外，妙用都歸指掌中。", "咫尺京師莫辭遠，有雲何患不乘風。"]'),
('8c78b549-79a3-4121-b45b-d3299eea2b8e','賞花亭致語口號','李之儀','宋','宋诗','song-poetry','','[]','綠陰初合燕歸來，煮酒新嘗換撥醅。',64,'全唐诗/poet.song.55000.json','["綠陰初合燕歸來，煮酒新嘗換撥醅。", "不獨江山想王謝，須知賓客盡鄒枚。", "十分歡意休教剩，萬斛愁心亦自開。", "倒載任他路人笑，更將何處作春臺。"]'),
('40f505b6-3bde-4940-8dd4-bbf2da268a38','還俗道士','李之儀','宋','宋诗','song-poetry','','[]','聞道華陽客，儒衣謁紫微。',48,'全唐诗/poet.song.55000.json','["聞道華陽客，儒衣謁紫微。", "舊山連藥賣，孤鶴带雲歸。", "柳市名猶在，桃源夢已稀。", "還家見鷗鳥，應愧背船飛。"]'),
('f189862d-909c-44bd-b459-887543e9d627','詩一首','李之儀','宋','宋诗','song-poetry','','[]','美人在時花滿堂，美人去後留空牀。',56,'全唐诗/poet.song.55000.json','["美人在時花滿堂，美人去後留空牀。", "牀上繡衾閑不寢，至今三載猶餘香。", "香亦竟不滅，人亦竟不來。", "相思復相憶，白露濕蒼苔。"]'),
('32723e5f-28f3-43f3-a732-df5cf228013f','存目  其一','李之儀','宋','宋诗','song-poetry','','[]','詩題：立秋日書唐行成扇首句：自古逢秋悲寂寥。',22,'全唐诗/poet.song.55000.json','["詩題：立秋日書唐行成扇首句：自古逢秋悲寂寥。"]'),
('4ffe7f67-bb5e-4b09-8b17-60a8d8a8fbeb','存目  其二','李之儀','宋','宋诗','song-poetry','','[]','詩題：偶題（其二）首句：洛陽城裏見秋風。',20,'全唐诗/poet.song.55000.json','["詩題：偶題（其二）首句：洛陽城裏見秋風。"]'),
('0a936cfc-815f-4af9-a570-5b246e69e9d8','白玉泉酒遺李端叔','賈朝奉','宋','宋诗','song-poetry','','[]','第一荆州白玉泉，蘭舟載與酒中仙。',32,'全唐诗/poet.song.55000.json','["第一荆州白玉泉，蘭舟載與酒中仙。", "且須捉住鯨魚尾，恐怕醉來騎上天。"]'),
('93b6253b-14a5-4da7-9e7c-6de335f3a43e','賦秀遠堂','趙德孺','宋','宋诗','song-poetry','','[]','翰林李謫仙，埋骨青山下。',156,'全唐诗/poet.song.55000.json','["翰林李謫仙，埋骨青山下。", "平生愛此山，老去終不捨。", "放逐鵷鷺行，追隨雞黍社。", "文采今尚存，英風滿松檟。", "寥寥五百年，好尚世所寡。", "韓子荆州後，爲求襲良冶。", "乃祖當時輩，異代同瀟洒。", "結堂山之陽，真趣非少假。", "秀色來天外，遠勢包平野。", "烟嵐浮翠黛，攬之不容把。", "徜徉盤谷遊，屢請秣吾馬。", "時無謫仙人，登臨誰賦者。", "九原如可作，一奠招魂斝。"]'),
('5d1a93b1-c651-4664-9bba-6a2888009053','中隠庵','趙德孺','宋','宋诗','song-poetry','','[]','在昔避世賢，隠居豈自喜。',168,'全唐诗/poet.song.55000.json','["在昔避世賢，隠居豈自喜。", "甘守西山餓，清洗潁陽耳。", "一旦事高尚，萬古激貪鄙。", "孰謂樂山林，便可輕朝市。", "竊笑效顰人，不知捧心美。", "妄將凡庸姿，敢希明哲軌。", "盜此嘉遯名，紛若干時子。", "仕途指捷徑，矯僞汙青史。", "聖朝揚仄陋，采錄無遐邇。", "不遺下體葑，况乃中鄉芑。", "多士生此時，貧且賤焉恥。", "夢自傅巖來，獵從渭濱起。", "隠君聞此風，翻然烏可已。", "聊爲知者道，庶達名菴旨。"]'),
('ce5fcf8f-9a23-4751-b2fa-fadba05e58fc','宮詞  其一','周彥質','宋','宋诗','song-poetry','','[]','正朝排仗謹天元，常服無令入禁閽。',32,'全唐诗/poet.song.55000.json','["正朝排仗謹天元，常服無令入禁閽。", "十樣冠裳五千襲，紫宸前殿對諸蕃。"]'),
