('261e3577-06ec-4459-9749-77d6288695be','宮詞  其八五','周彥質','宋','宋诗','song-poetry','','[]','上直歸來日未晡，宮嬪相與戲摴蒲。',32,'全唐诗/poet.song.55000.json','["上直歸來日未晡，宮嬪相與戲摴蒲。", "驀關渡塹尋常彩，無奈時時擲雉盧。"]'),
('df9e4b02-a3e7-4b70-bbe0-563c88fc9eae','宮詞  其八六','周彥質','宋','宋诗','song-poetry','','[]','三衛千官侍冕旒，君王郊祀款圓丘。',32,'全唐诗/poet.song.55000.json','["三衛千官侍冕旒，君王郊祀款圓丘。", "彩棚夾路瞻天表，一半珠簾上玉鈎。"]'),
('3292e589-ff3b-4b01-af2f-8925e6ae5353','宮詞  其八七','周彥質','宋','宋诗','song-poetry','','[]','慶成大禮御端門，肅肅千官拱至尊。',32,'全唐诗/poet.song.55000.json','["慶成大禮御端門，肅肅千官拱至尊。", "高捧金雞宣霈澤，兩班歡舞荷天恩。"]'),
('a6d1dca7-39bf-47b0-802e-c7f41774bed5','宮詞  其八八','周彥質','宋','宋诗','song-poetry','','[]','聰俊宮娥妙奕棋，每虞宣喚各窮奇。',32,'全唐诗/poet.song.55000.json','["聰俊宮娥妙奕棋，每虞宣喚各窮奇。", "更闌自覆忘憂局，好著長防敵手知。"]'),
('a998af84-f635-468b-86f7-b6c1e5d2f9ac','宮詞  其八九','周彥質','宋','宋诗','song-poetry','','[]','臘後寒梅蕊弄黄，金瓶叢插貯蘭房。',32,'全唐诗/poet.song.55000.json','["臘後寒梅蕊弄黄，金瓶叢插貯蘭房。", "已供闔座清香滿，更得臨鸞學晚妝。"]'),
('2524c4a7-da4e-49a1-9940-682b0c86fc41','宮詞  其九○','周彥質','宋','宋诗','song-poetry','','[]','踴躍新羈已過關，未高生怕別人盤。',32,'全唐诗/poet.song.55000.json','["踴躍新羈已過關，未高生怕別人盤。", "到窩路數無多擲，急滿須防將馬闌。"]'),
('dd5fe9ec-00c8-4119-823f-eb523132b0ea','宮詞  其九一','周彥質','宋','宋诗','song-poetry','','[]','冬候寒威凜未央，初欣至日乍迎長。',32,'全唐诗/poet.song.55000.json','["冬候寒威凜未央，初欣至日乍迎長。", "退朝一曲昇平樂，共進新陽萬壽觴。"]'),
('ca826c0b-fc19-4f27-9579-4d5ca30e9e6d','宮詞  其九二','周彥質','宋','宋诗','song-poetry','','[]','感古梅妝範樣殊，折梅特地試妝梳。',32,'全唐诗/poet.song.55000.json','["感古梅妝範樣殊，折梅特地試妝梳。", "薄施紅粉臨鸞鑑，却是梅花迥不如。"]'),
('66298eaa-4d9a-4401-8b9d-99e835201777','宮詞  其九三','周彥質','宋','宋诗','song-poetry','','[]','五雲宮闕鬰岧嶢，尤稱濛濛瑞雪飄。',32,'全唐诗/poet.song.55000.json','["五雲宮闕鬰岧嶢，尤稱濛濛瑞雪飄。", "中使到來東上閣，傳宣初放紫宸朝。"]'),
('af17a9ec-ec80-4235-bc21-99a4310a9635','宮詞  其九四','周彥質','宋','宋诗','song-poetry','','[]','二月春宮折杏花，垂梢繁蕊鬧交加。',32,'全唐诗/poet.song.55000.json','["二月春宮折杏花，垂梢繁蕊鬧交加。", "折來已覺柔枝重，插向搔頭寶髻斜。"]'),
('5e47b828-f5b2-4b4f-89dd-f07ff4e340f8','宮詞  其九五','周彥質','宋','宋诗','song-poetry','','[]','丹青御筆趣尤深，不許流傳到翰林。',32,'全唐诗/poet.song.55000.json','["丹青御筆趣尤深，不許流傳到翰林。", "乞得睿思全幅軸，寶藏端勝滿籝金。"]'),
('eae41134-9b9a-444b-8b42-834144d1e8c4','宮詞  其九六','周彥質','宋','宋诗','song-poetry','','[]','女冠新觀近西清，玉宇幽奇稱道情。',32,'全唐诗/poet.song.55000.json','["女冠新觀近西清，玉宇幽奇稱道情。", "宮禁沉沉銀漏永，好風時送步虛聲。"]'),
('03ac703c-c79e-4cd0-a5a8-57b33ec7f9b8','宮詞  其九七','周彥質','宋','宋诗','song-poetry','','[]','碧蘆方沼水潺潺，疊石嵯峨翠靄間。',32,'全唐诗/poet.song.55000.json','["碧蘆方沼水潺潺，疊石嵯峨翠靄間。", "不謂九重宮禁裏，忽逢江國好溪山。"]'),
('46fddf2c-22e4-4806-a6e9-481121d066b9','宮詞  其九八','周彥質','宋','宋诗','song-poetry','','[]','綵架清陰接鳳樓，分班左右各朋儔。',32,'全唐诗/poet.song.55000.json','["綵架清陰接鳳樓，分班左右各朋儔。", "就中最得拋梭便，不礙珠門紫繡毬。"]'),
('489f9df7-acae-4fae-a6c5-c6a9b8f33ada','宮詞  其九九','周彥質','宋','宋诗','song-poetry','','[]','樓殿亭臺處處通，花光柳色共溟濛。',32,'全唐诗/poet.song.55000.json','["樓殿亭臺處處通，花光柳色共溟濛。", "苑東即出橫門道，已覺仙凡路不同。"]'),
('cfeed241-36df-448c-be9f-0f218291694e','宮詞  其一○○','周彥質','宋','宋诗','song-poetry','','[]','分引天源入禁城，御溝縈繞六宮行。',32,'全唐诗/poet.song.55000.json','["分引天源入禁城，御溝縈繞六宮行。", "寒聲碧甃淙淙急，流到人間分外清。"]'),
('92b7c002-04f2-4bd1-a84a-44a13449176e','寄子弟','周諝','宋','宋诗','song-poetry','','[]','浪有虛名落世間，自慚無實骨毛寒。',64,'全唐诗/poet.song.55000.json','["浪有虛名落世間，自慚無實骨毛寒。", "未年三十身先倦，纔得一官心已闌。", "卜宅擬尋栽藥圃，買田宜近釣魚灘。", "他年子弟重相見，藜杖蓑衣筍籜冠。"]'),
('75ba8aec-c810-48bd-b773-eff81b444057','絕句  其一','關澥','宋','宋诗','song-poetry','','[]','野艇歸時蒲葉雨，繰車鳴處楝花風。',32,'全唐诗/poet.song.55000.json','["野艇歸時蒲葉雨，繰車鳴處楝花風。", "江南舊日經行地，盡在于今醉夢中。"]'),
('d9abc149-2700-4ff2-84d6-a8fc05597db1','絕句  其二','關澥','宋','宋诗','song-poetry','','[]','寺官官小未朝參，紅日半竿春睡酣。',32,'全唐诗/poet.song.55000.json','["寺官官小未朝參，紅日半竿春睡酣。", "爲報鄰雞莫驚起，且容歸夢到江南。"]'),
('375f2a1c-1b8a-4525-b050-70ac9dec2649','遊九鎖','關澥','宋','宋诗','song-poetry','','[]','山下寒流咽細泉，曉林浮日自生烟。',64,'全唐诗/poet.song.55000.json','["山下寒流咽細泉，曉林浮日自生烟。", "九峰密鎖疑無路，五洞潛通別有天。", "羽客依山多得道，昔人涉海謾求仙。", "我來要學棲真事，願借孤雲一榻眠。"]'),
('134fe861-4b66-4dac-8bef-60617242ed3c','五洩山','曾諤','宋','宋诗','song-poetry','','[]','五洩高寒插太清，銀河垂地落天聲。',64,'全唐诗/poet.song.55000.json','["五洩高寒插太清，銀河垂地落天聲。", "玉虹貫日晴空見，驄馬翻瓢白晝傾。", "作賦曾聞誇雁蕩，乘槎應可到蓬瀛。", "何當一比乖龍起，手挽商霖洗甲兵。"]'),
('0bd851b5-a9b3-4a19-a449-14854ce25785','次韵趙仲美表弟西齋自遣','曾旼','宋','宋诗','song-poetry','','[]','謫守凄凉卧郡齋，夫君失意偶同來。',64,'全唐诗/poet.song.55000.json','["謫守凄凉卧郡齋，夫君失意偶同來。", "海邊故國渺何許，城上新樓空幾回。", "寧羨一囊供鶴料，會看千里躍龍媒。", "清吟未免縈機慮，只恐飛鷗便見猜。"]'),
('a95dcfa3-bafe-4382-a806-2c5c37c006d0','統軍池','曾旼','宋','宋诗','song-poetry','','[]','長山謾刻金芝頌，宮相空吟石竹詩。',32,'全唐诗/poet.song.55000.json','["長山謾刻金芝頌，宮相空吟石竹詩。", "事往歲深無處問，北園唯見孟家池。"]'),
('5235d407-7eab-4215-9ef7-ed6bcb7ee6ff','遊九鎖','曾旼','宋','宋诗','song-poetry','','[]','山勢盤紆是幾重，溪行亂石水溶溶。',64,'全唐诗/poet.song.55000.json','["山勢盤紆是幾重，溪行亂石水溶溶。", "東西路口分雙洞，蒼翠羣中起一峰。", "石上仙翁留去跡，壁間羽客有吟蹤。", "夜分不是紅塵境，清夢回時曉殿鐘。"]'),
('0b749daa-7e34-4def-afa8-b9a90e7e262d','呈同院諸公  其一','柳子文','宋','宋诗','song-poetry','','[]','鄧子知名久，秋闈得暫依。',48,'全唐诗/poet.song.55000.json','["鄧子知名久，秋闈得暫依。", "論文虛以往，講道實而歸。", "得句賡酬數，忘言笑語稀。", "自慚初學步，魚目混珠璣。"]'),
('ba83a169-14c0-4b47-b77d-40037abe07e4','呈同院諸公  其二','柳子文','宋','宋诗','song-poetry','','[]','刻意長沙客，編書近隙光。',48,'全唐诗/poet.song.55000.json','["刻意長沙客，編書近隙光。", "朝方登廟器，時可咏山梁。", "未用嘲經笥，端宜號智囊。", "頗聞窮史學，猶想見三長。"]'),
('6b74f92d-9351-407c-a9ec-e9de4cc5bf74','呈同院諸公  其三','柳子文','宋','宋诗','song-poetry','','[]','官輟蓬萊直，身從帝所回。',48,'全唐诗/poet.song.55000.json','["官輟蓬萊直，身從帝所回。", "文章孔庭奧，事業傅巖隈。", "多士朝廷念，諸公殿閣來。", "英雄須入彀，應有濟川才。"]'),
('85af8841-efe4-4c61-b484-08bcaa654568','秋日同文館  其一','柳子文','宋','宋诗','song-poetry','','[]','磊落羣英集，崢嶸逸氣齊。',48,'全唐诗/poet.song.55000.json','["磊落羣英集，崢嶸逸氣齊。", "捷機聞墮竈，妙論及交梨。", "庭木何年植，窗塵異域題。", "獨憐車馬散，寒月滿宮閨。"]'),
('41a49d95-5b03-46fc-b2b8-0b934730ee64','秋日同文館  其二','柳子文','宋','宋诗','song-poetry','','[]','懶散江湖客，秋深念滌場。',48,'全唐诗/poet.song.55000.json','["懶散江湖客，秋深念滌場。", "端宜返田里，安敢論文章。", "山塢橙應熟，霜籬菊正香。", "行歸招隠客，鼓腹詠時康。"]'),
('adcaa21c-daaa-4fea-b61f-be2d4270150b','秋日同文館  其三','柳子文','宋','宋诗','song-poetry','','[]','國器來金馬，儒冠萃木鷄。',48,'全唐诗/poet.song.55000.json','["國器來金馬，儒冠萃木鷄。", "勝心爭逐北，銳氣鼓爭西。", "海嶠鵬程息，春風雁塔題。", "應思連夜雨，車馬六街泥。"]'),
('4d1b6f6f-cf81-48d1-98c1-9e9e85e0ce74','未試即事雜書  其一','柳子文','宋','宋诗','song-poetry','','[]','虛廊空白月，燈火閉重闈。',48,'全唐诗/poet.song.55000.json','["虛廊空白月，燈火閉重闈。", "思苦詩難繼，更長夢易歸。", "徒勞爭墨榜，須信有朱衣。", "萬事前期定，升沉不爾違。"]'),
('344d127a-489e-4d0d-9872-125654c11fee','未試即事雜書  其二','柳子文','宋','宋诗','song-poetry','','[]','一一聽宮徵，銖銖較短長。',48,'全唐诗/poet.song.55000.json','["一一聽宮徵，銖銖較短長。", "品題分玉石，得失異炎凉。", "中的非無術，知音豈易忘。", "魚龍頭角老，變化更何方。"]'),
('45f01041-6c0f-4eb7-b6e9-7636c620782e','未試即事雜書  其三','柳子文','宋','宋诗','song-poetry','','[]','萬戶爭看榜，三年此一開。',48,'全唐诗/poet.song.55000.json','["萬戶爭看榜，三年此一開。", "異時千載遇，此日四方來。", "價重連城璧，珍逾羽化杯。", "山梁欣有獲，置網豈須媒。"]'),
('8d3f6f83-35fb-415e-b682-8c1b6eb5d7af','呈同院後至諸公','柳子文','宋','宋诗','song-poetry','','[]','秋日同文館，中官押入回。',48,'全唐诗/poet.song.55000.json','["秋日同文館，中官押入回。", "西風初雨後，明月爲人來。", "藻鑒憑君許，賡歌媿我陪。", "相逢已忘寢，坐見斗移魁。"]'),
('3ac01a0d-dcb0-4d2a-9d9e-229c365e4870','初入試院','柳子文','宋','宋诗','song-poetry','','[]','跫然雖復喜斯行，開豁拘懷頼俊英。',64,'全唐诗/poet.song.55000.json','["跫然雖復喜斯行，開豁拘懷頼俊英。", "上國擢材初改轍，衆心督戰亦乘城。", "何時奏籍瞻霜簡，且復安眠聽雨聲。", "異日尚容休沐會，未慚相約太癯生。"]'),
('f1c17995-7fdb-48b0-af2d-d77e49d079ca','試院即事呈諸公','柳子文','宋','宋诗','song-poetry','','[]','高談初喜聽懸河，未厭鄰房日夕過。',64,'全唐诗/poet.song.55000.json','["高談初喜聽懸河，未厭鄰房日夕過。", "蝴蝶乍迴塵外夢，蜘蛛看結雨中羅。", "銀袍較藝觀勍敵，玉帳收功聽凱歌。", "共是當年廷試客，鎖闈今日合如何。"]'),
('4e473d5f-9960-43b6-ba01-ccfc643e44ad','再呈慎思諸公兼以言懷','柳子文','宋','宋诗','song-poetry','','[]','侵尋節物過秋風，何處鈞天燕鼓鐘。',64,'全唐诗/poet.song.55000.json','["侵尋節物過秋風，何處鈞天燕鼓鐘。", "九日菊花聊一醉，五湖佳士偶相逢。", "挑燈款語時供笑，借紙聯詩且漫從。", "待得出闈應放意，百杯追逐興方濃。"]'),
('307489d4-5b0b-4caf-b10a-dfe998c428c4','次韵呈文潛學士同年','柳子文','宋','宋诗','song-poetry','','[]','才堪斗量君獨釜，年少登瀛脫塵土。',128,'全唐诗/poet.song.55000.json','["才堪斗量君獨釜，年少登瀛脫塵土。", "重闈幾日鎖清秋，酬唱新篇亂如雨。", "讀書相逢十載前，君家酥酪和腐乳。", "分題吟思入風雲，得意還忘嘔心苦。", "晚將衰颯奉英游，漫記雪窗邀夜語。", "平生意氣杯酒間，我醉狂歌君起舞。", "即今頭白老青衫，但期教子應門戶。", "燕頷從君骨相殊，看君鼎食羅五俎。"]'),
('8da82574-81d1-4f7a-8002-4ab780be2eb3','次韵呈慎思學士','柳子文','宋','宋诗','song-poetry','','[]','咸韶濩武來何方，鏗鏘入耳安能忘。',352,'全唐诗/poet.song.55000.json','["咸韶濩武來何方，鏗鏘入耳安能忘。", "陽春蘭芷秋菊芳，金門詞客青袍郎。", "昭回下燭光焰長，深山大澤龍蛇蒼。", "浩歌激烈元非狂，正逢聖主開明堂。", "風煙關塞收旗槍，舞干兩階臣戎羌。", "喋血拓境謀非臧，邊城夜行休齎糧。", "採詩不復嘲青岡，蛜蝛戢羽戍婦牀。", "移文北斗猿鶴傍，渥洼朱龍兩服驤。", "胥靡版築罷浚隍，白環楛矢貢篚裝。", "航海萬里風帆揚，邊圉膽落嗟唇亡。", "諸蕃入學願可償，槐花舉子促書囊。", "成均貢士賢登鄉，東門宣詔禮十行。", "我慚駑駘追驌驦，何敢望回不及商。", "毛遂未至空連房，頼有墨妙江都王。", "傳模共分此日光，驊騮綠驃兩耳黄。", "想見蹙踏披天香，坐覺暑退秋堂凉。", "拘攣齷齪漫引觴，門外烏兔雙飛翔。", "悠悠逝川東去央，故山魚鳥空相望。", "鄧侯意氣摩秋霜，朝吟百篇暮千章。", "駢羅經史貫列莊，落紙但見書吏忙。", "孔鸞羽儀各效祥，鄙夫不學空面牆。", "先饋不用驚五漿，烏號要須賁育張。"]'),
('e529f5d9-cd6b-49ea-9ed8-418df71613e5','藜廳','余授','宋','宋诗','song-poetry','','[]','神僧曾西征，目覽江山異。',24,'全唐诗/poet.song.55000.json','["神僧曾西征，目覽江山異。", "深林植杖藜，他日成州治。"]'),
('7c227030-bde0-4955-a8fc-b09402506edc','詩一首','余授','宋','宋诗','song-poetry','','[]','絕塞邛崍外，偏城越巂東。',48,'全唐诗/poet.song.55000.json','["絕塞邛崍外，偏城越巂東。", "山含初夏雪，林偃夕陽風。", "地僻無參謁，民淳少訟爭。", "睡餘兵放教，衙退吏歸耕。"]'),
('fb48b1d2-5c0f-4dc8-983b-81abf644cced','朱喬年尉公舉男往賀  其一','鄭安道','宋','宋诗','song-poetry','','[]','今宵湯餠會，滿座桂香來。',48,'全唐诗/poet.song.55000.json','["今宵湯餠會，滿座桂香來。", "圓月飛金鏡，流霞泛玉杯。", "渥洼元異種，丹穴豈凡胎。", "載路聲聞徹，祥光燭上台。"]'),
('3bc61269-1244-4490-b945-74da046e12d3','朱喬年尉公舉男往賀  其二','鄭安道','宋','宋诗','song-poetry','','[]','瑞氣靄南山，弧懸別墅間。',48,'全唐诗/poet.song.55000.json','["瑞氣靄南山，弧懸別墅間。", "此時誇降嶽，他日見探環。", "席敞籬花艷，樽浮竹葉斑。", "老夫歌既醉，拄杖月中還。"]'),
('6ae7993e-8891-4fa1-8249-3ddb56bcaaac','屏山草堂四詠 鷺洲釣月','周述','宋','宋诗','song-poetry','','[]','維揚喬木翰林家，底事投閒釣鷺沙。',32,'全唐诗/poet.song.55000.json','["維揚喬木翰林家，底事投閒釣鷺沙。", "真隠每嫌勞物色，煙波深處足生涯。"]'),
('a45be3e2-1cfd-45e2-bd7a-5c3aa0f1dee3','屏山草堂四詠 天馬樵雲','周述','宋','宋诗','song-poetry','','[]','封事何如樂採薪，崚嶒石磴步堪馴。',32,'全唐诗/poet.song.55000.json','["封事何如樂採薪，崚嶒石磴步堪馴。", "深林不識日昏曉，一任山隈卧白雲。"]'),
('60c71f6e-003c-4ce5-9aa2-d584efed3a46','屏山草堂四詠 吳臯東作','周述','宋','宋诗','song-poetry','','[]','天設名區擁翠屏，草堂風度曉雞聲。',32,'全唐诗/poet.song.55000.json','["天設名區擁翠屏，草堂風度曉雞聲。", "年來不作繁華夢，飯犢郊原學耦耕。"]'),
('a7f017b5-b890-4d5d-929e-a25825c1ac00','屏山草堂四詠 月巖夜讀','周述','宋','宋诗','song-poetry','','[]','歸來築室月山傍，星斗長懸午夜光。',32,'全唐诗/poet.song.55000.json','["歸來築室月山傍，星斗長懸午夜光。", "清白流芳無別業，詩書堆滿竹方牀。"]'),
('cbcb27f4-1524-4397-b43a-0443a49b6b92','句','俞偉','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','笠澤漁帆翠葉輕，洞庭山色青螺小。',16,'全唐诗/poet.song.55000.json','["笠澤漁帆翠葉輕，洞庭山色青螺小。"]'),
('2a3f6807-9e55-4596-a89a-801ed00ea2da','求落籍','周韶','宋','宋诗','song-poetry','','[]','隴上巢空歲月驚，忍看回首自梳翎。',32,'全唐诗/poet.song.55000.json','["隴上巢空歲月驚，忍看回首自梳翎。", "開籠若放雪衣女，長念觀音般若經。"]'),
('56c531b1-96bb-4988-8ac5-2c1d1ab03a02','送周韶落籍','胡楚','宋','宋诗','song-poetry','','[]','淡粧輕素鶴翎紅，移入朱闌便不同。',32,'全唐诗/poet.song.55000.json','["淡粧輕素鶴翎紅，移入朱闌便不同。", "應笑西園桃與李，强勻顔色待東風。"]'),
('03f1b033-bcea-4d8d-a7c5-2175bd677da4','絕句','胡楚','宋','宋诗','song-poetry','','[]','不見當時丁令威，年來處處是相思。',32,'全唐诗/poet.song.55000.json','["不見當時丁令威，年來處處是相思。", "若將此恨同芳草，却恐青青有盡時。"]'),
('45caec34-1299-4c3e-a93c-32b85217e049','獻張郎中','龍靚','宋','宋诗','song-poetry','','[]','天與羣芳十樣葩，獨分顔色不堪誇。',32,'全唐诗/poet.song.55000.json','["天與羣芳十樣葩，獨分顔色不堪誇。", "牡丹芍藥人題徧，自分身如鼓子花。"]'),
('efa21e86-29ee-4ed0-9f68-bc273e475900','送周韶落籍','龍靚','宋','宋诗','song-poetry','','[]','桃花流水本無塵，一落人間幾度春。',32,'全唐诗/poet.song.55000.json','["桃花流水本無塵，一落人間幾度春。", "解佩暫酬交甫意，濯纓還作武陵人。"]'),
('7b08ffc4-5067-46f9-9933-d9b1eea920a5','遣興作偈','祖庵主','宋','宋诗','song-poetry','','[]','小鍋煮菜上蒸飯，菜熟飯香人正饑。',32,'全唐诗/poet.song.55000.json','["小鍋煮菜上蒸飯，菜熟飯香人正饑。", "一補饑瘡了無事，明朝依樣畫貓兒。"]'),
('575023d9-1308-4d11-a2c2-2dfc387bb6ed','誦華嚴經','覺禪師','宋','宋诗','song-poetry','','[]','佛具無有生，而能示出生。',36,'全唐诗/poet.song.55000.json','["佛具無有生，而能示出生。", "法性如虛空，諸佛于中住。", "無住亦無知，處處皆見佛。"]'),
('304fe858-e37b-4207-a013-371c9f77cd50','偈一首','覺禪師','宋','宋诗','song-poetry','','[]','家住孤峰頂，長年半掩門。',24,'全唐诗/poet.song.55000.json','["家住孤峰頂，長年半掩門。", "自嗟身已老，活計付兒孫。"]'),
('631fc979-f14d-4209-a1fe-2169e6cf50f1','寄圜悟偈','覺禪師','宋','宋诗','song-poetry','','[]','出林依舊入蓬蒿，天網恢恢不可逃。',32,'全唐诗/poet.song.55000.json','["出林依舊入蓬蒿，天網恢恢不可逃。", "誰信業緣無避處，回來不怕語聲高。"]'),
('ebe2c637-d685-4b7a-a9f8-2f85bf25df15','鍾山','王雱','宋','宋诗','song-poetry','','[]','當年睥睨此山阿，欲著紅樓貯綺羅。',32,'全唐诗/poet.song.55000.json','["當年睥睨此山阿，欲著紅樓貯綺羅。", "今日重來無一事，却騎羸馬下坡陀。"]'),
('d3de362f-b8a3-4ea5-bd40-4ef765994f37','度關山','王雱','宋','宋诗','song-poetry','','[]','萬馬度關山，關山三尺雪。',48,'全唐诗/poet.song.55000.json','["萬馬度關山，關山三尺雪。", "馬盡雪亦乾，沙飛石更裂。", "歸來三五騎，旌旗映雪滅。", "不見去時人，空流磧中血。"]'),
('e30fb1ea-a49d-435f-bace-41a5fb4a13fa','春懷','王雱','宋','宋诗','song-poetry','','[]','朝日上屋角，百鳥鳴不休。',84,'全唐诗/poet.song.55000.json','["朝日上屋角，百鳥鳴不休。", "豈復辨名字，但聞鬧鉤輈。", "亂我讀書語，驚我夢寐游。", "彎弓彈使去，暫去還啾啾。", "彈十不得一，窮時來愈稠。", "投弓坐榻上，咄咄空自尤。", "時節使汝鳴，我何爲汝讎。"]'),
('650d858b-d2cc-4040-9d15-39a8df542e61','絕句  其一','王雱','宋','宋诗','song-poetry','','[]','一雙燕子語簾前，病客無憀盡日眠。',32,'全唐诗/poet.song.55000.json','["一雙燕子語簾前，病客無憀盡日眠。", "開遍杏花人不見，滿庭輕雨綠如煙。"]'),
('027ee3d1-3354-4036-b33c-669acdedcce2','絕句  其二','王雱','宋','宋诗','song-poetry','','[]','霏微細雨不成泥，料峭輕寒透夾衣。',32,'全唐诗/poet.song.55000.json','["霏微細雨不成泥，料峭輕寒透夾衣。", "處處園林皆有主，欲尋何地看春歸。"]'),
('888d8b6e-64d1-47a4-bd02-956ea91eccbb','翠雲山','王雱','宋','宋诗','song-poetry','','[]','寺古無鄰家，千山抱虛碧。',84,'全唐诗/poet.song.55000.json','["寺古無鄰家，千山抱虛碧。", "門開猿鳥路，殿鎖烟霞積。", "老木森回溪，飛湍自淙激。", "曾無車馬到，絕境閒今昔。", "逍遙賢大夫，肯此携佳客。", "鳴騶清曉來，歸時日常昃。", "不使訟庭空，誰能傲泉石。"]'),
('f55fc04b-a5ea-41de-85fe-4cb22ba693da','詩一首','王雱','宋','宋诗','song-poetry','','[]','杜家園上好花時，尚有梅花三兩枝。',32,'全唐诗/poet.song.55000.json','["杜家園上好花時，尚有梅花三兩枝。", "日暮欲歸巖下宿，爲貪香雪故來遲。"]'),
('0c67042a-40ce-486b-b249-004a7ef04739','句','王雱','宋','宋诗','song-poetry','','[]','君心莫厭頻歡樂，請看雲間日西入。',16,'全唐诗/poet.song.55000.json','["君心莫厭頻歡樂，請看雲間日西入。"]'),
('7732308e-7c81-45cc-8cb6-243440ff4f91','偈  其一','釋從悅','宋','宋诗','song-poetry','','[]','耳目一何清，端居幽谷裏。',40,'全唐诗/poet.song.55000.json','["耳目一何清，端居幽谷裏。", "秋風入古松，秋月生寒水。", "衲僧於此更求真，兩箇猢猻垂四尾。"]'),
('101f6c6b-acb4-42a5-8d2b-02a144d5c20c','偈  其二','釋從悅','宋','宋诗','song-poetry','','[]','常居物外度清時，牛上橫將竹笛吹。',32,'全唐诗/poet.song.55000.json','["常居物外度清時，牛上橫將竹笛吹。", "一曲自幽山自綠，此情不與白雲知。"]'),
('b7bc2f9a-1237-41f1-9ecd-f3cc7447a4ab','偈  其三','釋從悅','宋','宋诗','song-poetry','','[]','無法亦無心，無心復何捨。',48,'全唐诗/poet.song.55000.json','["無法亦無心，無心復何捨。", "要真盡屬真，要假全歸假。", "平地上行船，虛空裏走馬。", "九年面壁人，有口還如啞。"]'),
('15d307d0-63d2-4050-a697-1d127fda2954','偈  其四','釋從悅','宋','宋诗','song-poetry','','[]','夜夜抱佛眠，朝朝還共起。',36,'全唐诗/poet.song.55000.json','["夜夜抱佛眠，朝朝還共起。", "起坐鎮相隨，語默同居止。", "欲識佛去處，祇這語聲是。"]'),
('50f598c1-17eb-4b21-87d6-49de6a1b73cc','辭衆偈','釋從悅','宋','宋诗','song-poetry','','[]','四十有八，聖凡盡殺。',20,'全唐诗/poet.song.55000.json','["四十有八，聖凡盡殺。", "不是英雄，龍安路滑。"]'),
('14682699-8a71-4d9e-88e5-b7659f940c85','罷雁門令後作','黄炎','宋','宋诗','song-poetry','','[]','獻議條陳十五事，輸錢歲減二千緡。',32,'全唐诗/poet.song.55000.json','["獻議條陳十五事，輸錢歲減二千緡。", "備員出宰當求瘼，忤旨監司竟累身。"]'),
('3b0fce02-858a-4921-b774-43e34e319a09','贈靈岩元長老','梁彥深','宋','宋诗','song-poetry','','[]','高僧升座息塵埃，萬慮都忘智眼開。',32,'全唐诗/poet.song.55000.json','["高僧升座息塵埃，萬慮都忘智眼開。", "今日□□□□□，□知宿世有緣來。"]'),
('bb8bcc65-736b-4e71-bdd0-23c181654a85','巾山廣軒','何執中','宋','宋诗','song-poetry','','[]','曲檻小欄干，登臨咫尺間。',48,'全唐诗/poet.song.55000.json','["曲檻小欄干，登臨咫尺間。", "望隨流水遠，高共白雲閑。", "亭栢僧歸路，江楓客渡灣。", "覺來生羽翼，疑是夢中還。"]'),
('014f2946-8a0d-460f-ab1e-adb65c3340ee','題壽師塔南軒','何執中','宋','宋诗','song-poetry','','[]','焚修六七齡，內外已圓成。',48,'全唐诗/poet.song.55000.json','["焚修六七齡，內外已圓成。", "教相論因果，冥心契死生。", "紙窗應自白，花砌本無情。", "燕坐觀浮世，誰非走利名。"]'),
('ff6ee521-5184-4b7d-9e26-68bd29d4fead','句','何執中','宋','宋诗','song-poetry','','[]','香山寂寂聽因緣。',8,'全唐诗/poet.song.55000.json','["香山寂寂聽因緣。"]'),
('e3937c30-8872-40ea-a74f-880596e7f331','北斗岐山','陳次升','宋','宋诗','song-poetry','','[]','土精成石石成星，屈曲安排天北形。',32,'全唐诗/poet.song.55000.json','["土精成石石成星，屈曲安排天北形。", "自是山遊玩物者，依稀信步踏蒼冥。"]'),
('33e9e44d-062f-457c-b914-2d6f8b4539f8','送程給事知越州','吳安持','宋','宋诗','song-poetry','','[]','嶺表騷然避賊鋒，番禺當此每從容。',64,'全唐诗/poet.song.55000.json','["嶺表騷然避賊鋒，番禺當此每從容。", "故知封豕非無意，自是金城不可攻。", "海嶠百年忻受賜，承明三接正酬庸。", "山陰豈足勞公久，能活千人尚有封。"]'),
('6042d109-2e6a-46b3-aeac-201e00467faa','駕幸太學倡和','吳安持','宋','宋诗','song-poetry','','[]','翰林墨客奏封章，天子欣然幸國庠。',64,'全唐诗/poet.song.55000.json','["翰林墨客奏封章，天子欣然幸國庠。", "綵仗六龍初擁路，青衿三舍已重修。", "隆儒共慶賢堯舜，訪道誰知應帝王。", "附鳳騫淵皆法從，獨慚由也亦升堂。"]'),
('88de3813-5496-4d99-9fd6-7168812f6803','留題贈靈巖鑒公禪師','張會宗','宋','宋诗','song-poetry','','[]','人中令德居高地，天下精藍占好山。',64,'全唐诗/poet.song.55000.json','["人中令德居高地，天下精藍占好山。", "四絕名標清世上，十方僧聚白雲間。", "二龍珠照看經靜，雙鶴泉供洗鉢閒。", "早晚利榮韁鎖脫，性通三教叩禪關。"]'),
('37c8eb93-e931-4b5a-82a9-2b555fa7c45c','題通雲亭','王孝先','宋','宋诗','song-poetry','','[]','小亭高古占城闉，地迥全無一點塵。',32,'全唐诗/poet.song.55000.json','["小亭高古占城闉，地迥全無一點塵。", "時有行雲自來去，晚來施雨欲留人。"]'),
('91af0014-7e08-4763-b909-260facf72642','贈佛印禪師','韓宗古','宋','宋诗','song-poetry','','[]','雲居古道場，縹緲若化土。',36,'全唐诗/poet.song.55000.json','["雲居古道場，縹緲若化土。", "西有卧龍洞，傳聞結庵住。", "曉日射寒巖，翠光入窗戶。"]'),
('25ba9e55-3073-4670-8c07-0a70467715b1','送程給事知越州','韓宗古','宋','宋诗','song-poetry','','[]','東渡吳江景氣清，拂雲樓閣會稽城。',64,'全唐诗/poet.song.55000.json','["東渡吳江景氣清，拂雲樓閣會稽城。", "乍辭青瑣雙旌擁，重駕朱轓駟馬迎。", "應笑買臣夸郡邸，還同嚴助厭承明。", "茂林脩竹山陰地，何日陪公載酒行。"]'),
('40271d68-3b21-42ab-9262-3bac0cd54fe3','和孔司封題蓬萊閣','孫昌齡','宋','宋诗','song-poetry','','[]','突兀軒楹氣象豪，使君携客共遊遨。',64,'全唐诗/poet.song.55000.json','["突兀軒楹氣象豪，使君携客共遊遨。", "坐來面揖湖山勝，行處深騰日月高。", "隠約壺中露蓬島，分明海上涌金鼇。", "宜酬絕景頻吟醉，况是東南暫擁旄。"]'),
('e72daa56-4a94-45d7-860c-affaa157dc55','句','孫昌齡','宋','宋诗','song-poetry','','[]','白狼去後桑田出，仙女昇來洞府閑。',16,'全唐诗/poet.song.55000.json','["白狼去後桑田出，仙女昇來洞府閑。"]'),
('0c5d159b-ded7-4f3c-9175-74860c7a6351','句','張佑','宋','宋诗','song-poetry','','[]','蟹黄鹽滿箸，熊白軟加籩。',12,'全唐诗/poet.song.55000.json','["蟹黄鹽滿箸，熊白軟加籩。"]'),
('5a64602e-7d77-42cb-bf5c-3bd52dafdf78','大觀二年戊子三月二十九日請假祀墳和族人升之韵','陽孝本','宋','宋诗','song-poetry','','[]','連日陰雲拂曉開，歡聲九族一時來。',64,'全唐诗/poet.song.55000.json','["連日陰雲拂曉開，歡聲九族一時來。", "江山奇秀渾如畫，鼓樂喧闐却似雷。", "三爵香醪澆故壠，滿天春色絕纖埃。", "自從菲德叨榮甚，八行初從帝里來。"]'),
('3602dbfa-5047-4663-8e5c-cde88e5e6b3b','步韵奉酬林郡守二首  其一','陽孝本','宋','宋诗','song-poetry','','[]','六槐何日起商巖，未許蟠龍卧碧潭。',64,'全唐诗/poet.song.55000.json','["六槐何日起商巖，未許蟠龍卧碧潭。", "天下蒼生還有待，郡中善政却無慚。", "錦囊珠玉成咳唾，綺席風雲出笑談。", "千載通天蒙品藻，恐教虛譽滿江南。"]'),
('6b4de193-651d-4f00-8e81-fd2c14d5dedb','步韵奉酬林郡守二首  其二','陽孝本','宋','宋诗','song-poetry','','[]','家世中條舊素貧，塵編堆積漫繽紛。',64,'全唐诗/poet.song.55000.json','["家世中條舊素貧，塵編堆積漫繽紛。", "未甘末俗成虛老，却笑勞生漫逐群。", "爲愛嚴陵灘上月，還思巢父嶺頭雲。", "閭閻莫怪衡門陋，旌節曾來有使君。"]'),
('d31941d7-b462-49da-8a35-bcb6f74cb3d3','敷淺原見桃花','劉次莊','宋','宋诗','song-poetry','','[]','桃花雨過碎紅飛，半逐溪流半染泥。',32,'全唐诗/poet.song.55000.json','["桃花雨過碎紅飛，半逐溪流半染泥。", "何處飛來雙燕子，一時銜在畫梁西。"]'),
('6c6d5443-c4c1-401e-8b03-38933479deeb','塵土黄','劉次莊','宋','宋诗','song-poetry','','[]','翠眉連娟舞袖長，春風自對理容妝。',80,'全唐诗/poet.song.55000.json','["翠眉連娟舞袖長，春風自對理容妝。", "染絲繡作雙鴛鴦，欲飛不飛在羅裳。", "耳中明月珠，肘後錦香囊。", "憑高欲有寄，所寄在遠方。", "追風還君立路傍，豈不有地能相當，請著一鞭塵土黄。"]'),
('42c77483-12ef-4dc6-a3ca-f1e85f46afd3','塵土黄 譯','劉次莊','宋','宋诗','song-poetry','','[]','妾本倡家子，笄鬟擅容止。',96,'全唐诗/poet.song.55000.json','["妾本倡家子，笄鬟擅容止。", "名隸倡籍中，生倡即倡死。", "物勢本從權，情恩亦遂遷。", "一朝官長怒，獨抱錦衾眠。", "日暮倚高樓，青絲繫白馬。", "豈不謝慇懃，汪汪淚盈把。", "萬感自有因，無容遽相親。", "請君促金勒，妾願看飛塵。"]'),
('b716185f-c30b-4770-aef0-110481f89704','塵土黄 箋','劉次莊','宋','宋诗','song-poetry','','[]','春臺女兒似紅玉，曾奉當筵柘枝曲。',168,'全唐诗/poet.song.55000.json','["春臺女兒似紅玉，曾奉當筵柘枝曲。", "舞成早自得癡名，更傍春風情不足。", "客携黄金欲有贈，多在鄰家賭雙陸。", "近從新官作顔面，祇得低心隨所欲。", "自知久去非所安，夜半東門車特碌。", "秀闕芙蓉潭畔起，每向波間得雙鯉。", "水流却上大應難，惟有孤懷似潭水。", "一騎翩翩錦臂鞲，紅羅百丈作纏頭。", "爲言聞得琵琶怨，當門下馬欲登樓。", "莫登樓，君馬駭。", "無限朱簾薰好香，城北城南無一瞬。"]'),
('69f6286d-c6e9-4767-ab04-20df03670697','江神詞','劉次莊','宋','宋诗','song-poetry','','[]','髻插幽蘭花，手把菖蒲葉。',56,'全唐诗/poet.song.55000.json','["髻插幽蘭花，手把菖蒲葉。", "漁郎偷語人，云是江神妾。", "江神昨日鼓雲濤，開帆拍天上千艘。", "吳洲女兒弄春水，浪濕船頭紅綿袍。"]'),
('78954d7f-7cc0-4d68-8407-12487827816f','王昭君','劉次莊','宋','宋诗','song-poetry','','[]','斂袂出明光，琵琶道路長。',48,'全唐诗/poet.song.55000.json','["斂袂出明光，琵琶道路長。", "初聞胡騎語，未解漢宮妝。", "薄命隨塵土，元功屬廟堂。", "蛾眉如有用，慚媿羽林郎。"]'),
('ac67246c-9996-4317-ac44-1597703834d3','醉眠亭','晁端稟','宋','宋诗','song-poetry','','[]','吏部甕閒眠，先生窗下卧。',258,'全唐诗/poet.song.55000.json','["吏部甕閒眠，先生窗下卧。", "夜偷綠醑飲，晝喜清風過。", "人爲清風快於酒，擺落煩襟洗塵垢。", "吾知醉寢勝閑睡，可以寄天真兮忘世累。", "溝瀆超江漢，幕席視天地。", "蝴蝶不知緣變化，黄粱未熟虛營利。", "從來閑處得閑樂，何者功成與名遂。", "隴西夫子稱世賢，世家自是酒中仙。", "作亭占得松陵地，東坡名之爲醉眠。", "醉復眠兮眠復醉，頤養鄒軻浩然氣。", "賢人爲濁聖人清，昏昏夢寐都忘形。", "花影滿身猶未覺，竹風吹面不知醒。", "憶昔樂天貪醉吟，吟哦未免勞其心。", "不如醉睡了無事，其樂陶陶得趣深。", "我身走塵埃，羈鞅殊未息。", "有所思兮在高軒，欲往從之路艱塞。", "無緣一榻同醉眠，空禿千毫揮醉筆。"]'),
('76adb827-a7e4-4459-823f-e914b01b7782','琅邪山','晁端稟','宋','宋诗','song-poetry','','[]','琅邪山色連雲綠，煙樹參差裹巖谷。',32,'全唐诗/poet.song.55000.json','["琅邪山色連雲綠，煙樹參差裹巖谷。", "幽香爛熳四時花，翠影交加萬竿竹。"]'),
('2d46c47d-a23b-4fe5-86ea-ee9536b67f84','清風亭','晁端稟','宋','宋诗','song-poetry','','[]','物外林泉靜，閑中日月長。',24,'全唐诗/poet.song.55000.json','["物外林泉靜，閑中日月長。", "清風颯然至，可以傲羲皇。"]'),
('fac47497-2f7c-4613-8022-43bd52ff2b8a','翠微亭','晁端稟','宋','宋诗','song-poetry','','[]','曉風吹落秋泉聲，夜雨洗出秋山色。',32,'全唐诗/poet.song.55000.json','["曉風吹落秋泉聲，夜雨洗出秋山色。", "上有樓臺深翠微，可惜丹青圖不得。"]'),
('ce4bcabb-4202-4673-a31e-fd16c185a49d','無心亭','晁端稟','宋','宋诗','song-poetry','','[]','地與市朝遠，雲藏山水深。',24,'全唐诗/poet.song.55000.json','["地與市朝遠，雲藏山水深。", "長令有心者，到此自無心。"]'),
('5c1648a1-ccf8-45bb-8f03-182bcea668a4','雙井敝廬之東得勝地一區長林巨麓危峰四環泉甘土肥可以結茅菴居是在寅山之頦命曰寅菴喜成四詩遠寄魯直可同魏都士人共和之  其一','黄大臨','宋','宋诗','song-poetry','','[]','一溪婉婉如平篆，四野青青似畫圖。',64,'全唐诗/poet.song.55000.json','["一溪婉婉如平篆，四野青青似畫圖。", "阮客放船迷洞府，化人携袂到清都。", "山中安用名丞相，天下於今得廣居。", "我即其間構宮室，預愁帝夢有華胥。"]'),
('89592641-ad7a-473b-9667-5d0fdaaf72a2','雙井敝廬之東得勝地一區長林巨麓危峰四環泉甘土肥可以結茅菴居是在寅山之頦命曰寅菴喜成四詩遠寄魯直可同魏都士人共和之  其二','黄大臨','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','山前有路到華胥，下即乾坤極海隅。',64,'全唐诗/poet.song.55000.json','["山前有路到華胥，下即乾坤極海隅。", "西接洞庭開曉楚，東傾彭蠡浸晴吳。", "四時更代觀形化，萬物推移見尾閭。", "此世人人少閑暇，每携樽酒自看書。"]'),
('9aa0bdce-fe02-46e2-b670-74b051b56fb3','雙井敝廬之東得勝地一區長林巨麓危峰四環泉甘土肥可以結茅菴居是在寅山之頦命曰寅菴喜成四詩遠寄魯直可同魏都士人共和之  其三','黄大臨','宋','宋诗','song-poetry','','[]','手把齊民種蒔書，莎衫臺笠事耘鋤。',64,'全唐诗/poet.song.55000.json','["手把齊民種蒔書，莎衫臺笠事耘鋤。", "夏栽醉竹餘千个，春糞辰瓜滿百區。", "早秫旋舂嘗麴藥，新粱炊熟自樵蘇。", "日西杖屨行山口，招得鄰丁作飲徒。"]'),
('69e979b7-d403-48a1-bfa7-e1533d41e070','雙井敝廬之東得勝地一區長林巨麓危峰四環泉甘土肥可以結茅菴居是在寅山之頦命曰寅菴喜成四詩遠寄魯直可同魏都士人共和之  其四','黄大臨','宋','宋诗','song-poetry','','[]','招得鄰丁作飲徒，山家肴蔬蓋胥疏。',64,'全唐诗/poet.song.55000.json','["招得鄰丁作飲徒，山家肴蔬蓋胥疏。", "就根煨笋連黄籜，和蒂栽瓜带綠鬚。", "羹熟澤中親射雁，膾成溪上自罾魚。", "遠懷羊仲荒三徑，能似林間今日無。"]'),
('59426718-eedc-440d-8730-8d92e39367ac','奉寄子由','黄大臨','宋','宋诗','song-poetry','','[]','鐘鼎功名淹管庫，朝廷翰墨寫風煙。',64,'全唐诗/poet.song.55000.json','["鐘鼎功名淹管庫，朝廷翰墨寫風煙。", "遙知道院頗岑寂，定是壺中第幾天。", "歷下笑談漫一夢，江南消息又餘年。", "動心忍性非無意，吏部如今信大顛。"]'),
('e270dba7-a53a-4a20-a1ef-cda7a1673b85','題哥羅驛竹枝詞','黄大臨','宋','宋诗','song-poetry','','[]','尺五攀天天慘顔，鹽煙溪瘴鎖諸蠻。',64,'全唐诗/poet.song.55000.json','["尺五攀天天慘顔，鹽煙溪瘴鎖諸蠻。", "平生夢亦未嘗處，聞有鴉飛不到山。", "風黑馬嘶馿瘦嶺，日黄人度鬼門關。", "黔南此去無多遠，想在夕陽猿嘯間。"]'),
('782476e7-a329-47de-af70-9f8d0b8bd4a0','留別','黄大臨','宋','宋诗','song-poetry','','[]','桄榔笋白映玉箸，椰子酒清宜具觴。',64,'全唐诗/poet.song.55000.json','["桄榔笋白映玉箸，椰子酒清宜具觴。", "市井衣裘半夷夏，陰晴朝暮變炎凉。", "莫推月色共千里，不寄江南書一行。", "無頼笳聲上雲漢，曉來偏繞九回腸。"]'),
('e8ff59b4-9beb-405d-b1ec-135b8c7a7371','入萍鄉道中','黄大臨','宋','宋诗','song-poetry','','[]','路入前村信馬行，野花香好不知名。',32,'全唐诗/poet.song.55000.json','["路入前村信馬行，野花香好不知名。", "官卑無補公家事，時向田家問耦耕。"]'),
('5a6cba6b-c106-4426-a286-eb5a37ad78f0','句  其一','黄大臨','宋','宋诗','song-poetry','','[]','南山占相去，方石爲誰存。',12,'全唐诗/poet.song.55000.json','["南山占相去，方石爲誰存。"]'),
('663626eb-551f-4ca5-8cb2-64417a0fc590','句  其二','黄大臨','宋','宋诗','song-poetry','','[]','虎子養溪魚。',6,'全唐诗/poet.song.55000.json','["虎子養溪魚。"]'),
('574943ff-633f-400e-9b8d-bb83c2adacec','句  其三','黄大臨','宋','宋诗','song-poetry','','[]','急雪鶺鴒相並影，驚風鴻雁不成行。',16,'全唐诗/poet.song.55000.json','["急雪鶺鴒相並影，驚風鴻雁不成行。"]'),
('3bc632ad-d8e1-406e-bc55-188eea80d13e','古詩二首上蘇子瞻  其一','黄庭堅','宋','宋诗','song-poetry','','[]','江梅有佳實，託根桃李場。',96,'全唐诗/poet.song.55000.json','["江梅有佳實，託根桃李場。", "桃李終不言，朝露借恩光。", "孤芳忌皎潔，冰雪空自香。", "古來和鼎實，此物升廟廊。", "歲月坐成晚，烟雨青已黄。", "得升桃李盤，以遠初見嘗。", "終然不可口，擲置官道傍。", "但使本根在，棄捐果何傷。"]'),
('95855830-e662-48e8-9ab1-56787bacc4b9','古詩二首上蘇子瞻  其二','黄庭堅','宋','宋诗','song-poetry','','[]','青松出澗壑，十里聞風聲。',84,'全唐诗/poet.song.55000.json','["青松出澗壑，十里聞風聲。", "上有百尺絲，下有千歲苓。", "自性得久要，爲人制頹齡。", "小草有遠志，相依在平生。", "醫和不並世，深根且固蒂。", "人言可醫國，可用太早計。", "小大材則殊，氣味固相似。"]'),
('12717ad9-76f2-4999-8eae-4957c77a999c','醇道得蛤蜊復索舜泉舜泉已酌盡官醖不堪不敢送','黄庭堅','宋','宋诗','song-poetry','','[]','青州從事難再得，牆底數樽猶未眠。',32,'全唐诗/poet.song.55000.json','["青州從事難再得，牆底數樽猶未眠。", "商略督郵風味惡，不堪持到蛤蜊前。"]'),
('e9a9f00d-f798-4e59-bcf0-172975ad3d10','次韵王穉川客舍二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','五更歸夢常苦短，一寸客愁無奈多。',32,'全唐诗/poet.song.55000.json','["五更歸夢常苦短，一寸客愁無奈多。", "慈母每占烏鵲喜，家人應賦扊扅歌。"]'),
('d7209f59-04f2-40b5-8f4e-9fc30d03aae7','次韵王穉川客舍二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','身如病鶴翅翎短，心似亂絲頭緒多。',32,'全唐诗/poet.song.55000.json','["身如病鶴翅翎短，心似亂絲頭緒多。", "此曲朱門歌不得，湖南湖北竹枝歌。"]'),
('9cafd3e0-2a22-448c-a235-c5acd57cddc8','欵乃歌二章戲王穉川  其一','黄庭堅','宋','宋诗','song-poetry','','[]','花上盈盈人不歸，棗下纂纂實已垂。',32,'全唐诗/poet.song.55000.json','["花上盈盈人不歸，棗下纂纂實已垂。", "臘雪在時聽馬嘶，長安城中花片飛。"]'),
('f6a26081-89a5-44ea-8976-30488d52e4bd','欵乃歌二章戲王穉川  其二','黄庭堅','宋','宋诗','song-poetry','','[]','從師學道魚千里，蓋世成功黍一炊。',32,'全唐诗/poet.song.55000.json','["從師學道魚千里，蓋世成功黍一炊。", "日日倚門人不見，看盡林烏反哺兒。"]'),
('158ad3f2-300f-4421-9ded-7f56341e39dc','詠史呈徐仲車','黄庭堅','宋','宋诗','song-poetry','','[]','諸葛見益州，釋耒答三顧。',72,'全唐诗/poet.song.55000.json','["諸葛見益州，釋耒答三顧。", "川流恨未平，武功原上路。", "杜微對諸葛，輿致但求去。", "傾心倚經綸，坐上漫書疏。", "白鷗渺蒹葭，霜鶻在指呼。", "借問諸葛公，如何迎主簿。"]'),
('31e3730d-fb89-44d8-a8e4-bb41dc5fb1ec','宿舊彭澤懷陶令','黄庭堅','宋','宋诗','song-poetry','','["\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','潛魚願深渺，淵明無由逃。',132,'全唐诗/poet.song.55000.json','["潛魚願深渺，淵明無由逃。", "彭澤當此時，沈冥一世豪。", "司馬寒如灰，禮樂卯金刀。", "歲晚以字行，更始號元亮。", "凄其望諸葛，骯髒猶漢相。", "時無益州牧，指揮用諸將。", "平生本朝心，歲月閱江浪。", "空餘詩語工，落筆九天上。", "向來非無人，此友獨可尚。", "屬予剛制酒，無用酌杯盎。", "欲招千載魂，斯文或宜當。"]'),
('3ab8d1fa-0a0a-481a-8294-cee80bb01ad5','題山谷石牛洞','黄庭堅','宋','宋诗','song-poetry','','[]','司命無心播物，祖師有記傳衣。',28,'全唐诗/poet.song.55000.json','["司命無心播物，祖師有記傳衣。", "白雲橫而不度，高鳥倦而猶飛。"]'),
('a7c16db2-1551-4362-bd8a-3f7d91118fee','題灊峰閣','黄庭堅','宋','宋诗','song-poetry','','[]','徐老海棠巢上，王翁主簿峰菴。',28,'全唐诗/poet.song.55000.json','["徐老海棠巢上，王翁主簿峰菴。", "梅蘤破顔冰雪，綠叢不見黄甘。"]'),
('bfb69e91-c448-4fe7-a55b-01b7bbede2d4','次韵公擇舅','黄庭堅','宋','宋诗','song-poetry','','[]','昨夢黄粱半熟，立談白璧一雙。',28,'全唐诗/poet.song.55000.json','["昨夢黄粱半熟，立談白璧一雙。", "驚鹿要須野草，鳴鷗本願秋江。"]'),
('8adbdebc-6053-4d55-a19e-d682897465ce','贛上食蓮有感','黄庭堅','宋','宋诗','song-poetry','','[]','蓮實大如指，分甘念母慈。',120,'全唐诗/poet.song.55000.json','["蓮實大如指，分甘念母慈。", "共房頭𧥄𧥄，更深兄弟思。", "實中有幺荷，拳如小兒手。", "令我憶衆雛，迎門索梨棗。", "蓮心正自苦，食苦何能甘。", "甘餐恐腊毒，素食則懷慙。", "蓮生淤泥中，不與泥同調。", "食蓮誰不甘，知味良獨少。", "吾家雙井塘，十里秋風香。", "安得同袍子，歸製芙蓉裳。"]'),
('8aabb4b8-358f-41ca-863e-fed96f37cb8e','秋思寄子由','黄庭堅','宋','宋诗','song-poetry','','[]','黄落山川知晚秋，小蟲催女獻功裘。',32,'全唐诗/poet.song.55000.json','["黄落山川知晚秋，小蟲催女獻功裘。", "老松閱世卧雲壑，挽著滄江無萬牛。"]'),
('a32f3743-24df-49e8-8e3c-6b77fe48a22b','贈別李次翁','黄庭堅','宋','宋诗','song-poetry','','[]','利欲薰心，隨人翕張。',160,'全唐诗/poet.song.55000.json','["利欲薰心，隨人翕張。", "國好駿馬，盡爲王良。", "不有德人，俗無津梁。", "德人天遊，秋月寒江。", "映徹萬物，玲瓏八窗。", "于愛欲泥，如蓮生塘。", "處水超然，出泥而香。", "孔竅穿穴，明冰其相。", "維乃根華，其本含光。", "大雅次翁，用心不忘。", "日問月學，旅人念鄉。", "能如斯蓮，汔可小康。", "在俗行李，密密堂堂。", "觀物慈哀，涖民愛莊。", "成功萬年，付之面牆。", "草衣石質，與世低昂。"]'),
('ca70477c-533c-4170-a77f-4ceae73e3ffd','演雅','黄庭堅','宋','宋诗','song-poetry','','[]','桑蠶作繭自纏裹，蛛蝥結網工遮邏。',320,'全唐诗/poet.song.55000.json','["桑蠶作繭自纏裹，蛛蝥結網工遮邏。", "燕無居舍經始忙，蝶爲風光勾引破。", "老鶬銜石宿水飲，穉蜂趨衙供蜜課。", "鵲傳吉語安得閒，雞催晨興不敢卧。", "氣陵千里蠅附驥，枉過一生蟻旋磨。", "蝨聞湯沸尚血食，雀喜宮成自相賀。", "晴天振羽樂蜉蝣，空穴祝兒成蜾蠃。", "蛣蜣轉丸賤蘇合，飛蛾赴燭甘死禍。", "井邊蠹李螬苦肥，枝頭飲露蟬常餓。", "天螻伏隙錄人語，射工含沙須影過。", "訓狐啄屋真行怪，蠨蛸報喜太多可。", "鸕鷀密伺魚蝦便，白鷺不禁塵土涴。", "絡緯何嘗省機織，布穀未應勤種播。", "五技鼯鼠笑鳩拙，百足馬蚿憐鼈跛。", "老蚌胎中珠是賊，醯雞甕裏天幾大。", "螳螂當轍恃長臂，熠燿宵行矜照火。", "提壺猶能勸沽酒，黄口只知貪飯顆。", "伯勞饒舌世不問，鸚鵡纔言便關鏁。", "春蛙夏蜩更嘈雜，土蚓壁蟫何碎瑣。", "江南野水碧于天，中有白鷗閒似我。"]'),
('0edb5609-cd61-43c7-b757-33e75e1cba0e','戲和答禽語','黄庭堅','宋','宋诗','song-poetry','','[]','南村北村雨一犁，新婦餉姑翁哺兒。',48,'全唐诗/poet.song.55000.json','["南村北村雨一犁，新婦餉姑翁哺兒。", "田中啼鳥自四時，催人脫袴著新衣。", "著新替舊亦不惡，去年租重無袴著。"]'),
('6d59c9c7-fc79-440b-8475-a96dd986519f','贈鄭交','黄庭堅','宋','宋诗','song-poetry','','[]','高居大士是龍象，草堂丈人非熊羆。',64,'全唐诗/poet.song.55000.json','["高居大士是龍象，草堂丈人非熊羆。", "不逢壞衲乞香飯，唯見白頭垂釣絲。", "鴛鴦終日愛水鏡，菡萏晚風彫舞衣。", "開徑老禪來煮茗，還尋密竹逕中歸。"]'),
('8dfae8eb-f928-4c9e-bf39-bc1f4d22d40c','平陰張澄居士隠處三詩 仁亭','黄庭堅','宋','宋诗','song-poetry','','[]','無心經世網，有道藏丘山。',108,'全唐诗/poet.song.55000.json','["無心經世網，有道藏丘山。", "養生息天黥，藝木印歲寒。", "德人牆九仞，强學窺一斑。", "張侯大雅質，結髮闖儒關。", "奇贏或諧偶，老大嘗艱難。", "築亭上雲雨，日月轉朱欄。", "牀敷聽萬籟，我家頗寬閒。", "牧牛有坦途，亡羊自多端。", "市聲鏖午枕，常以此心觀。"]'),
('b30b484a-6314-4077-b8b0-a1a509f4ad90','平陰張澄居士隠處三詩 復庵','黄庭堅','宋','宋诗','song-poetry','','[]','舂糧出求仁，行李彌宇宙。',60,'全唐诗/poet.song.55000.json','["舂糧出求仁，行李彌宇宙。", "久客渺愁人，馬饑僕夫瘦。", "歸來一丘中，萬事不改舊。", "禾黍鋤其驕，牛羊鞭在後。", "隠几天籟寒，六鑿忽通透。"]'),
('118a2b94-89a5-48b0-9919-d15abb881289','平陰張澄居士隠處三詩 亨泉','黄庭堅','宋','宋诗','song-poetry','','[]','水德通萬物，發源會時亨。',48,'全唐诗/poet.song.55000.json','["水德通萬物，發源會時亨。", "伏坎非心願，成川且意行。", "栖遲林丘下，欲濯無塵纓。", "杖藜逢載酒，一瓢酌餘清。"]'),
('ad76102a-1f45-41da-982b-b4f553996bab','留王郎','黄庭堅','宋','宋诗','song-poetry','','[]','河外吹沙塵，江南水無津。',156,'全唐诗/poet.song.55000.json','["河外吹沙塵，江南水無津。", "骨肉常萬里，寄聲何由頻。", "我隨簡書來，顧影將一身。", "留我左右手，奉承白頭親。", "小邦王事略，蟲鳥聲無人。", "王甥解鞍馬，夜語雞喚晨。", "母慈家人肥，女惠男垂紳。", "有田爲酒事，豚韭及秋春。", "生涯得如此，舊學更光新。", "索去何草草，小留慰艱勤。", "百年才一炊，六籍經幾秦。", "要知胸中有，不與迹同陳。", "郢人懷妙質，聊欲運吾斤。"]'),
('221216a8-09c5-469b-9f3b-e726bbd28744','送王郎','黄庭堅','宋','宋诗','song-poetry','','["\u9001\u522b", "\u5199\u4eba", "\u529d\u6170", "\u8d5e\u7f8e"]','酌君以蒲城桑落之酒，泛君以湘纍秋菊之英。',188,'全唐诗/poet.song.55000.json','["酌君以蒲城桑落之酒，泛君以湘纍秋菊之英。", "贈君以黟川點漆之墨，送君以陽關墮淚之聲。", "酒澆胸次之壘塊，菊制短世之頹齡。", "墨以傳萬古文章之印，歌以寫一家兄弟之情。", "江山千里俱頭白，骨肉十年終眼青。", "連牀夜語雞戒曉，書囊無底談未了。", "有功翰墨乃如此，何恨遠別音書少。", "炊沙作糜終不飽，鏤冰文章費工巧。", "要須心地收汗馬，孔孟行世日杲杲。", "有弟有弟力持家，婦能養姑供珍鮭。", "兒大詩禮女絲麻，公但讀書煮春茶。"]'),
('f02c924a-3774-41d3-9d65-bc9f0a6bac4c','次韵劉景文登鄴王臺見思五首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','黄濁歸大壑，漣漪遶重城。',48,'全唐诗/poet.song.55000.json','["黄濁歸大壑，漣漪遶重城。", "西風一橫笛，金氣與高明。", "歸鴉度晚景，落雁带邊聲。", "平生知音處，別離空復情。"]'),
('f296e57e-7c03-4d0d-adf2-b56b0cd9ff0c','次韵劉景文登鄴王臺見思五首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','舊時劉子政，憔悴鄴王城。',48,'全唐诗/poet.song.55000.json','["舊時劉子政，憔悴鄴王城。", "把筆已頭白，見書猶眼明。", "平原秋樹色，沙麓暮鐘聲。", "歸雁南飛盡，無因寄此情。"]'),
('2d78c967-0923-49d8-8c2b-0f36a3213fa5','次韵劉景文登鄴王臺見思五首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','繫匏兩相憶，極目十餘城。',48,'全唐诗/poet.song.55000.json','["繫匏兩相憶，極目十餘城。", "積潦干斗極，山河皆夜明。", "白璧按劍起，朱絃流水聲。", "乖逢四時爾，木石了無情。"]'),
('b730c62c-345c-40c9-8b16-45105d658a53','次韵劉景文登鄴王臺見思五首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','茗花浮曾坑，酒泛酌宜城。',48,'全唐诗/poet.song.55000.json','["茗花浮曾坑，酒泛酌宜城。", "路尋西九曲，人似漢三明。", "千戶非無相，五言空有聲。", "何時郭池晚，照影寫閒情。"]'),
('e8246a71-030a-4a82-ade6-9763eacfd3ff','次韵劉景文登鄴王臺見思五首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','公詩如美色，未嫁已傾城。',48,'全唐诗/poet.song.55000.json','["公詩如美色，未嫁已傾城。", "嫁作蕩子婦，寒機泣到明。", "綠琴蛛網徧，絃絕不成聲。", "想見鴟夷子，江湖萬里情。"]'),
('557f7f71-5762-40b7-af5e-45e541d8ac06','次韵吳宣義三徑懷友','黄庭堅','宋','宋诗','song-poetry','','[]','佳眠未知曉，屋角聞晴哢。',84,'全唐诗/poet.song.55000.json','["佳眠未知曉，屋角聞晴哢。", "萬事頗忘懷，猶牽故人夢。", "采蘭秋蓬深，汲井短綆凍。", "起看冥飛鴻，乃見天宇空。", "甚念故人寒，誰省機與綜。", "在者天一方，日月老賓送。", "往者不可言，古柏守翁仲。"]'),
('abd2b2f9-cafd-4c5a-9319-884ba8018a6c','送劉季展從軍雁門二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','劉郎才力耐百戰，蒼鷹下韝秋未晚。',64,'全唐诗/poet.song.55000.json','["劉郎才力耐百戰，蒼鷹下韝秋未晚。", "千里荷戈防犬羊，十年讀書厭藜莧。", "試尋北産汗血駒，莫殺南飛寄書雁。", "人生有祿親白頭，可能一日無甘饌。"]'),
('480b34e8-f35d-43a5-9ab2-cc0020aa6f3d','送劉季展從軍雁門二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','石趺谷中玉子瘦，金剛窟前藥草肥。',64,'全唐诗/poet.song.55000.json','["石趺谷中玉子瘦，金剛窟前藥草肥。", "仙家耕耘成白璧，道人煮掘起風痱。", "絳囊璀璨思盈斗，竹畚香甘要百圍。", "到官莫道無來使，日日北風鴻雁歸。"]'),
('b9d1228d-fc39-4c54-b60e-39c27baaa4c3','題宛陵張待舉曲肱亭','黄庭堅','宋','宋诗','song-poetry','','[]','仲蔚蓬蒿宅，宣城詩句中。',60,'全唐诗/poet.song.55000.json','["仲蔚蓬蒿宅，宣城詩句中。", "人賢忘巷陋，境勝失途窮。", "寒葅書萬卷，零亂剛直胸。", "偃蹇勳業外，嘯歌山水重。", "晨雞催不起，擁被聽松風。"]'),
('58c2af3e-c7e3-48db-a4fe-f8cf882dc3ef','寄裴仲謨','黄庭堅','宋','宋诗','song-poetry','','[]','交游二十年，義等親骨肉。',132,'全唐诗/poet.song.55000.json','["交游二十年，義等親骨肉。", "風雨漂我巢，公亦未有屋。", "寄聲來問安，足音到空谷。", "我家輦轂下，薪桂炊白玉。", "在官與影俱，衣綻髮曲局。", "天機行日月，春事勤草木。", "念公篤行李，野飯中道宿。", "驚沙卷旍旗，烏尾城角謖。", "騷騷家治具，夫子且歸沐。", "作書寄後乘，爲我遣臣僕。", "起居太夫人，并問相與睦。"]'),
('0a724d86-c903-40b8-9598-b152f5f6ce71','寄黄幾復','黄庭堅','宋','宋诗','song-poetry','','["\u601d\u5ff5", "\u53cb\u60c5"]','我居北海君南海，寄雁傳書謝不能。',64,'全唐诗/poet.song.55000.json','["我居北海君南海，寄雁傳書謝不能。", "桃李春風一杯酒，江湖夜雨十年燈。", "持家但有四立壁，治病不蘄三折肱。", "想得讀書頭已白，隔溪猿哭瘴溪藤。"]'),
('2681c72b-ce02-4599-af87-57e191640112','神宗皇帝挽詞三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','文思昭日月，神武用雷霆。',48,'全唐诗/poet.song.55000.json','["文思昭日月，神武用雷霆。", "制作深垂統，憂勤減夢齡。", "孫謀開二聖，末命對三靈。", "今代誰班馬，能書汗簡青。"]'),
('99bb4e93-f812-4dce-9ce0-6bc39c9cd1f6','神宗皇帝挽詞三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','釣築收賢輔，天人與聖能。',48,'全唐诗/poet.song.55000.json','["釣築收賢輔，天人與聖能。", "輝光唐六典，度越漢中興。", "百世神宗廟，千秋永裕陵。", "帝鄉無馬跡，空望白雲乘。"]'),
('4af2a064-d23a-4ed8-b737-58a078f18c43','神宗皇帝挽詞三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','昔在基皇極，師臣論九疇。',48,'全唐诗/poet.song.55000.json','["昔在基皇極，師臣論九疇。", "丘陵忽爲谷，天地不藏舟。", "河洛功無憾，幽燕策未收。", "嗣皇朝萬國，任姒正興周。"]'),
('3f03099d-f0eb-47f4-aa4a-f5e7301351b3','王文恭公挽詞二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','先皇憑玉几，末命寄元勳。',48,'全唐诗/poet.song.55000.json','["先皇憑玉几，末命寄元勳。", "賓日行黄道，攀髯上白雲。", "四時成歲律，五色補天文。", "不謂堂堂去，今爲馬鬣墳。"]'),
('a4f35add-8b62-4491-bc21-bc1beb775df0','王文恭公挽詞二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','宥密深黄閣，光輝極上台。',48,'全唐诗/poet.song.55000.json','["宥密深黄閣，光輝極上台。", "藏舟移夜壑，華屋落泉臺。", "雨紼誰爲挽，寒笳故作哀。", "傷心具瞻地，無復衮衣來。"]'),
('cd451a3f-6151-4961-86c9-30fafa2efab6','謝送碾壑源揀芽','黄庭堅','宋','宋诗','song-poetry','','[]','矞雲從龍小蒼璧，元豐至今人未識。',160,'全唐诗/poet.song.55000.json','["矞雲從龍小蒼璧，元豐至今人未識。", "壑源包貢第一春，緗奩碾香供玉食。", "睿思殿東金井欄，甘露薦椀天開顔。", "橋山事嚴庀百局，補衮諸公省中宿。", "中人傳賜夜未央，雨露恩光照宮燭。", "右丞似是李元禮，好事風流有涇渭。", "肯憐天祿校書郎，親敕家庭遣分似。", "春風飽識大官羊，不慣腐儒湯餠腸。", "搜攪十年燈火讀，令我胸中書傳香。", "已戒應門老馬走，客來問字莫載酒。"]'),
('147a2f8c-dd59-4c22-9be0-79bf2e0002c3','以小團龍及半挺贈无咎并詩用前韵爲戲','黄庭堅','宋','宋诗','song-poetry','','[]','我持玄圭與蒼璧，以暗投人渠不識。',160,'全唐诗/poet.song.55000.json','["我持玄圭與蒼璧，以暗投人渠不識。", "城南窮巷有佳人，不索賓郎常晏食。", "赤銅茗椀雨斑斑，銀粟翻光解破顔。", "上有龍文下棋局，探囊贈君諾已宿。", "此物已是元豐春，先皇聖功調玉燭。", "晁子胸中開典禮，平生自期莘與渭。", "故用澆君磊隗胸，莫令鬢毛雪相似。", "曲几團蒲聽煮湯，煎成車聲繞羊腸。", "雞蘇胡麻留渴羌，不應亂我官焙香。", "肥如瓠壺鼻雷吼，幸君飲此勿飲酒。"]'),
('a1177134-eb25-47e0-b8f6-946a2fa1cb76','和答外舅孫莘老','黄庭堅','宋','宋诗','song-poetry','','[]','西風挽不來，殘暑推不去。',144,'全唐诗/poet.song.55000.json','["西風挽不來，殘暑推不去。", "出門厭靴帽，稅駕喜巾屨。", "道山鄰日月，清樾深牖戶。", "同舍多望郎，閒官無窘步。", "少監巖壑姿，宿昔廊廟具。", "行趨補衮職，黼黻我王度。", "歸休飲熱客，觴豆愆調護。", "浩然養靈根，勿藥有神助。", "寄聲舊僚屬，訓詁及匕箸。", "尚憐費諫紙，玉唾灑新句。", "北焙碾玄璧，谷簾煮甘露。", "何時臨書几，剝芡談至暮。"]'),
('3f560692-62b5-4ceb-8f27-4c83e60b434d','次韵定國聞子由卧病績溪','黄庭堅','宋','宋诗','song-poetry','','[]','炎洲冬無冰，十月雷虺虺。',168,'全唐诗/poet.song.55000.json','["炎洲冬無冰，十月雷虺虺。", "及春瘧癘行，用人祭非鬼。", "巫師司民命，藥石不入市。", "溪弩潛發機，土風甚不美。", "蘇子卧江南，感歎中夜起。", "聞道病在牀，食魚不知旨。", "寒暑戰胸中，士窮有如此。", "此公天機深，爵祿心已死。", "養生遺形骸，觀妙得骨髓。", "后皇蒔嘉橘，中歲多成枳。", "佳人何時來，爲天啟玉齒。", "湔祓瘴霧姿，朝趨去天咫。", "諸公轉洪鈞，國器方薦砥。", "矢詩寫予心，莊語不加綺。"]'),
('169cd0df-adab-4c1c-aca5-fb3afb2550a6','次韵子由績溪病起被召寄王定國','黄庭堅','宋','宋诗','song-poetry','','[]','種萱盈九畹，蘇子憂國病。',288,'全唐诗/poet.song.55000.json','["種萱盈九畹，蘇子憂國病。", "炎蒸卧百戰，山立有餘勁。", "斯人廊廟器，不合從遠屏。", "江湖摇歸心，毛髮侵老境。", "艱難喜歸來，如晴月生嶺。", "仍懷阻歸舟，風水蛟鰐橫。", "補衮諫官能，用儒吾道盛。", "上書詆平津，蠹藁初記省。", "至今民社計，非事頰舌競。", "方來立本朝，獻納繼晨暝。", "人材包新舊，王度濟寬猛。", "必開曲突謀，滿慰傾耳聽。", "斯文呂與張，泉下亦蘇醒。", "天聰四門闢，國勢九鼎定。", "身得遭太平，分甘守閒冷。", "天津十年面，想見頎而整。", "何時及國門，休暇過煮茗。", "燒燈留夜語，鴻雁看對影。", "但恐張羅地，頗復多造請。", "維此禮部公，寒泉甃舊井。", "謫去久羸瓶，召還汲修綆。", "太任决齋宮，陛下天統慶。", "日月進亨衢，經緯寒耿耿。", "西走已和戎，南遷無哀郢。"]'),
('c9ae9e2b-fbc5-4efc-b1e7-d9d543a3b597','次韵李之純少監惠硯','黄庭堅','宋','宋诗','song-poetry','','[]','黄公山下黄雞秋，持節恤刑曾少休。',160,'全唐诗/poet.song.55000.json','["黄公山下黄雞秋，持節恤刑曾少休。", "小人負弩得開道，掃葉張飲林巖幽。", "相傳有石非地産，列仙持來自羅浮。", "酒酣步出雲雨上，南撫方城西嵩丘。", "林端乃見石空洞，猛獸贔屭踞上頭。", "鳥道兔迒謀挽致，萬牛不動五丁愁。", "道家蓬萊見仙伯，我亦洗湔與清流。", "探囊贈研頗宜墨，近出黄山非遠求。", "乃知此山自才美，物欲致用當窮搜。", "迷邦故令成器晚，不琢元非匠石羞。"]'),
('ab115ed9-5aa9-4d91-9c81-ba60122d630e','送舅氏野夫之宣城二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','藉甚宣城郡，風流數貢毛。',48,'全唐诗/poet.song.55000.json','["藉甚宣城郡，風流數貢毛。", "霜林收鴨脚，春網薦琴高。", "共理須良守，今年輟省曹。", "平生割雞手，聊試發硎刀。"]'),
('6d8764c3-a486-421a-9cfb-0d83c2058621','送舅氏野夫之宣城二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','試說宣城郡，停盃且細聽。',48,'全唐诗/poet.song.55000.json','["試說宣城郡，停盃且細聽。", "晚樓明宛水，春騎簇昭亭。", "䆉稏豐圩戶，桁楊卧訟庭。", "謝公歌舞處，時對換鵝經。"]'),
('152b2d0e-cd38-4677-af01-c9b128f7c520','送范德孺知慶州','黄庭堅','宋','宋诗','song-poetry','','["\u5199\u4eba", "\u671f\u671b", "\u9001\u522b", "\u8d5e\u7f8e", "\u6292\u6000"]','乃翁知國如知兵，塞垣草木識威名。',144,'全唐诗/poet.song.55000.json','["乃翁知國如知兵，塞垣草木識威名。", "敵人開戶玩處女，掩耳不及驚雷霆。", "平生端有活國計，百不一試薶九京。", "阿兄兩持慶州節，十年騏驎地上行。", "潭潭大度如卧虎，邊頭耕桑長兒女。", "折衝千里雖有餘，論道經邦正要渠。", "妙年出補父兄處，公自才力應時須。", "春風旍旗擁萬夫，幕下諸將思草枯。", "智名勇功不入眼，可用折箠笞羌胡。"]'),
('52e65454-1322-4c7b-abe2-4b39c0fd314a','題王黄州墨蹟後','黄庭堅','宋','宋诗','song-poetry','','[]','掘地與斷木，智不如機舂。',96,'全唐诗/poet.song.55000.json','["掘地與斷木，智不如機舂。", "聖人懷餘巧，故爲萬物宗。", "世有斲泥手，或不待郢工。", "往時王黄州，謀國極匪躬。", "朝聞不及夕，百壬避其鋒。", "九鼎安盤石，一身轉孤蓬。", "浮雲當日月，白髮照秋空。", "諸君發蒙耳，汲直與臣同。"]'),
('094008fb-fdee-4dd1-bae0-14b8050aa04f','題王仲弓兄弟巽亭','黄庭堅','宋','宋诗','song-poetry','','[]','大隗七聖迷，許田連城重。',156,'全唐诗/poet.song.55000.json','["大隗七聖迷，許田連城重。", "里中多佳樹，與世作梁棟。", "市門行清渠，潩水可抱甕。", "翬飛城東南，隠几撫羣動。", "人境要俱爾，我乃得大用。", "烏衣之雲孫，昆弟不好弄。", "木末風雨來，卷箔醉賓從。", "事常超然觀，樂與賢者共。", "人登斷龍求，我自歸鴻送。", "溪毛亂錦纈，候蟲響機綜。", "世紛甚崢嶸，胸次欲空洞。", "讀書開萬卷，謀國妙百中。", "儻無斲鼻工，聊付曲肱夢。"]'),
('a25d137a-dde2-4d94-94b0-aec4226252ae','寄尉氏倉官王仲弓','黄庭堅','宋','宋诗','song-poetry','','[]','嘯臺有佳人，玄髮鑑䈂珥。',48,'全唐诗/poet.song.55000.json','["嘯臺有佳人，玄髮鑑䈂珥。", "登高歌一曲，聽者傾城市。", "門無行媒迹，草木倚憔悴。", "人物方眇然，誰能委圭幣。"]'),
('10f7463a-253d-4d48-b2b7-c6ceee5e59dc','有惠江南帳中香者戲答六言二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','百鍊香螺沉水，寶薰近出江南。',28,'全唐诗/poet.song.55000.json','["百鍊香螺沉水，寶薰近出江南。", "一穟黄雲繞几，深禪想對同參。"]'),
('f67ed760-7754-44ae-9f6e-5b73b240a66c','有惠江南帳中香者戲答六言二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','螺甲割崑崙耳，香材屑鷓鴣斑。',28,'全唐诗/poet.song.55000.json','["螺甲割崑崙耳，香材屑鷓鴣斑。", "欲雨鳴鳩日永，下帷睡鴨春閒。"]'),
('942198e8-c6c5-45af-a17b-90606c1042a3','子瞻繼和復答二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','置酒未容虛左，論詩時要指南。',28,'全唐诗/poet.song.55000.json','["置酒未容虛左，論詩時要指南。", "迎笑天香滿袖，喜公新赴朝參。"]'),
('ef7608aa-a87f-4215-a1fe-ca0c9bd87e1b','子瞻繼和復答二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','迎燕溫風旎旎，潤花小雨斑斑。',28,'全唐诗/poet.song.55000.json','["迎燕溫風旎旎，潤花小雨斑斑。", "一炷煙中得意，九衢塵裏偷閒。"]'),
('ab43fcb8-b2b4-4e7f-af8d-2a9868d06c2a','有聞帳中香以爲熬蝎者戲用前韵二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','海上有人逐臭，天生鼻孔司南。',28,'全唐诗/poet.song.55000.json','["海上有人逐臭，天生鼻孔司南。", "但印香嚴本寂，不必叢林徧參。"]'),
('843355ca-eb7a-4bb0-ae11-5f20daa981d0','有聞帳中香以爲熬蝎者戲用前韵二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','我讀蔚宗香傳，文章不減二班。',28,'全唐诗/poet.song.55000.json','["我讀蔚宗香傳，文章不減二班。", "誤以甲爲淺俗，却知麝要防閑。"]'),
('b451bafc-86a9-467f-85d6-2f8c23c324d6','謝公擇舅分賜茶三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','外家新賜蒼龍璧，北焙風煙天上來。',32,'全唐诗/poet.song.55000.json','["外家新賜蒼龍璧，北焙風煙天上來。", "明日蓬山破寒月，先甘和夢聽春雷。"]'),
('7ed74c3e-1fa6-48f7-9edc-761fc8d93f1d','謝公擇舅分賜茶三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','文書滿案惟生睡，夢裏鳴鳩喚雨來。',32,'全唐诗/poet.song.55000.json','["文書滿案惟生睡，夢裏鳴鳩喚雨來。", "乞與降魔大圓鏡，真成破柱作驚雷。"]'),
('a78b419a-642d-4f21-ad18-756a7e83bf36','謝公擇舅分賜茶三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','細題葉字包青箬，割取丘郎春信來。',32,'全唐诗/poet.song.55000.json','["細題葉字包青箬，割取丘郎春信來。", "拚洗一春湯餠睡，亦知清夜有蚊雷。"]'),
('23c28599-b1c1-4c6d-8201-0e073b2f9f1a','便糶王丞送碧香酒用子瞻韵戲贈鄭彥能','黄庭堅','宋','宋诗','song-poetry','','[]','食貧好酒嘗自嘲，日給上尊無骨相。',96,'全唐诗/poet.song.55000.json','["食貧好酒嘗自嘲，日給上尊無骨相。", "大農部丞送新酒，碧香竊比主家釀。", "應憐坐客竟無氈，更遭官長頗譏謗。", "銀杯同色試一傾，排遣春寒出帷帳。", "浮蛆翁翁杯底滑，坐想康成論泛盎。", "重門著關不爲君，但備惡客來仇餉。"]'),
('4bce817b-cbd0-457e-a7af-23d7c56c7be5','送鄭彥能宣德知福昌縣','黄庭堅','宋','宋诗','song-poetry','','[]','往時河北盜橫行，白晝驅人取城郭。',112,'全唐诗/poet.song.55000.json','["往時河北盜橫行，白晝驅人取城郭。", "唯聞不犯鄭冠氏，犬卧不驚民氣樂。", "秖今化民作鋤耰，田舍老翁百不憂。", "銅章去作福昌縣，山中讀書民有秋。", "福昌愛民如父母，當官不擾萬事舉。", "用才之地要得人，眼中虛席十四五。", "不知諸公用心許，魯恭卓茂可人否。"]'),
('bf01e571-90bc-4e9b-95b0-8c31bd01a6ad','顯聖寺庭枸杞','黄庭堅','宋','宋诗','song-poetry','','[]','仙苗壽日月，佛界承露雨。',72,'全唐诗/poet.song.55000.json','["仙苗壽日月，佛界承露雨。", "誰爲萬年計，乞此一抔土。", "扶疏上翠蓋，磊落綴丹乳。", "去家尚不食，出家何用許。", "正恐落人間，采剝四時苦。", "養成九節杖，持獻西王母。"]'),
('4afa2a6c-80f1-4eca-bbf0-4a3811376d50','次韵子瞻贈王定國','黄庭堅','宋','宋诗','song-poetry','','[]','遠志作小草，蛙衣生陵屯。',120,'全唐诗/poet.song.55000.json','["遠志作小草，蛙衣生陵屯。", "但爲居移氣，其實何足言。", "名下難爲人，醜好隨手翻。", "百年炊未熟，一垤蟻追奔。", "夏日蓬山永，戎葵茂牆藩。", "王子吐佳句，如繭絲出盆。", "風姿極灑落，雲氣畫罍樽。", "屬有補衮章，自當寵頻煩。", "鄙夫無他能，上車問寒溫。", "惟思窮山去，抱犢長兒孫。"]'),
('4b0dac01-85a6-46f9-bfcf-fed935daecc3','次韵張詢齋中晚春','黄庭堅','宋','宋诗','song-poetry','','[]','學古編簡殘，懷人江湖永。',72,'全唐诗/poet.song.55000.json','["學古編簡殘，懷人江湖永。", "非無車馬客，心遠境亦靜。", "挽蔬夜雨畦，煮茗寒泉井。", "春去不窺園，黄鸝頗三請。", "立朝無物望，補外儻天幸。", "想乘滄浪船，濯髮晞翠嶺。"]'),
('0062572c-4fb0-43fa-9ef5-df9d53ead8bd','次韵答晁无咎見贈','黄庭堅','宋','宋诗','song-poetry','','[]','翕翕一日炎，耽耽萬年永。',72,'全唐诗/poet.song.55000.json','["翕翕一日炎，耽耽萬年永。", "四海仰首觀，頃復歸根靜。", "時雨瀉玉除，潢流漲天井。", "性不耐衣冠，入門疏造請。", "煮餠卧北窗，保此已徼幸。", "空餘見賢心，忍渴望梅嶺。"]'),
('7a488481-ef7f-40c9-b1d3-8588840a2381','次韵答張文潛惠寄','黄庭堅','宋','宋诗','song-poetry','','[]','短褐不磷緇，文章近楚辭。',96,'全唐诗/poet.song.55000.json','["短褐不磷緇，文章近楚辭。", "未識想風采，別去令人思。", "斯文已戰勝，凱歌偃旍旂。", "君行魚上冰，忽復燕哺兒。", "學省得佳士，催來費符移。", "方觀追金玉，如許遽言歸。", "南山有君子，握蘭懷令姿。", "但應潔齋俟，勿詠無生詩。"]'),
('1a12a80a-458b-4716-9c3d-8407838ff5b8','同錢志仲飯藉田錢孺文官舍','黄庭堅','宋','宋诗','song-poetry','','[]','帝藉開千畝，農功先九州。',120,'全唐诗/poet.song.55000.json','["帝藉開千畝，農功先九州。", "王孫守耒耜，吏隠極風流。", "永夏豐草木，五雲衛郊丘。", "牛羊卧籬落，賓客解衣裘。", "汲井羞熱啜，挽溪供甘柔。", "倒靫收蓮的，剖蚌煮鴻頭。", "野日草光合，水風荷氣浮。", "稻畦下白鷺，林樾應鳴鳩。", "主人發清賞，況復佳同遊。", "歸扇障小雨，真成一賜休。"]'),
('3b4880f5-135f-458a-8fa0-641208410872','次韵曾子開舍人遊藉田載荷花歸','黄庭堅','宋','宋诗','song-poetry','','[]','維王調玉燭，時夏雨我田。',180,'全唐诗/poet.song.55000.json','["維王調玉燭，時夏雨我田。", "壁掛蒼龍骨，溜渠故濺濺。", "三推勸根本，百穀收皂堅。", "官司極齋明，崇丘見升煙。", "繫馬西門柳，憶聽去夏蟬。", "剝芡珠走盤，釣魚柳貫鮮。", "掃堂延枕簟，公子氣翩翩。", "自爾欲繼往，阻心如壅泉。", "紫微樂暇日，披襟詠風漣。", "紅妝倚荷蓋，水鏡寫明蠲。", "美物亦有實，剪房助加籩。", "珠宮紫貝闕，足此水府仙。", "鬰鬰冠蓋宅，追奔易彫年。", "能從物外賞，真是區中賢。", "仍聞載後乘，籠燭照嬋娟。"]'),
('27e9837c-c5b3-4dfb-ac55-18dbef88f0bd','送劉士彥赴福建轉運判官','黄庭堅','宋','宋诗','song-poetry','','[]','秋葉雨墮來，冥鴻天資高。',120,'全唐诗/poet.song.55000.json','["秋葉雨墮來，冥鴻天資高。", "車馬氣成霧，九衢行滔滔。", "中有寂寞人，靈府扃鎖牢。", "西風持漢節，騎從嚴弓刀。", "惟閩七聚落，惸獨困吏饕。", "土弊禾黍惡，水煩鱗介勞。", "南驅將仁氣，百城共一陶。", "察人極涇渭，問俗及豚羔。", "官閒得勝日，杖屨之林臯。", "人間閱忠厚，物外訪英豪。"]'),
('dcdf02aa-386b-491d-a113-dfde9bda1e1b','次韵韓川奉祠西太乙宮四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','萬靈未對甘泉，五福問祀迎年。',28,'全唐诗/poet.song.55000.json','["萬靈未對甘泉，五福問祀迎年。", "旍旂三斿半偃，風馬雲車闖然。"]'),
('de6fcb88-3aed-4a73-a51d-8524344d3ac7','次韵韓川奉祠西太乙宮四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','白髦下金神節，青祝携御爐香。',28,'全唐诗/poet.song.55000.json','["白髦下金神節，青祝携御爐香。", "百禮盡修亳祀，九歌不取沈湘。"]'),
('3c1cba3c-7bd5-427a-a627-023bb4bd6afc','次韵韓川奉祠西太乙宮四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','紫府侍臣鳴玉，霜臺御史生風。',28,'全唐诗/poet.song.55000.json','["紫府侍臣鳴玉，霜臺御史生風。", "官燭論詩未了，知秋自屬梧桐。"]'),
('dae6e4ab-fffe-4295-9f19-f2dc54c1a91f','次韵韓川奉祠西太乙宮四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','泰壇下瑞雲黄，雨師灑道塵香。',28,'全唐诗/poet.song.55000.json','["泰壇下瑞雲黄，雨師灑道塵香。", "便面猶承墜露，金鉦半吐東牆。"]'),
('25934aba-eabb-4736-a5cd-39a672d952d8','次韵王荆公題西太乙宮壁二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','風急啼烏未了，雨來戰蟻方酣。',28,'全唐诗/poet.song.55000.json','["風急啼烏未了，雨來戰蟻方酣。", "真是真非安在，人間北看成南。"]'),
('1b656bc3-6e78-4a21-86c8-ca1d6f484b1b','次韵王荆公題西太乙宮壁二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','晚風池蓮香度，曉日宮槐影西。',28,'全唐诗/poet.song.55000.json','["晚風池蓮香度，曉日宮槐影西。", "白下長干夢到，青門紫曲塵迷。"]'),
('9334cd3b-b66c-44b9-b85a-3c0462950279','有懷半山老人再次韵二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','短世風驚雨過，成功夢迷酒酣。',28,'全唐诗/poet.song.55000.json','["短世風驚雨過，成功夢迷酒酣。", "草玄不妨準易，論詩終近周南。"]'),
('264aa8ed-59d8-4890-924d-2e14d578f3f6','有懷半山老人再次韵二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','啜羹不如放麑，樂羊終愧巴西。',28,'全唐诗/poet.song.55000.json','["啜羹不如放麑，樂羊終愧巴西。", "欲問老翁歸處，帝鄉無路雲迷。"]'),
('fbc984bb-4eaf-4787-88ac-f56b3de00ef2','和答錢穆父詠猩猩毛筆','黄庭堅','宋','宋诗','song-poetry','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','愛酒醉魂在，能言機事疏。',48,'全唐诗/poet.song.55000.json','["愛酒醉魂在，能言機事疏。", "平生幾兩屐，身後五車書。", "物色看王會，勳勞在石渠。", "拔毛能濟世，端爲謝楊朱。"]'),
('856bd672-d323-4c2c-b103-cd88d166d4ee','戲詠猩猩毛筆二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','桄榔葉暗賓郎紅，朋友相呼墮酒中。',32,'全唐诗/poet.song.55000.json','["桄榔葉暗賓郎紅，朋友相呼墮酒中。", "正以多知巧言語，失身來作管城公。"]'),
('b4a8ab57-7b8d-4ca5-8e25-0693e52f6d78','戲詠猩猩毛筆二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','明窗脫帽見蒙茸，醉著青鞋在眼中。',32,'全唐诗/poet.song.55000.json','["明窗脫帽見蒙茸，醉著青鞋在眼中。", "束縛歸來儻無辱，逢時猶作黑頭公。"]'),
('6cebfba6-7fd3-44c2-9bea-261f06980112','奉和文潛贈无咎篇末多見及以既見君子云胡不喜爲韵  其一','黄庭堅','宋','宋诗','song-poetry','','[]','龜以靈故焦，雉以文故翳。',48,'全唐诗/poet.song.55000.json','["龜以靈故焦，雉以文故翳。", "本心如日月，利欲食之既。", "後生玩華藻，照影終沒世。", "安得八紘罝，以道獵衆智。"]'),
('35f31be0-a11d-4a2e-87d6-ce3f39fafc60','奉和文潛贈无咎篇末多見及以既見君子云胡不喜爲韵  其二','黄庭堅','宋','宋诗','song-poetry','','[]','談經用燕說，束棄諸儒傳。',48,'全唐诗/poet.song.55000.json','["談經用燕說，束棄諸儒傳。", "濫觴雖有罪，末派瀰九縣。", "張侯真理窟，堅壁不與戰。", "難以口舌爭，水清石自見。"]'),
('ddef7439-294c-491e-883f-8ad0d21de3d8','奉和文潛贈无咎篇末多見及以既見君子云胡不喜爲韵  其三','黄庭堅','宋','宋诗','song-poetry','','[]','野性友麋鹿，君非我同羣。',48,'全唐诗/poet.song.55000.json','["野性友麋鹿，君非我同羣。", "文明近日月，我亦不如君。", "十載長相望，逝川水沄沄。", "何當談絕倒，茗椀對爐薰。"]'),
('02b1e87b-d059-47fb-9722-7f09e060bc14','奉和文潛贈无咎篇末多見及以既見君子云胡不喜爲韵  其四','黄庭堅','宋','宋诗','song-poetry','','[]','北寺鎖齋房，塵鑰時一啟。',48,'全唐诗/poet.song.55000.json','["北寺鎖齋房，塵鑰時一啟。", "晁張跫然來，連璧照書几。", "庭柏鬰葱葱，紅榴罅多子。", "時蒙吐佳句，幽處萬籟起。"]'),
('2ef26474-f0a0-4a37-bcbf-edb3c197dd0a','奉和文潛贈无咎篇末多見及以既見君子云胡不喜爲韵  其五','黄庭堅','宋','宋诗','song-poetry','','[]','先皇元豐未，極厭士淺聞。',48,'全唐诗/poet.song.55000.json','["先皇元豐未，極厭士淺聞。", "只今舉秀孝，天未喪斯文。", "晁張班馬首，崔蔡不足云。", "當令橫筆陣，一戰靜楚氛。"]'),
('053ca9a8-4384-4966-bef1-19d7fe4bf69a','奉和文潛贈无咎篇末多見及以既見君子云胡不喜爲韵  其六','黄庭堅','宋','宋诗','song-poetry','','[]','張侯窘炊玉，僦屋得空壚。',48,'全唐诗/poet.song.55000.json','["張侯窘炊玉，僦屋得空壚。", "但見索酒郎，不見酒家胡。", "雖肥如瓠壺，胸中殊不麤。", "何用知如此，文彩似於菟。"]'),
('859eb4a6-b3e8-4189-a585-64dd1089f2b4','奉和文潛贈无咎篇末多見及以既見君子云胡不喜爲韵  其七','黄庭堅','宋','宋诗','song-poetry','','[]','荆公六藝學，妙處端不朽。',48,'全唐诗/poet.song.55000.json','["荆公六藝學，妙處端不朽。", "諸生用其短，頗復鑿戶牖。", "譬如學捧心，初不悟己醜。", "玉石恐俱焚，公爲區別不。"]'),
('13264335-0436-415d-987d-2f371dc2af10','奉和文潛贈无咎篇末多見及以既見君子云胡不喜爲韵  其八','黄庭堅','宋','宋诗','song-poetry','','[]','吾友陳師道，抱獨門掃軌。',48,'全唐诗/poet.song.55000.json','["吾友陳師道，抱獨門掃軌。", "晁張作薦書，射雉用一矢。", "吾聞舉逸民，故得天下喜。", "兩公陣堂堂，此士可摩壘。"]'),
('b675162c-67f5-4b63-b2e5-b555109b0c9f','次韵答邢惇夫','黄庭堅','宋','宋诗','song-poetry','','[]','爲山不能山，過在一簣止。',192,'全唐诗/poet.song.55000.json','["爲山不能山，過在一簣止。", "渥洼騏驎兒，墮地志千里。", "岷江初濫觴，入楚乃無底。", "將升聖人堂，道固有廉陛。", "邢子好少年，如世有源水。", "方求無津涯，不作蛙井喜。", "兒中兀老蒼，趣造甚奇異。", "過閱王公門，袖中有漫刺。", "別來阻河山，望遠每障袂。", "斯文向千載，有志常寡遂。", "後生文楚楚，照影若孔翠。", "不應太玄草，睎價咸陽市。", "雨作枕簞秋，官閒省中睡。", "夢不到漢東，茗椀乃爲祟。", "聞君肺渴減，頗復佳食寐。", "讀書得新功，來雁寄一字。"]'),
('a2ed3bdc-45e2-46a2-ae59-733502a7e547','和邢惇夫秋懷十首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','殘暑已俶裝，好風方來歸。',48,'全唐诗/poet.song.55000.json','["殘暑已俶裝，好風方來歸。", "未能疏團扇，且復製秋衣。", "高蟬遽如許，長吟送落暉。", "相戒趣女功，莎蟲能表微。"]'),
('d52f6b54-346e-4f51-9e1f-ff077015a6fa','和邢惇夫秋懷十首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','曩時高唐客，暮雨朝行雲。',48,'全唐诗/poet.song.55000.json','["曩時高唐客，暮雨朝行雲。", "陰居懷天匹，楚觀夢紛紜。", "我欲睹光儀，齋明炷爐薰。", "天高萬物肅，誰爲帝子魂。"]'),
('7b1c4c47-d702-4684-8b3c-160c41f262c5','和邢惇夫秋懷十首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','七均師無聲，五和常主淡。',48,'全唐诗/poet.song.55000.json','["七均師無聲，五和常主淡。", "芸芸觀此歸，一德貫真濫。", "夢臨秋江水，魚蝦避窺瞰。", "明月本無心，誰令作寒鑑。"]'),
('e72c0cc3-ebc3-4f3f-a9b9-9c55c9aac69e','和邢惇夫秋懷十首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','王度無畦畛，包荒用馮河。',48,'全唐诗/poet.song.55000.json','["王度無畦畛，包荒用馮河。", "秦收鄭渠成，晉得楚材多。", "用人當其物，不但軸與薖。", "六通而四闢，玉燭四時和。"]'),
('07dbb9a9-eb65-428a-abf8-a14f96b1e684','和邢惇夫秋懷十首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','相如用全趙，留侯開有漢。',48,'全唐诗/poet.song.55000.json','["相如用全趙，留侯開有漢。", "名登太山重，功略天下半。", "讓頗封韓彭，事成羣疑泮。", "天道當曲全，小智驁後患。"]'),
('50d45964-98e6-4d4c-9ff5-01be06c8e7ea','和邢惇夫秋懷十首  其六','黄庭堅','宋','宋诗','song-poetry','','[]','慶州名父子，忠勇橫八區。',48,'全唐诗/poet.song.55000.json','["慶州名父子，忠勇橫八區。", "許身如稷契，初不學孫吳。", "荷戈去防秋，面皺鬢欲疏。", "雖折千里衝，豈若秉事樞。"]'),
('cae2f64d-96ad-43ce-ae75-15a6d73f5e36','和邢惇夫秋懷十首  其七','黄庭堅','宋','宋诗','song-poetry','','[]','謝公藴風流，詩作鮑照語。',48,'全唐诗/poet.song.55000.json','["謝公藴風流，詩作鮑照語。", "絲蟲縈草紙，筆力挾風雨。", "萬里投諫書，石交化豺虎。", "世方用賢髦，先成泉下土。"]'),
('34551b59-28f5-48bd-b8af-d28e9f7e97af','和邢惇夫秋懷十首  其八','黄庭堅','宋','宋诗','song-poetry','','[]','今日呂虢州，堂堂古遺直。',48,'全唐诗/poet.song.55000.json','["今日呂虢州，堂堂古遺直。", "許國輸九死，補天鍊五色。", "頗修諫員缺，人壽無金石。", "西風壯夫淚，多爲程顥滴。"]'),
('8d926d0f-6efb-4a8e-b771-d16b484b6224','和邢惇夫秋懷十首  其九','黄庭堅','宋','宋诗','song-poetry','','[]','吾友陳師道，抱瑟不吹竽。',48,'全唐诗/poet.song.55000.json','["吾友陳師道，抱瑟不吹竽。", "文章似揚馬，欬唾落明珠。", "固窮有膽氣，風壑嘯於菟。", "秋來入詩律，陶謝不枝梧。"]'),
('9d11e15a-bd4a-4ff6-9e24-c365fb5cd537','和邢惇夫秋懷十首  其一○','黄庭堅','宋','宋诗','song-poetry','','[]','邢子卧北窗，吟秋意少悰。',48,'全唐诗/poet.song.55000.json','["邢子卧北窗，吟秋意少悰。", "讀書用意苦，嘔血驚乃翁。", "安得和扁輩，爲浣學古胸。", "肺熱今好否，微凉生井桐。"]'),
('19f9e90c-b210-49d7-b158-6f6811ea95a5','謝公定和二范秋懷五首邀予同作  其一','黄庭堅','宋','宋诗','song-poetry','','[]','西風一葉脫，迹亦不可掃。',48,'全唐诗/poet.song.55000.json','["西風一葉脫，迹亦不可掃。", "巷有白馬生，朝回焚諫草。", "誰云事君難，是亦父子間。", "所要功補衮，不言能犯顔。"]'),
('8632b3fe-0b6d-4067-80cd-b1620a37f4e8','謝公定和二范秋懷五首邀予同作  其二','黄庭堅','宋','宋诗','song-poetry','','[]','四會有黄令，學古著勳多。',48,'全唐诗/poet.song.55000.json','["四會有黄令，學古著勳多。", "白頭對紅葉，奈此摇落何。", "雖懷斲鼻巧，有斧且無柯。", "安得五十絃，奏此寒士歌。"]'),
('590288a6-f11e-402e-9259-399446ba4d23','謝公定和二范秋懷五首邀予同作  其三','黄庭堅','宋','宋诗','song-poetry','','[]','采蓮涉江湖，采菊度林藪。',48,'全唐诗/poet.song.55000.json','["采蓮涉江湖，采菊度林藪。", "插鬢不成妍，誰憐飛蓬首。", "平生耦耕地，風雨深稂莠。", "謝公遂如此，永袖絕絃手。"]'),
('2e374db6-0eec-4f9c-9b37-a656aff69caf','謝公定和二范秋懷五首邀予同作  其四','黄庭堅','宋','宋诗','song-poetry','','[]','往日孫陽翟，才可任遺補。',48,'全唐诗/poet.song.55000.json','["往日孫陽翟，才可任遺補。", "擊强如摧枯，食蘗不知苦。", "屬者缺諫垣，時論或未許。", "儻可假一邦，使民作鄒魯。"]'),
('4d17a947-0703-435a-b878-6944edb15ecd','謝公定和二范秋懷五首邀予同作  其五','黄庭堅','宋','宋诗','song-poetry','','[]','用智常恨耄，用决常恨早。',48,'全唐诗/poet.song.55000.json','["用智常恨耄，用决常恨早。", "推轂天下士，誠心要傾倒。", "海宇日清明，廟堂勤洒掃。", "何爲陳師道，白髮三徑草。"]'),
('1e9b1b72-bb6a-433c-ac0c-01ae9a7f7573','送謝公定作竟陵主簿','黄庭堅','宋','宋诗','song-poetry','','[]','謝公文章如虎豹，至今斑斑在兒孫。',128,'全唐诗/poet.song.55000.json','["謝公文章如虎豹，至今斑斑在兒孫。", "竟陵主簿極多聞，萬事不理專討論。", "澗松無心古鬚鬣，天球不瑑中粹溫。", "落筆塵沙百馬奔，劇談風霆九河翻。", "胸中恢疏無怨恩，當官持廉庭不煩。", "吏民欺公亦可忍，慎勿驚魚使水渾。", "漢濱耆舊今誰存，駟馬高蓋徒紛紛。", "安知四海習鑿齒，拄笏看度南山雲。"]'),
('a46efd55-578b-4cc4-9bb8-4a18e4c1da28','奉答謝公靜與榮子邕論狄元規孫少述詩長韵','黄庭堅','宋','宋诗','song-poetry','','[]','謝公遂如此，宰木已三霜。',120,'全唐诗/poet.song.55000.json','["謝公遂如此，宰木已三霜。", "無人知句法，秋月自澄江。", "二子學邁俗，窺杜見牖窗。", "試斲郢人鼻，未免傷手創。", "蟹胥與竹萌，乃不美羊腔。", "自往見謝公，論詩得濠梁。", "世方尊兩耳，未敢築受降。", "丹穴鳳凰羽，風林虎豹章。", "小謝有家法，聞此不聽冰。", "相思北風惡，歸雁落斜行。"]'),
('7ed50ca1-893a-47bf-a677-c543bd712702','贈送張叔和','黄庭堅','宋','宋诗','song-poetry','','[]','張侯溫如鄒子律，能令陰谷黍生春。',194,'全唐诗/poet.song.55000.json','["張侯溫如鄒子律，能令陰谷黍生春。", "有齊先君之季女，十年擇對無可人。", "箕帚掃公堂上塵，家風孝友故相親。", "廟中時薦南澗蘋，兒女衣袴得補紉。", "兩家俱爲白頭計，察公與人意甚真。", "吏能束縛老姦手，要使鰥寡無顰呻。", "但迴此光還照己，平生倦學皆日新。", "我提養生之四印，君家所有更贈君。", "百戰百勝不如一忍，萬言萬當不如一默。", "無可簡擇眼界平，不藏秋毫心地直。", "我肱三折得此醫，自覺兩踵生光輝。", "團蒲日靜鳥吟時，爐薰一炷試觀之。"]'),
('62b80f3d-e52c-4083-9856-4bb2335fb1ad','送顧子敦赴河東三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','頭白書林二十年，印章今領晉山川。',64,'全唐诗/poet.song.55000.json','["頭白書林二十年，印章今領晉山川。", "紫參可掘宜包貢，青鐵無多莫鑄錢。", "勸課農桑誠有道，折衝樽俎不臨邊。", "要知使者功多少，看取春郊處處田。"]'),
('aa6caab8-3784-4d39-a9d6-2336c4ef8af9','送顧子敦赴河東三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','家在江東不繫懷，愛民憂國有從來。',64,'全唐诗/poet.song.55000.json','["家在江東不繫懷，愛民憂國有從來。", "月斜汾沁催驛馬，雪暗岢嵐傳酒杯。", "塞上金湯惟粟粒，胸中水鏡是人材。", "遙知更解青牛句，一寸功名心已灰。"]'),
('e76238b2-b7f7-4cff-870d-b156dd1d454f','送顧子敦赴河東三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','攬轡都城風露秋，行臺無妾護衣篝。',64,'全唐诗/poet.song.55000.json','["攬轡都城風露秋，行臺無妾護衣篝。", "虎頭妙墨能頻寄，馬乳蒲萄不待求。", "上黨地寒應强飲，兩河民病要分憂。", "猶聞昔在軍興日，一馬人間費十牛。"]'),
('e0ac638a-f91e-449e-8393-bf3a3414fea9','司馬文正公挽詞四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','元祐開皇極，功歸用老成。',48,'全唐诗/poet.song.55000.json','["元祐開皇極，功歸用老成。", "惟深萬物表，不令四時行。", "日者傾三接，天乎奠兩楹。", "堂堂寧復有，埋玉慟佳城。"]'),
('6fc21ba8-40eb-4ebe-b296-9b32ae856cb5','司馬文正公挽詞四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','國在多艱日，人如大雅詩。',48,'全唐诗/poet.song.55000.json','["國在多艱日，人如大雅詩。", "忠清俱沒世，孝友是生知。", "加璧延諸老，櫜弓撫四夷。", "公身與宗社，同作太平基。"]'),
('8b9930db-42fa-4cb4-b3de-e76b1beb073e','司馬文正公挽詞四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','獻納無虛日，居然迹已陳。',48,'全唐诗/poet.song.55000.json','["獻納無虛日，居然迹已陳。", "清班區玉石，寶歷順星辰。", "更化思鳴鵙，遺書似獲麟。", "易名無異論，今代兩三人。"]'),
('ff88c778-2772-4f09-8eae-f02d831b06b0','司馬文正公挽詞四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','毀譽蓋棺了，于今名實尊。',48,'全唐诗/poet.song.55000.json','["毀譽蓋棺了，于今名實尊。", "哀榮有王命，終始酌民言。", "蟬冕三公府，深衣獨樂園。", "公心兩無累，憂國愛元元。"]'),
('b390dbd0-a3aa-4c97-bdfe-7bb8ee47483e','次韵子瞻武昌西山','黄庭堅','宋','宋诗','song-poetry','','[]','漫郎江南酒隠處，古木參天應手栽。',224,'全唐诗/poet.song.55000.json','["漫郎江南酒隠處，古木參天應手栽。", "石坳爲尊酌花鳥，自許作鼎調鹽梅。", "平生四海蘇太史，酒澆不下胸崔嵬。", "黄州副使坐閒散，諫疏無路通銀臺。", "鸚鵡洲前弄明月，江妃起舞襪生埃。", "次山醉魂招彷彿，步入寒溪金碧堆。", "洗湔塵痕飲嘉客，笑倚武昌江作罍。", "誰知文章照今古，野老爭席漁爭隈。", "鄧公勒銘留刻畫，刳剔銀鈎洗綠苔。", "琢磨十年煙雨晦，摸索一讀心眼開。", "謫去長沙憂鵩入，歸來杞國痛天摧。", "玉堂却對鄧公直，北門喚仗聽風雷。", "山川悠遠莫浪許，富貴崢嶸今鼎來。", "萬壑松聲如在耳，意不及此文生哀。"]'),
('a0dcbc73-6f6f-445f-9fb0-5065ca35b00c','子瞻詩句妙一世乃云效庭堅體蓋退之戲效孟郊樊宗師之比以文滑稽耳恐後生不解故次韵道之','黄庭堅','宋','宋诗','song-poetry','','[]','我詩如曹鄶，淺陋不成邦。',120,'全唐诗/poet.song.55000.json','["我詩如曹鄶，淺陋不成邦。", "公如大國楚，吞五湖三江。", "赤壁風月笛，玉堂雲霧窗。", "句法提一律，堅城受我降。", "枯松倒澗壑，波濤所舂撞。", "萬牛挽不前，公乃獨力扛。", "諸人方嗤點，渠非晁張雙。", "但懷相識察，牀下拜老龐。", "小兒未可知，客或許敦厖。", "誠堪婿阿巽，買紅纏酒缸。"]'),
('4eeda674-0151-4032-8aa1-337431c8047e','柳閎展如子瞻甥也其才德甚美有意于學故以桃李不言下自成蹊八字作詩贈之  其一','黄庭堅','宋','宋诗','song-poetry','','[]','柳君文武甚，睨視萬人豪。',48,'全唐诗/poet.song.55000.json','["柳君文武甚，睨視萬人豪。", "老氣鼓不作，卷旗解弓刀。", "上爲朝陽桐，下爲澗溪毛。", "囊中有美實，期子種蟠桃。"]'),
('e18f1a97-adc5-414d-8b2e-e45fa6b86047','柳閎展如子瞻甥也其才德甚美有意于學故以桃李不言下自成蹊八字作詩贈之  其二','黄庭堅','宋','宋诗','song-poetry','','[]','浮陽愧嘉魚，道傍多苦李。',48,'全唐诗/poet.song.55000.json','["浮陽愧嘉魚，道傍多苦李。", "古來賢達人，不爭咸陽市。", "吾子富春秋，日月東趨水。", "潛聖有玉音，聞道而已矣。"]'),
('41c2b7f4-f126-4e09-9cfc-abf922e8e46c','柳閎展如子瞻甥也其才德甚美有意于學故以桃李不言下自成蹊八字作詩贈之  其三','黄庭堅','宋','宋诗','song-poetry','','[]','霜威能折綿，風力欲冰酒。',48,'全唐诗/poet.song.56000.json','["霜威能折綿，風力欲冰酒。", "勤子來訪道，枵然我何有。", "寢興與時俱，由我屈伸肘。", "飯羹自知味，如此是道不。"]'),
('c68000e9-2471-45f3-af41-74c06ebf5b7a','柳閎展如子瞻甥也其才德甚美有意于學故以桃李不言下自成蹊八字作詩贈之  其四','黄庭堅','宋','宋诗','song-poetry','','[]','任世萬鈞重，載言以爲軒。',48,'全唐诗/poet.song.56000.json','["任世萬鈞重，載言以爲軒。", "空文誤來世，聖達欲無言。", "咸池浴日月，深宅養靈根。", "胸中浩然氣，一家同化元。"]'),
('310490fc-b0e5-49e7-a645-6052be6e9f7a','柳閎展如子瞻甥也其才德甚美有意于學故以桃李不言下自成蹊八字作詩贈之  其五','黄庭堅','宋','宋诗','song-poetry','','[]','陸沈百世師，寄食魯柳下。',48,'全唐诗/poet.song.56000.json','["陸沈百世師，寄食魯柳下。", "我今見諸孫，風味窺大雅。", "大雅久不作，圖王忽成霸。", "偉哉居移氣，蘭鮑在所化。"]'),
('751fb362-726b-46c5-a588-6981ba21dfd7','柳閎展如子瞻甥也其才德甚美有意于學故以桃李不言下自成蹊八字作詩贈之  其六','黄庭堅','宋','宋诗','song-poetry','','[]','聖學魯東家，恭惟同出自。',48,'全唐诗/poet.song.56000.json','["聖學魯東家，恭惟同出自。", "乘流去本遠，遂有作書肆。", "日中駕肩來，薄晚常掉臂。", "徒囂終無贏，歸矣求己事。"]'),
('b4aa2235-a8fe-4828-ae87-30b03668c08c','柳閎展如子瞻甥也其才德甚美有意于學故以桃李不言下自成蹊八字作詩贈之  其七','黄庭堅','宋','宋诗','song-poetry','','[]','清潤玉泉冰，高明秋景晴。',48,'全唐诗/poet.song.56000.json','["清潤玉泉冰，高明秋景晴。", "妙年勤翰墨，銀鉤爛縱橫。", "藍田生美璞，未琢價連城。", "思爲萬乘器，柱下貴晚成。"]'),
('8419c0a6-b9a3-41bb-b8c1-7b927b5e6978','柳閎展如子瞻甥也其才德甚美有意于學故以桃李不言下自成蹊八字作詩贈之  其八','黄庭堅','宋','宋诗','song-poetry','','[]','八方去求道，渺渺困多蹊。',48,'全唐诗/poet.song.56000.json','["八方去求道，渺渺困多蹊。", "歸來坐虛室，夕陽在吾西。", "君今秣高馬，夙駕先鳴雞。", "慎勿取我語，親行乃不迷。"]'),
('b780278c-a132-4cab-bec9-9ae3a66ab452','戲詠蠟梅二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','金蓓鎖春寒，惱人香未展。',24,'全唐诗/poet.song.56000.json','["金蓓鎖春寒，惱人香未展。", "雖無桃李顔，風味極不淺。"]'),
('a9563c42-b13c-4c47-b4cc-5e8626a7af57','戲詠蠟梅二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','體薰山麝臍，色染薔薇露。',24,'全唐诗/poet.song.56000.json','["體薰山麝臍，色染薔薇露。", "披拂不滿襟，時有暗香度。"]'),
('607091ad-babb-4248-a967-7fc736aa2dd3','蠟梅','黄庭堅','宋','宋诗','song-poetry','','[]','天工戲剪百花房，奪盡人工更有香。',32,'全唐诗/poet.song.56000.json','["天工戲剪百花房，奪盡人工更有香。", "埋玉地中成故物，折枝鏡裏憶新妝。"]'),
('493e6aef-8306-4a68-a592-01db083571b7','從張仲謀乞蠟梅','黄庭堅','宋','宋诗','song-poetry','','[]','聞君寺後野梅發，香蜜染成宮樣黄。',32,'全唐诗/poet.song.56000.json','["聞君寺後野梅發，香蜜染成宮樣黄。", "不擬折來遮老眼，欲知春色到池塘。"]'),
('46e1abc8-52b8-4837-98a6-1ff211e205f6','賈天錫惠寶薰乞詩予以兵衛森畫戟燕寢凝清香十字作詩報之  其一','黄庭堅','宋','宋诗','song-poetry','','[]','險心游萬仞，躁欲生五兵。',24,'全唐诗/poet.song.56000.json','["險心游萬仞，躁欲生五兵。", "隠几香一炷，靈臺湛空明。"]'),
('74cee307-d7e4-4efb-a07a-9fc18c0fd4d5','賈天錫惠寶薰乞詩予以兵衛森畫戟燕寢凝清香十字作詩報之  其二','黄庭堅','宋','宋诗','song-poetry','','[]','晝食鳥窺臺，宴坐日過砌。',24,'全唐诗/poet.song.56000.json','["晝食鳥窺臺，宴坐日過砌。", "俗氛無因來，煙霏作輿衛。"]'),
('281cf428-64b0-4799-b4b5-7bdf43800abe','賈天錫惠寶薰乞詩予以兵衛森畫戟燕寢凝清香十字作詩報之  其三','黄庭堅','宋','宋诗','song-poetry','','[]','石蜜化螺甲，榠樝煮水沈。',24,'全唐诗/poet.song.56000.json','["石蜜化螺甲，榠樝煮水沈。", "博山孤煙起，對此作森森。"]'),
('87de62a6-a3f4-4e29-9554-167a94c9e34c','賈天錫惠寶薰乞詩予以兵衛森畫戟燕寢凝清香十字作詩報之  其四','黄庭堅','宋','宋诗','song-poetry','','[]','輪囷香事已，郁郁著書畫。',24,'全唐诗/poet.song.56000.json','["輪囷香事已，郁郁著書畫。", "誰能入吾室，脫汝世俗械。"]'),
('404e7b17-4aa8-46ff-8f90-8d4d15ddc459','賈天錫惠寶薰乞詩予以兵衛森畫戟燕寢凝清香十字作詩報之  其五','黄庭堅','宋','宋诗','song-poetry','','[]','賈侯懷六韜，家有十二戟。',24,'全唐诗/poet.song.56000.json','["賈侯懷六韜，家有十二戟。", "天資喜文事，如我有香癖。"]'),
('414194e2-0835-4ae4-be83-73ae2a6d0ebe','賈天錫惠寶薰乞詩予以兵衛森畫戟燕寢凝清香十字作詩報之  其六','黄庭堅','宋','宋诗','song-poetry','','[]','林花飛片片，香歸銜泥燕。',24,'全唐诗/poet.song.56000.json','["林花飛片片，香歸銜泥燕。", "閉閤和春風，還尋蔚宗傳。"]'),
('c7571445-5186-4385-b345-07d3410aabdc','賈天錫惠寶薰乞詩予以兵衛森畫戟燕寢凝清香十字作詩報之  其七','黄庭堅','宋','宋诗','song-poetry','','[]','公虛采蘋宮，行樂在小寢。',24,'全唐诗/poet.song.56000.json','["公虛采蘋宮，行樂在小寢。", "香光當發聞，色敗不可稔。"]'),
('2a913c5c-0c83-41af-b7d6-ca4874e08f6c','賈天錫惠寶薰乞詩予以兵衛森畫戟燕寢凝清香十字作詩報之  其八','黄庭堅','宋','宋诗','song-poetry','','[]','牀帷夜氣馥，衣桁晚煙凝。',24,'全唐诗/poet.song.56000.json','["牀帷夜氣馥，衣桁晚煙凝。", "瓦溝鳴急雪，睡鴨照華燈。"]'),
('622296e3-c303-47b1-9cfd-d9a6782fa249','賈天錫惠寶薰乞詩予以兵衛森畫戟燕寢凝清香十字作詩報之  其九','黄庭堅','宋','宋诗','song-poetry','','[]','雉尾映鞭聲，金爐拂太清。',24,'全唐诗/poet.song.56000.json','["雉尾映鞭聲，金爐拂太清。", "班近聞香早，歸來學得成。"]'),
('0562bc34-a389-4b4d-a79c-2696d617437e','賈天錫惠寶薰乞詩予以兵衛森畫戟燕寢凝清香十字作詩報之  其一○','黄庭堅','宋','宋诗','song-poetry','','[]','衣篝麗紈綺，有待乃芬芳。',24,'全唐诗/poet.song.56000.json','["衣篝麗紈綺，有待乃芬芳。", "當念真富貴，自薰知見香。"]'),
('8f295d2e-bf34-4c3b-baba-39615bd37ff1','次韵張仲謀過酺池寺齋','黄庭堅','宋','宋诗','song-poetry','','[]','十年醉錦幄，酴醾照金沙。',240,'全唐诗/poet.song.56000.json','["十年醉錦幄，酴醾照金沙。", "敧眠春風底，不去留君家。", "是時應門兒，紫蘭茁其芽。", "只今將弟妹，嬉戲牽羊車。", "忽書滿窗紙，整整復斜斜。", "平生悲歡事，頭緒亂如麻。", "苟祿無補報，幾成來食嗟。", "喜君崇名節，青雲似有涯。", "我夢江湖去，釣船刺蘆花。", "江濱開園宅，畦蔗蒔梨柤。", "夢驚如昨日，炊玉困京華。", "公來或藜羹，愛我不疵瑕。", "深念煩鄉里，忍窮禁貸賒。", "夜談簾幕冷，霜月動金蛇。", "即是桃李月，春蟲語交加。", "我亦無酒飲，一室可盤蝸。", "要公共文字，朱墨勘舛差。", "非復少年日，聲名取嫮姱。", "諸阮有二妙，能詩定自嘉。", "何時來煮餠，蟹眼試官茶。"]'),
('133c2923-9f5b-42dd-a548-17f8fb85c907','常父惠示丁卯雪十四韵謹同韵賦之','黄庭堅','宋','宋诗','song-poetry','','[]','春皇賦上瑞，來寧黄屋憂。',240,'全唐诗/poet.song.56000.json','["春皇賦上瑞，來寧黄屋憂。", "下令走百神，大雲庇九丘。", "風聲將仁氣，艷艷生瓦溝。", "寒花舞零亂，表裏照皇州。", "千門委圭璧，曉日不肯收。", "元年冬無澤，穴處長螟蟊。", "兩宮初旰食，補衮獻良籌。", "有道四夷守，無征萬邦休。", "耆年秉國論，涇渭極分流。", "輟耒入班品，逸民盡歸周。", "股肱共一體，間不容戈矛。", "人材如金玉，同美異剛柔。", "正須衆賢和，乃可疏共吺。", "改絃張敝法，病十九已瘳。", "王指要不匿，蝕非日月羞。", "桑林請六事，河水問九疇。", "天意果然得，玄功與吾謀。", "此物有嘉德，占年在麥秋。", "近臣知天喜，玉色動冕旒。", "儒館無他事，作詩配崇丘。"]'),
('38ea581d-ea0e-438d-b134-678efe3ec8fc','詠雪奉呈廣平公','黄庭堅','宋','宋诗','song-poetry','','[]','連空春雪明如洗，忽憶江清水見沙。',64,'全唐诗/poet.song.56000.json','["連空春雪明如洗，忽憶江清水見沙。", "夜聽疏疏還密密，曉看整整復斜斜。", "風回共作婆娑舞，天巧能開頃刻花。", "正使盡情寒至骨，不妨桃李用年華。"]'),
('cd54e1e9-fc8e-4095-a54f-bb11afd9173d','次韵宋懋宗僦居甘泉坊雪後書懷','黄庭堅','宋','宋诗','song-poetry','','[]','漢家太史宋公孫，漫逐班行謁帝閽。',64,'全唐诗/poet.song.56000.json','["漢家太史宋公孫，漫逐班行謁帝閽。", "燕頷封侯空有相，蛾眉傾國自難昏。", "家徒四壁書侵坐，馬瘦三山葉擁門。", "安得風帆隨雪水，江南石上對漥尊。"]'),
('05a1e2d1-dbef-4772-bcd2-317d5bc6d695','和答子瞻和子由常父憶館中故事','黄庭堅','宋','宋诗','song-poetry','','[]','二蘇上連璧，三孔立分鼎。',168,'全唐诗/poet.song.56000.json','["二蘇上連璧，三孔立分鼎。", "少小看飛騰，中年嗟遠屏。", "風撼鶺鴒枝，波寒鴻雁影。", "天不椓斯文，俱來集臺省。", "日月黄道明，桃李春晝永。", "時平少犴獄，地禁絕蛙黽。", "頗懷修故事，文會陳果茗。", "當時羣玉府，人物殊秀整。", "下直馬闐闐，杯盤具俄頃。", "共醉凌波襪，誰窺投轄井。", "天網極恢疏，道山非簿領。", "何曾歸閉門，燈火生寒冷。", "欲觀太平象，復古望公等。", "賤子託後車，當煩煮湯餠。"]'),
('3c2a0f33-12a3-4a8e-9bc2-71023497ada0','雙井茶送子瞻','黄庭堅','宋','宋诗','song-poetry','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','人間風日不到處，天上玉堂森寶書。',64,'全唐诗/poet.song.56000.json','["人間風日不到處，天上玉堂森寶書。", "想見東坡舊居士，揮毫百斛瀉明珠。", "我家江南摘雲腴，落磑霏霏雪不如。", "爲君喚起黄州夢，獨載扁舟向五湖。"]'),
('8713e5f4-5dec-4fe7-a336-fd79c3ef4955','和答子瞻','黄庭堅','宋','宋诗','song-poetry','','[]','一月空迴長者車，報人問疾遣兒書。',64,'全唐诗/poet.song.56000.json','["一月空迴長者車，報人問疾遣兒書。", "翰林貽我東南句，窗間默坐得玄珠。", "故園溪友膾腹腴，遠包春茗問何如。", "玉堂下直長廊靜，爲君滿意說江湖。"]'),
('cee80cef-0ad2-4af9-bcce-a0aed3c9e458','子瞻以子夏丘明見戲聊復戲答','黄庭堅','宋','宋诗','song-poetry','','[]','化工見彈太早計，端爲失明能著書。',64,'全唐诗/poet.song.56000.json','["化工見彈太早計，端爲失明能著書。", "邇來似天會事發，淚睫見光猶隕珠。", "喜公新賜紫琳腴，上清虛皇對久如。", "請天還我讀書眼，願載軒轅訖鼎湖。"]'),
('ec81f4a2-7273-44e2-bf11-56f486818db5','省中烹茶懷子瞻用前韵','黄庭堅','宋','宋诗','song-poetry','','[]','閤門井不落第二，竟陵谷簾定誤書。',64,'全唐诗/poet.song.56000.json','["閤門井不落第二，竟陵谷簾定誤書。", "思公煮茗共湯鼎，蚯蚓竅生魚眼珠。", "置身九州之上腴，爭名燄中沃焚如。", "但恐次山胸壘塊，終便酒舫石魚湖。"]'),
('c46da165-0ce5-4db8-9a1a-2be770666120','以雙井茶送孔常父','黄庭堅','宋','宋诗','song-poetry','','[]','校經同省並門居，無日不聞公讀書。',64,'全唐诗/poet.song.56000.json','["校經同省並門居，無日不聞公讀書。", "故持茗椀澆舌本，要聽六經如貫珠。", "心知韵勝舌知腴，何似寶雲與真如。", "湯餠作魔應午寢，慰公渴夢吞江湖。"]'),
('25daf23f-8591-49cd-8071-93440aecdd19','常父答詩有煎點徑須煩綠珠之句復次韵戲答','黄庭堅','宋','宋诗','song-poetry','','[]','小鬟雖醜巧妝梳，掃地如鏡能檢書。',64,'全唐诗/poet.song.56000.json','["小鬟雖醜巧妝梳，掃地如鏡能檢書。", "欲買娉婷供煮茗，我無一斛明月珠。", "知公家亦闕掃除，但有文君對相如。", "正當爲公乞如願，作牋遠寄宮亭湖。"]'),
('2921816c-55b0-4ce2-bdb1-6fced212c8e1','戲呈孔毅父','黄庭堅','宋','宋诗','song-poetry','','[]','管城子無肉食相，孔方兄有絕交書。',64,'全唐诗/poet.song.56000.json','["管城子無肉食相，孔方兄有絕交書。", "文章功用不經世，何異絲窠綴露珠。", "校書著作頻詔除，猶能上車問何如。", "忽憶僧牀同野飯，夢隨秋雁到東湖。"]'),
('ccced3b9-5330-4e08-a6b7-d49251d7a1c6','謝黄從善司業寄惠山泉','黄庭堅','宋','宋诗','song-poetry','','["\u897f\u6e56"]','錫谷寒泉撱石俱，并得新詩蠆尾書。',64,'全唐诗/poet.song.56000.json','["錫谷寒泉撱石俱，并得新詩蠆尾書。", "急呼烹鼎供茗事，晴江急雨看跳珠。", "是功與世滌羶腴，令我屢空常晏如。", "安得左轓清潁尾，風爐煮茗卧西湖。"]'),
('903d1ed7-3416-4a9a-b9e2-36c18c822785','次韵奉酬劉景文河上見寄','黄庭堅','宋','宋诗','song-poetry','','[]','省中岑寂坐雲窗，忽有歸鴻拂建章。',64,'全唐诗/poet.song.56000.json','["省中岑寂坐雲窗，忽有歸鴻拂建章。", "珍重多情惟石友，琢磨佳句問潛郎。", "遙憐部曲風沙裏，不廢平生翰墨場。", "想見哦詩煮春茗，向人懷抱絕關防。"]'),
('7cb7c1b6-4c50-455a-bade-3a381b50c5fa','見諸人唱和酴醾詩輒次韵戲詠','黄庭堅','宋','宋诗','song-poetry','','[]','梅殘紅藥遲，此物共春歸。',72,'全唐诗/poet.song.56000.json','["梅殘紅藥遲，此物共春歸。", "名字因壺酒，風流付枕幃。", "墜鈿香徑草，飄雪浄垣衣。", "玉氣晴虹發，沉材鋸屑霏。", "直知多不厭，何忍摘令稀。", "常恨金沙學，顰時正可揮。"]'),
('cc60c876-f84b-484c-95d6-a907b3eb9c8a','次韵秦覯過陳無己書院觀鄙句之作','黄庭堅','宋','宋诗','song-poetry','','[]','陳侯大雅姿，四壁不治第。',96,'全唐诗/poet.song.56000.json','["陳侯大雅姿，四壁不治第。", "碌碌盆盎中，見此古罍洗。", "薄飯不能羹，牆陰老春薺。", "惟有文字性，萬古抱根柢。", "我學少師承，坎井可窺底。", "何因蒙賞味，相享當牲醴。", "試問求志君，文章自有體。", "玄鑰鎖靈臺，渠當爲君啟。"]'),
('9af61ffa-fe2b-4e73-beeb-74e377a30170','陳留市隠','黄庭堅','宋','宋诗','song-poetry','','[]','市井懷珠玉，往來人未逢。',48,'全唐诗/poet.song.56000.json','["市井懷珠玉，往來人未逢。", "乘肩嬌小女，邂逅此生同。", "養性霜刀在，閱人清鏡空。", "時時能舉酒，彈鑷送飛鴻。"]'),
('38b11710-ea5d-4877-b26f-ed30c4d2cbea','晁張和答秦覯五言予亦次韵','黄庭堅','宋','宋诗','song-poetry','','[]','山林與心違，日月使鬢換。',120,'全唐诗/poet.song.56000.json','["山林與心違，日月使鬢換。", "儒衣相詬病，文字奉娛玩。", "自古非一秦，六籍蓋多難。", "詩書或發冢，熟念令人惋。", "秦君銳本學，驥子已血汗。", "相期驂天衢，伯樂嘗一盼。", "士爲慾心縛，寸勇輒尺懦。", "要當觀此心，日照雲霧散。", "扶疏萬物影，宇宙同璀璨。", "置規豈惟君，亦自警弛慢。"]'),
('05e66ce4-716f-47af-a502-f51ce5b03c31','劉晦叔許洮河綠石硯','黄庭堅','宋','宋诗','song-poetry','','[]','久聞岷石鴨頭綠，可磨桂溪龍文刀。',32,'全唐诗/poet.song.56000.json','["久聞岷石鴨頭綠，可磨桂溪龍文刀。", "莫嫌文吏不知武，要試飽霜秋兔毫。"]'),
('a63b5326-e209-455b-b365-32d77ae6d5fb','以團茶洮州綠石硯贈无咎文潛','黄庭堅','宋','宋诗','song-poetry','','[]','晁子智囊可以括四海，張子筆端可以回萬牛。',156,'全唐诗/poet.song.56000.json','["晁子智囊可以括四海，張子筆端可以回萬牛。", "自我得二士，意氣傾九州。", "道山延閣委竹帛，清都太微望冕旒。", "貝宮胎寒弄明月，天網下罩一日收。", "此地要須無不有，紫皇訪問富春秋。", "晁无咎，贈君越侯所貢蒼玉璧，可烹玉塵試春色。", "澆君胸中過秦論，斟酌古今來活國。", "張文潛，贈君洮州綠石含風漪，能淬筆鋒利如錐。", "請書元祐開皇極，第入思齊訪落詩。"]'),
('1ff9c159-27f8-4689-916a-6d3047059a59','謝王仲至惠洮州礪石黄玉印材','黄庭堅','宋','宋诗','song-poetry','','[]','洮礪發劍虹貫日，印章不琢色蒸栗。',80,'全唐诗/poet.song.56000.json','["洮礪發劍虹貫日，印章不琢色蒸栗。", "磨礱頑鈍印此心，佳人持贈意堅密。", "佳人鬢彫文字工，藏書萬卷胸次同。", "日臨天閑豢真龍，新詩得意挾雷風。", "我貧無句當二物，看公倒海取明月。"]'),
('d399787e-90b0-49c9-8dbf-c2b379dc6ef7','次韵文潛同遊王舍人園','黄庭堅','宋','宋诗','song-poetry','','[]','移竹淇園下，買花洛水陽。',216,'全唐诗/poet.song.56000.json','["移竹淇園下，買花洛水陽。", "風煙二十年，花竹可迷藏。", "九衢流車馬，相值各匆忙。", "豈有道邊宅，靜居如寶坊。", "幅巾延客酒，妙歌小紅裳。", "主人有班綴，衣拂御爐香。", "常恐鷤鴂鳴，百草爲不芳。", "故作龜曳尾，頗深漆園方。", "初開蝸牛廬，中置師子牀。", "買田宛丘間，江漢起濫觴。", "今此百畝宮，冬溫夏清凉。", "身閒閱世故，宇靜發天光。", "安肯聲利場，牽黄臂老蒼。", "張侯筆瑞世，三秀麗齋房。", "作詩盛推賞，明珠計斛量。", "掃花坐晚吹，妙語益難忘。", "重游樊素病，捧心不能妝。", "來日猶可追，聽我歌楚狂。"]'),
('66f6589d-17c3-4b77-8ab2-351ce56586fa','卧陶軒','黄庭堅','宋','宋诗','song-poetry','','[]','陶公白頭卧，宇宙一北窗。',108,'全唐诗/poet.song.56000.json','["陶公白頭卧，宇宙一北窗。", "但聞窗風雨，平陸漫成江。", "卯金扛九鼎，把菊醉胡牀。", "城南晁正字，國器無等雙。", "日月麗宸極，大明朝萬邦。", "假版未通班，曉嚴夢逄逄。", "萬卷曲肱裏，胸中湛秋霜。", "亦有好事人，叩門提酒缸。", "欲眠不遣客，佳處更難忘。"]'),
('c19d5c71-ee85-4536-aff0-7b035fb921f0','次韵寄晁以道','黄庭堅','宋','宋诗','song-poetry','','[]','河漢牛與女，咫尺不得語。',108,'全唐诗/poet.song.56000.json','["河漢牛與女，咫尺不得語。", "歡然共秋盤，以茲不忘故。", "我友在天末，問天許見否。", "雲雨隔九關，日月不我與。", "念公坐臞禪，守心如縛虎。", "頗思携法喜，舉案饁南畝。", "不聞犯齋收，猶聞畫眉詡。", "良爲鼻祖來，渠伊爲伴侶。", "我有桂溪刀，聊憑東風去。"]'),
('3d3105e6-1a45-4962-902f-50e4f97e53cf','次以道韵寄范子夷子默','黄庭堅','宋','宋诗','song-poetry','','[]','鼓缶多秦聲，琵琶作胡語。',108,'全唐诗/poet.song.56000.json','["鼓缶多秦聲，琵琶作胡語。", "是中非神奇，根器如此故。", "范公秉文德，斷國極可否。", "至今筦樞機，大度而少與。", "蟬嫣世有人，風壑嘯兩虎。", "小心學忠孝，鄙事能壠畝。", "持論不籧篠，奉身謝誇詡。", "頗知城南園，文會英俊侶。", "何當休沐歸，懷茗就煎去。"]'),
('3b241349-ac06-4a88-80eb-7aa665f825c0','僧景宗相訪寄法王航禪師','黄庭堅','宋','宋诗','song-poetry','','[]','抱牘稍退鳬鶩行，倦禪時作橐駝坐。',64,'全唐诗/poet.song.56000.json','["抱牘稍退鳬鶩行，倦禪時作橐駝坐。", "忽憶頭陀雲外人，閉門作夏與僧過。", "一絲不掛魚脫淵，萬古同歸蟻旋磨。", "山中雨熟瓜芋田，喚取小僧休乞錢。"]'),
('013f8283-5bdc-40a1-9bb9-20faf5817e7b','次韵子瞻送顧子敦河北都運二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','儒者給事中，顧公甚魁偉。',120,'全唐诗/poet.song.56000.json','["儒者給事中，顧公甚魁偉。", "經明往行河，商略頗應史。", "勞人又費乏，國計安能已。", "成功渠有命，得人斯可喜。", "似聞阻饑餘，惡少驚邑里。", "啟鑰探珠金，奪懷取姝美。", "部中十盜發，一二書奏紙。", "西連魏三河，東盡齊四履。", "此豈小事哉，何但行治水。", "使民皆農桑，乃是真儒耳。"]'),
('237ffc45-a36b-4212-8c94-23b5a4cdb75d','次韵子瞻送顧子敦河北都運二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','今代顧虎頭，骨相自雄偉。',120,'全唐诗/poet.song.56000.json','["今代顧虎頭，骨相自雄偉。", "不令長天官，亦合丞御史。", "能貧安四壁，無慍可三已。", "昨來立清班，國士相顧喜。", "何因將使節，風日按千里。", "汲黯不居中，似非朝廷美。", "太任錄萬事，御坐留諫紙。", "發政恐傷民，天步薄冰履。", "蒼生憂其魚，南畝多被水。", "公行圖安集，信目勿信耳。"]'),
('d246ebaa-3df4-4a1e-996d-2b6edbd213d8','慈孝寺餞子敦席上奉同孔經父八韵','黄庭堅','宋','宋诗','song-poetry','','[]','日永知槐夏，雲黄喜麥秋。',96,'全唐诗/poet.song.56000.json','["日永知槐夏，雲黄喜麥秋。", "同朝國士集，賜沐吏功休。", "祇園冠蓋地，清與耳目謀。", "晴雲浮茗椀，飛雹落文楸。", "一客衆主人，醉此顧虎頭。", "虎頭持龍節，排河使東流。", "厥田惟上上，桑麻十數州。", "計功不汗馬，可致萬戶侯。"]'),
('78580508-1c45-4cf4-b753-26ea098a6ffe','次韵張昌言給事喜雨','黄庭堅','宋','宋诗','song-poetry','','[]','三雨全清六合塵，詩翁喜雨句凌雲。',64,'全唐诗/poet.song.56000.json','["三雨全清六合塵，詩翁喜雨句凌雲。", "垤漂戰蟻餘追北，柱擊乖龍有裂文。", "減去鮮肥憂玉食，徧宗河嶽起爐薰。", "聖功惠我豐年食，未有涓埃可報君。"]'),
('ff50b197-11f6-41fe-be1f-39692cbbd1df','送李德素歸舒城','黄庭堅','宋','宋诗','song-poetry','','[]','僧夏莫問途，麥秋宜煮餠。',156,'全唐诗/poet.song.56000.json','["僧夏莫問途，麥秋宜煮餠。", "北寺旬休歸，長廊六月冷。", "簟翻寒江浪，茶破蒼璧影。", "李侯爲我來，遽以歸期請。", "青衿廢詩書，白髮違定省。", "荒畦當鉏灌，蠹簡要籤整。", "挽衣不可留，决去事幽屏。", "天恢獵德網，日饎養賢鼎。", "此士落江湖，熟思令人癭。", "胸中吉祥宅，膜外榮辱境。", "婆娑萬物表，藏刃避肯綮。", "人生要當學，安宴不徹警。", "古來惟深地，相待汲脩綆。"]'),
('f4a478b8-d77d-42fe-8839-3a0dbacab00f','詠李伯時摹韓幹三馬次子由韵簡伯時兼寄李德素','黄庭堅','宋','宋诗','song-poetry','','[]','太史瑣窗雲雨垂，試開三馬拂蛛絲。',160,'全唐诗/poet.song.56000.json','["太史瑣窗雲雨垂，試開三馬拂蛛絲。", "李侯寫影韓幹墨，自有筆如沙畫錐。", "絕塵超日精爽緊，若失其一望路馳。", "馬官不語臂指揮，乃知仗下非新羈。", "吾嘗覽觀在坰馬，駑駘成列無權奇。", "緬懷胡沙英妙質，一雄可將千萬雌。", "决非皂櫪所成就，天驥生駒人得之。", "千金市骨今何有，士或不價五羖皮。", "李侯畫隠百僚底，初不自期人誤知。", "戲弄丹青聊卒歲，身如閱世老禪師。"]'),
('644c7b7d-d8d5-4ac2-a59c-27e79e61efb5','次韵子瞻和子由觀韓幹馬因論伯時畫天馬','黄庭堅','宋','宋诗','song-poetry','','[]','于闐花驄龍八尺，看雲不受絡頭絲。',160,'全唐诗/poet.song.56000.json','["于闐花驄龍八尺，看雲不受絡頭絲。", "西河驄作蒲萄錦，雙瞳夾鏡耳卓錐。", "長楸落日試天步，知有四極無由馳。", "電行山立氣深穩，可耐珠韉白玉羈。", "李侯一顧歎絕足，領略古法生新奇。", "一日真龍入圖畫，在坰群雄望風雌。", "曹霸弟子沙苑丞，喜作肥馬人笑之。", "李侯論幹獨不爾，妙畫骨相遺毛皮。", "翰林評書乃如此，賤肥貴瘦渠未知。", "況我平生賞神駿，僧中云是道林師。"]'),
('05b86e59-d4dc-42dc-b4fa-4edf4cc7ad1e','次韵答王眘中','黄庭堅','宋','宋诗','song-poetry','','[]','有身猶縛律，無夢到行雲。',72,'全唐诗/poet.song.56000.json','["有身猶縛律，無夢到行雲。", "俗裏光塵合，胸中涇渭分。", "我搴江南秀，一見空馬羣。", "夸士慕鍾鼎，寒儒守典墳。", "吾欲超萬古，乃如負山蚊。", "能來商略此，趺坐對爐芬。"]'),
('3d526b74-ac5b-4312-8b13-cf0a4df8a128','子瞻去歲春侍立邇英子由秋冬間相繼入侍作詩各述所懷予亦次韵四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','赤壁歸來入紫清，堂堂心在鬢彫零。',32,'全唐诗/poet.song.56000.json','["赤壁歸來入紫清，堂堂心在鬢彫零。", "江沙踏破青鞋底，却結絲絇侍禁庭。"]'),
('973f1023-9b1b-46f8-b80a-dc14890c295f','子瞻去歲春侍立邇英子由秋冬間相繼入侍作詩各述所懷予亦次韵四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','胸蟠萬卷夜光寒，筆倒三江硯滴乾。',32,'全唐诗/poet.song.56000.json','["胸蟠萬卷夜光寒，筆倒三江硯滴乾。", "大似不蒙稽古力，只今猶著侍臣冠。"]'),
('9cca8f4f-dd50-4780-ade3-63ab66451e8f','子瞻去歲春侍立邇英子由秋冬間相繼入侍作詩各述所懷予亦次韵四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','封掌絲綸罷記言，職親黄屋傍堯軒。',32,'全唐诗/poet.song.56000.json','["封掌絲綸罷記言，職親黄屋傍堯軒。", "雁行飛上猶回首，不受青雲富貴吞。"]'),
('e58a8d6a-9937-46eb-a2c9-6c4262aabaaf','子瞻去歲春侍立邇英子由秋冬間相繼入侍作詩各述所懷予亦次韵四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','樂天名位聊相似，却是初無富貴心。',32,'全唐诗/poet.song.56000.json','["樂天名位聊相似，却是初無富貴心。", "只欠小蠻樊素在，我知造物愛公深。"]'),
('a7a79106-d509-4332-b6dc-cd0a668263ca','再次韵四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','隆儒殿閣對橫經，咫尺清都雨露零。',32,'全唐诗/poet.song.56000.json','["隆儒殿閣對橫經，咫尺清都雨露零。", "見說文星環北極，人間無路仰天庭。"]'),
('77bacc06-d214-438c-97cd-a98bfe46193c','再次韵四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','風櫺倒影日光寒，堯日當中露正乾。',32,'全唐诗/poet.song.56000.json','["風櫺倒影日光寒，堯日當中露正乾。", "殿上給扶鳴漢履，螭頭簪筆見秦冠。"]'),
('0790be44-a1ed-413e-96da-62781bbded25','再次韵四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','萬國歸心天不言，諸儒爭席異臨軒。',32,'全唐诗/poet.song.56000.json','["萬國歸心天不言，諸儒爭席異臨軒。", "聖功典學形歌頌，更覺曹劉不足吞。"]'),
('82068e5b-6720-4a7b-bc48-64dfed476c95','再次韵四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','延和西路古槐陰，不隔朝宗夙夜心。',32,'全唐诗/poet.song.56000.json','["延和西路古槐陰，不隔朝宗夙夜心。", "公有胸中五色線，平生補衮用功深。"]'),
('eedababe-8639-4983-be6f-cebe4bcfac8f','次韵子瞻題郭熙畫秋山','黄庭堅','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','黄州逐客未賜環，江南江北飽看山。',128,'全唐诗/poet.song.56000.json','["黄州逐客未賜環，江南江北飽看山。", "玉堂卧對郭熙畫，發興已在青林間。", "郭熙官畫但荒遠，短紙曲折開秋晚。", "江村烟外雨脚明，歸雁行邊餘疊巘。", "坐思黄柑洞庭霜，恨身不如雁隨陽。", "熙今頭白有眼力，尚能弄筆映窗光。", "畫取江南好風日，慰此將老鏡中髮。", "但熙肯畫寬作程，十日五日一水石。"]'),
('3b1617f5-ee3f-463c-b429-c8f1892e9891','題郭熙山水扇','黄庭堅','宋','宋诗','song-poetry','','[]','郭熙雖老眼猶明，便面江山取意成。',32,'全唐诗/poet.song.56000.json','["郭熙雖老眼猶明，便面江山取意成。", "一段風烟且千里，解如明月逐人行。"]'),
('863175a9-ddac-41f0-9563-a052aaf624fb','題惠崇畫扇','黄庭堅','宋','宋诗','song-poetry','','[]','惠崇筆下開江面，萬里晴波向落暉。',32,'全唐诗/poet.song.56000.json','["惠崇筆下開江面，萬里晴波向落暉。", "梅影橫斜人不見，鴛鴦相對浴紅衣。"]'),
('92545eb4-0aa2-4456-a97c-989683922e2c','題鄭防畫夾五首  其一','黄庭堅','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','惠崇煙雨歸雁，坐我瀟湘洞庭。',28,'全唐诗/poet.song.56000.json','["惠崇煙雨歸雁，坐我瀟湘洞庭。", "欲喚扁舟歸去，故人言是丹青。"]'),
('500ec63c-a3c0-4404-9a62-983099b02af6','題鄭防畫夾五首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','能作山川遠勢，白頭惟有郭熙。',28,'全唐诗/poet.song.56000.json','["能作山川遠勢，白頭惟有郭熙。", "欲寫李成驟雨，惜無六幅鵝溪。"]'),
('a1ec7df7-4bc8-4cc0-a7fd-e3a8b2dbf50e','題鄭防畫夾五首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','徐生脫水雙魚，吹沫相看晚圖。',28,'全唐诗/poet.song.56000.json','["徐生脫水雙魚，吹沫相看晚圖。", "老矣箇中得計，作書遠寄江湖。"]'),
('55101547-0fc3-41c8-a17c-4779e8038dd2','題鄭防畫夾五首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','折葦枯荷共晚，紅榴苦竹同時。',28,'全唐诗/poet.song.56000.json','["折葦枯荷共晚，紅榴苦竹同時。", "睡鴨不知飄雪，寒雀四顧風枝。"]'),
('c237db79-ee90-4936-bb74-50252757f354','題鄭防畫夾五首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','子母猿號槲葉，山南山北危機。',28,'全唐诗/poet.song.56000.json','["子母猿號槲葉，山南山北危機。", "世故誰能樗里，彀中皆是由基。"]'),
('6f2caed8-6111-4d00-b09c-cb31e6e14a31','戲題小雀捕飛蟲畫扇','黄庭堅','宋','宋诗','song-poetry','','[]','小蟲心在一啄間，得失與世同輕重。',32,'全唐诗/poet.song.56000.json','["小蟲心在一啄間，得失與世同輕重。", "丹青妙處不可傳，輪扁斲輪如此用。"]'),
('3bb02701-aabd-447e-8902-44ad53fea306','題畫孔雀','黄庭堅','宋','宋诗','song-poetry','','[]','桄榔暗天蕉葉長，終露文章嬰世網。',32,'全唐诗/poet.song.56000.json','["桄榔暗天蕉葉長，終露文章嬰世網。", "故山桂子落秋風，無因雌雄青雲上。"]'),
('3a12cd9d-897b-41a8-9174-14ec78a4ad93','睡鴨','黄庭堅','宋','宋诗','song-poetry','','[]','山鷄照影空自愛，孤鸞舞鏡不作雙。',32,'全唐诗/poet.song.56000.json','["山鷄照影空自愛，孤鸞舞鏡不作雙。", "天下真成長會合，兩鳬相倚睡秋江。"]'),
('53d1c319-e486-4262-805d-1605db8b52df','小鴨','黄庭堅','宋','宋诗','song-poetry','','[]','小鴨看從筆下生，幻法生機全得妙。',32,'全唐诗/poet.song.56000.json','["小鴨看從筆下生，幻法生機全得妙。", "自知力小畏滄波，睡起晴沙依晚照。"]'),
('935509f0-d51e-41b4-ba4f-ae8637552085','題劉將軍雁二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','滕王蛺蝶雙穿花，東丹胡馬歕胡沙。',32,'全唐诗/poet.song.56000.json','["滕王蛺蝶雙穿花，東丹胡馬歕胡沙。", "祁連將軍一筆雁，生不並世俱名家。"]'),
('4016b18f-d5fb-428b-9c14-9c771e4129b1','題劉將軍雁二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','將軍一矢萬人看，雪灑晴空碎羽翰。',32,'全唐诗/poet.song.56000.json','["將軍一矢萬人看，雪灑晴空碎羽翰。", "乞與失羣沙宿雁，筆間千頃暮江寒。"]'),
('c51f7971-c17a-4678-aa09-a10aeeef1cb6','題劉將軍鵝','黄庭堅','宋','宋诗','song-poetry','','[]','箭羽不霑春水，籀文時印平沙。',28,'全唐诗/poet.song.56000.json','["箭羽不霑春水，籀文時印平沙。", "想見山陰書罷，舉羣驅向王家。"]'),
('c485d684-c2cf-4e05-8eaa-0f64000cce61','題晁以道雪雁圖','黄庭堅','宋','宋诗','song-poetry','','[]','飛雪灑蘆如銀箭，前雁驚飛後回眄。',32,'全唐诗/poet.song.56000.json','["飛雪灑蘆如銀箭，前雁驚飛後回眄。", "憑誰說與謝玄暉，莫道澄湖靜如練。"]'),
('f28efb83-a9cf-4a48-8fb0-ae4d342a0ff2','次韵子瞻題无咎所得與可竹二首粥字韵戲嘲无咎人字韵詠竹  其一','黄庭堅','宋','宋诗','song-poetry','','[]','十字供籠餠，一水試茗粥。',48,'全唐诗/poet.song.56000.json','["十字供籠餠，一水試茗粥。", "忽憶故人來，壁間風動竹。", "舍前粲戎葵，舍後荒苜蓿。", "此郎如竹瘦，十飯九不肉。"]'),
('12434d78-4180-4ebe-a4af-248d873b0f6f','次韵子瞻題无咎所得與可竹二首粥字韵戲嘲无咎人字韵詠竹  其二','黄庭堅','宋','宋诗','song-poetry','','[]','地下文夫子，風流絕此人。',48,'全唐诗/poet.song.56000.json','["地下文夫子，風流絕此人。", "能和晚煙色，幻出歲寒身。", "馬鬣松成拱，鵝溪墨尚新。", "應懷斲泥手，去作主林神。"]'),
('283ad201-19a5-4a78-b295-eeffac4dfb33','次韵文潛休沐不出二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','風塵車馬逐，得失兩關心。',48,'全唐诗/poet.song.56000.json','["風塵車馬逐，得失兩關心。", "惟有張仲蔚，門前蓬藋深。", "自公及歸沐，畢願詩書林。", "牆東作瘦馬，萬里氣駸駸。"]'),
('64a8afa2-37eb-4536-8b7a-4e5dc971840c','次韵文潛休沐不出二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','與世自少味，閉關非有心。',48,'全唐诗/poet.song.56000.json','["與世自少味，閉關非有心。", "戎葵一笑粲，露井百尺深。", "著書灑風雨，枯筆束如林。", "蘇公歎妙墨，逼人太駸駸。"]'),
('22339214-59ed-4a97-88b9-b24af44611f0','奉同子瞻韵寄定國','黄庭堅','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','風雲開古鏡，淮海熨冰紈。',120,'全唐诗/poet.song.56000.json','["風雲開古鏡，淮海熨冰紈。", "王孫醉短舞，羅襪步微瀾。", "老驥心雖在，白鷗盟已寒。", "斯人氣金玉，視世一鼠肝。", "南歸脫蟲蠱，入對隨孔鸞。", "忽以口語去，鼓船下驚湍。", "收身薄冰釋，置枕泰山安。", "后土花藥麗，海門天水寬。", "伐木思我友，知人良獨難。", "遙憐鬚鬢綠，猶復耐悲歡。"]'),
('1df820a0-adb9-41b9-bcbc-1b1eaa9e663e','次韵王定國揚州見寄','黄庭堅','宋','宋诗','song-poetry','','[]','清洛思君晝夜流，北歸何日片帆收。',64,'全唐诗/poet.song.56000.json','["清洛思君晝夜流，北歸何日片帆收。", "未生白髮猶堪酒，垂上青雲却佐州。", "飛雪堆盤鱠魚腹，明珠論斗煮雞頭。", "平生行樂自不惡，豈有竹西歌吹愁。"]'),
('85b4b0ad-6f9e-4d8d-ad41-6a5ba2bda21c','往歲過廣陵值早春嘗作詩云春風十里珠簾捲彷彿三生杜牧之紅藥梢頭初繭栗揚州風物鬢成絲今春有自淮南來者道揚州事戲以前韵寄王定國二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','淮南二十四橋月，馬上時時夢見之。',32,'全唐诗/poet.song.56000.json','["淮南二十四橋月，馬上時時夢見之。", "想得揚州醉年少，正圍紅袖寫烏絲。"]'),
('caebe95a-5035-4ba9-a470-a07eed9d0ccb','往歲過廣陵值早春嘗作詩云春風十里珠簾捲彷彿三生杜牧之紅藥梢頭初繭栗揚州風物鬢成絲今春有自淮南來者道揚州事戲以前韵寄王定國二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','日邊置論誠深矣，聖處時中乃得之。',32,'全唐诗/poet.song.56000.json','["日邊置論誠深矣，聖處時中乃得之。", "莫作秋蟲促機杼，貧家能有幾絇絲。"]'),
('5420f9d1-c6a7-4de7-bd60-85b064e70c75','次韵錢穆父贈松扇','黄庭堅','宋','宋诗','song-poetry','','[]','銀鉤玉唾明繭紙，松箑輕凉并送似。',64,'全唐诗/poet.song.56000.json','["銀鉤玉唾明繭紙，松箑輕凉并送似。", "可憐遠度幘溝婁，適堪今時褦襶子。", "丈人玉立氣高寒，三韓持節見神山。", "合得安期不死藥，使我蟬蛻塵埃間。"]'),
('ca9f81ba-fc10-4e22-aa7b-d398fc087b37','戲和文潛謝穆父松扇','黄庭堅','宋','宋诗','song-poetry','','[]','猩毛束筆魚網紙，松柎織扇清相似。',64,'全唐诗/poet.song.56000.json','["猩毛束筆魚網紙，松柎織扇清相似。", "動摇懷袖風雨來，想見僧前落松子。", "張侯哦詩松韵寒，六月火雲蒸肉山。", "持贈小君聊一笑，不須射雉彀黄間。"]'),
('fb37b087-2a41-44d2-baf3-9e66534713cd','謝鄭閎中惠高麗畫扇二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','會稽內史三韓扇，分送黄門畫省中。',32,'全唐诗/poet.song.56000.json','["會稽內史三韓扇，分送黄門畫省中。", "海外人煙來眼界，全勝博物注魚蟲。"]'),
('891c693f-0fd4-4c7b-9cab-088ae68a4c9d','謝鄭閎中惠高麗畫扇二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','蘋汀遊女能騎馬，傳道蛾眉畫不如。',32,'全唐诗/poet.song.56000.json','["蘋汀遊女能騎馬，傳道蛾眉畫不如。", "寶扇真成集陳隼，史臣今得殺青書。"]'),
('50aafbde-6b95-424e-9e0c-101dbf87834d','次韵王炳之惠玉版紙','黄庭堅','宋','宋诗','song-poetry','','[]','王侯鬚若緣坡竹，哦詩清風起空谷。',176,'全唐诗/poet.song.56000.json','["王侯鬚若緣坡竹，哦詩清風起空谷。", "古田小紙惠我百，信知溪翁能解玉。", "鳴踸千杵動秋山，裹糧萬里來輦轂。", "儒林丈人有蘇公，相如子雲再生蜀。", "往時翰墨頗橫流，此公歸來有邊幅。", "小楷多傳樂毅論，高詞欲奏雲門曲。", "不持去掃蘇公門，乃令小人今拜辱。", "去騷甚遠文氣卑，畫虎不成書勢俗。", "董狐南史一筆無，誤掌殺青司記錄。", "雖然此中有公議，或辱五鼎榮半菽。", "願公進德使見書，不敢求公米千斛。"]'),
('1d20c4db-a050-4a9a-9801-8bdd51d029cc','謝王炳之惠石香鼎','黄庭堅','宋','宋诗','song-poetry','','[]','薰爐宜小寢，鼎製琢晴嵐。',48,'全唐诗/poet.song.56000.json','["薰爐宜小寢，鼎製琢晴嵐。", "香潤雲生礎，煙明虹貫巖。", "法從空處起，人向鼻頭參。", "一炷聽秋雨，何時許對談。"]'),
('80a8ddcc-1bb3-4d60-b49b-c89c6ce8e404','次韵柳通叟寄王文通','黄庭堅','宋','宋诗','song-poetry','','[]','故人昔有凌雲賦，何意陸沈黄綬間。',64,'全唐诗/poet.song.56000.json','["故人昔有凌雲賦，何意陸沈黄綬間。", "頭白眼花行作吏，兒婚女嫁望還山。", "心猶未死杯中物，春不能朱鏡裏顔。", "寄語諸公肯湔祓，割雞今得近鄉關。"]'),
('499c8d1f-dd96-4444-a222-19d714be3b7f','送張天覺得登字','黄庭堅','宋','宋诗','song-poetry','','[]','張侯起巴渝，翼若垂天鵬。',96,'全唐诗/poet.song.56000.json','["張侯起巴渝，翼若垂天鵬。", "歷詆漢諸公，霜風拂觚稜。", "去國行萬里，淡如雲水僧。", "歸來頭亦白，小試不盡能。", "湖海尚豪氣，有人議陳登。", "持節三晉邦，典刑寄哀矜。", "公家有閒日，禪窟問香燈。", "因來敘行李，斬寄老崖藤。"]'),
('c797914f-af7d-417a-9d42-c1e10b26a0c0','次韵徐文將至國門見寄二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','槐催舉子著花黄，來食邯鄲道上粱。',32,'全唐诗/poet.song.56000.json','["槐催舉子著花黄，來食邯鄲道上粱。", "便欲掃牀懸麈尾，正愁喘月似燈光。"]'),
('7ff4aa69-c490-4669-8090-7e3034c25d20','次韵徐文將至國門見寄二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','千頭剖蚌明珠熟，百尺垂絲鱠縷長。',32,'全唐诗/poet.song.56000.json','["千頭剖蚌明珠熟，百尺垂絲鱠縷長。", "柳下石門君有此，可能衝雪厭清凉。"]'),
('28c0ceac-236d-41db-8add-b5d822b143d1','博士王揚休碾密雲龍同事十三人飲之戲作','黄庭堅','宋','宋诗','song-poetry','','[]','矞雲蒼璧小盤龍，貢包新樣出元豐。',104,'全唐诗/poet.song.56000.json','["矞雲蒼璧小盤龍，貢包新樣出元豐。", "王郎坦腹飯牀東，大官分物來婦翁。", "棘圍深鎖武成宮，談天進士雕虛空。", "鳴鳩欲雨喚雌雄，南嶺北嶺宮徵同。", "午窗欲眠視濛濛，喜君開包碾春風，注湯官焙香出籠。", "非君灌頂甘露椀，幾爲談天乾舌本。"]'),
('149da734-da72-4274-b3c3-e61aed784326','答黄冕仲索煎雙井并簡揚休','黄庭堅','宋','宋诗','song-poetry','','[]','江夏無雙乃吾宗，同舍頗似王安豐。',104,'全唐诗/poet.song.56000.json','["江夏無雙乃吾宗，同舍頗似王安豐。", "能澆茗椀湔祓我，風袂欲挹浮丘翁。", "吾宗落筆賞幽事，秋月下照澄江空。", "家山鷹爪是小草，敢與好賜雲龍同。", "不嫌水厄幸來辱，寒泉湯鼎聽松風，夜堂朱墨小燈籠。", "惜無纖纖來捧椀，惟倚新詩可傳本。"]'),
('8131043e-d75d-4a4e-b1c9-ab5ea54f9995','再答冕仲','黄庭堅','宋','宋诗','song-poetry','','[]','丘壑詩書雖數窮，田園芋栗頗時豐。',104,'全唐诗/poet.song.56000.json','["丘壑詩書雖數窮，田園芋栗頗時豐。", "小桃源口雨繁紅，春溪蒲稗沒鳬翁。", "投身世網夢歸去，摘山鼓聲雷隠空。", "秋堂一笑共燈火，與公草木臭味同。", "安用茗澆壘塊胸，他日過飯隨家風，買魚貫柳雞著籠。", "更當力貧開酒椀，走謁鄰翁稱子本。"]'),
('ccc7df6b-ce6d-44ca-b47b-0fa85fed9315','戲答陳元輿','黄庭堅','宋','宋诗','song-poetry','','[]','平生所聞陳汀州，蝗不入境年屢豐。',104,'全唐诗/poet.song.56000.json','["平生所聞陳汀州，蝗不入境年屢豐。", "東門拜書始識面，鬢髮幸未成老翁。", "官饔同盤厭腥膩，茶甌破睡秋堂空。", "自言不復娥眉夢，枯淡頗與小人同。", "但憂迎笑花枝紅，夜窗冷雨打斜風，秋衣沉水換薰籠。", "銀屏宛轉復宛轉，意根難拔如薤本。"]'),
('b8a6ae8d-0694-4a2c-8d48-4354a168b97d','再答元輿','黄庭堅','宋','宋诗','song-poetry','','[]','君不能入身帝城結子公，又不能擊强有如諸葛豐。',110,'全唐诗/poet.song.56000.json','["君不能入身帝城結子公，又不能擊强有如諸葛豐。", "法當顦顇百僚底，五十天涯一禿翁。", "問君何自今爲郎，便殿作賦聲摩空。", "偶然樽酒相勞苦，牛鐸調與黄鍾同。", "安得朱轓各憑熊，江南樓閣白蘋風，勸歸啼鳥曉窗籠。", "男兒邂逅功補衮，鳥倦歸巢葉歸本。"]'),
('a82960cc-8f3e-412c-9322-e86e5732052c','次韵冕仲考進士試卷','黄庭堅','宋','宋诗','song-poetry','','[]','少年迷翰墨，無異蟲蠹木。',180,'全唐诗/poet.song.56000.json','["少年迷翰墨，無異蟲蠹木。", "諸生程藝文，承詔當品目。", "牀敷設箱篚，賦納忽數束。", "變名混甲乙，謄寫失句讀。", "晝窗過白駒，夜几跋紅燭。", "鉤深思嘉魚，攻璞願良玉。", "談天用一律，呻訊壓重複。", "絲布澀難縫，快意忽破竹。", "聖言裨曲學，割衮綴邪幅。", "注金無全巧，竊發或中鵠。", "翟公辟廱老，薪槱茂棫樸。", "御史威降霜，行私不容粟。", "吏部提英鑒，片善蒙采錄。", "博士刈其楚，銓量頗三復。", "因人享成事，賤子真碌碌。"]'),
('72639263-b7a4-41d3-a4d8-88b38fa2e802','王聖美三子補中廣文生','黄庭堅','宋','宋诗','song-poetry','','[]','王家人物從來遠，今見諸孫總好賢。',64,'全唐诗/poet.song.56000.json','["王家人物從來遠，今見諸孫總好賢。", "三級定知魚尾進，一鳴已作雁行連。", "愧無藻鑑能推轂，願卷囊書當贈錢。", "歸去雄誇向兒姪，舍中犢子賸狂顛。"]'),
('106a943f-cc4e-44bb-932a-b11bc6e3aa19','次韵游景叔聞洮河捷報寄諸將四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','千仞溪中石轉雷，漢家萬騎擣虛回。',32,'全唐诗/poet.song.56000.json','["千仞溪中石轉雷，漢家萬騎擣虛回。", "定知獻馬胡雛入，看即稱觴都護來。"]'),
('186ce6fa-c59e-4d69-bc3a-f9bf56af40cb','次韵游景叔聞洮河捷報寄諸將四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','中原日月九夷知，不用禽胡釁鼓旗。',32,'全唐诗/poet.song.56000.json','["中原日月九夷知，不用禽胡釁鼓旗。", "更向天階舞干羽，降書剩破一年遲。"]'),
('4cf1f299-94c4-41e2-9bc4-0cc9521a5157','次韵游景叔聞洮河捷報寄諸將四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','漢得洮州箭有神，斬關禽敵不逡巡。',32,'全唐诗/poet.song.56000.json','["漢得洮州箭有神，斬關禽敵不逡巡。", "將軍快上屯田計，要納降胡十萬人。"]'),
('4641e2b0-93cb-4cb7-be6b-b07e8c948c24','次韵游景叔聞洮河捷報寄諸將四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','遙知一炬絕河津，生縛青宜不動塵。',32,'全唐诗/poet.song.56000.json','["遙知一炬絕河津，生縛青宜不動塵。", "付與山河印如斗，忍爲鼠子腹心人。"]'),
('aeb5b82f-2779-414b-8c94-bd0a3c6bd930','和游景叔月報三捷','黄庭堅','宋','宋诗','song-poetry','','[]','漢家飛將用廟謀，復我匹夫匹婦讎。',64,'全唐诗/poet.song.56000.json','["漢家飛將用廟謀，復我匹夫匹婦讎。", "真成折箠禽胡月，不是黄榆牧馬秋。", "幄中已斷匈奴臂，軍前可飲月氏頭。", "願見呼韓朝渭上，諸將不用萬戶侯。"]'),
('797c9744-77f4-4578-a529-f38e9eeac8bb','次韵崔伯易席上所賦因以贈行二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','迎新與送故，渠已不勝勤。',48,'全唐诗/poet.song.56000.json','["迎新與送故，渠已不勝勤。", "民賣腰間劍，公寬柱後文。", "諸郎投賜沐，高會惜臨分。", "去國雖千里，分憂即近君。"]'),
('b1ad0c12-f445-42de-931a-cd2da0748d74','次韵崔伯易席上所賦因以贈行二首  其二','黄庭堅','宋','宋诗','song-poetry','','["\u897f\u6e56"]','老惜交情別，追隨車馬勤。',48,'全唐诗/poet.song.56000.json','["老惜交情別，追隨車馬勤。", "臨朝思共理，治郡復斯文。", "訟息常休吏，民貧更勸分。", "西湖十頃月，自比漢封君。"]'),
('afa66c68-1ef9-45f3-950a-91789a80c2fb','同子瞻和趙伯充團練','黄庭堅','宋','宋诗','song-poetry','','[]','金玉堂中寂寞人，仙班時得共朝真。',64,'全唐诗/poet.song.56000.json','["金玉堂中寂寞人，仙班時得共朝真。", "兩宮無事安磐石，萬國歸心有老臣。", "家釀可供開口笑，侍兒工作捧心顰。", "醉鄉乃是安身處，付與升平作幸民。"]'),
('12f4f36c-2375-4784-b06f-12e5cac1c08c','戲答趙伯充勸莫學書及爲席子澤解嘲','黄庭堅','宋','宋诗','song-poetry','','[]','平生飲酒不盡味，五鼎餽肉如嚼蠟。',193,'全唐诗/poet.song.56000.json','["平生飲酒不盡味，五鼎餽肉如嚼蠟。", "我醉欲眠便遣客，三年窺牆亦面壁。", "空餘小來翰墨場，松煙兔穎傍明窗。", "偶隨兒戲灑墨汁，衆人許在崔杜行。", "晚學長沙小三昧，幻出萬物真成狂。", "龍蛇起陸雷破柱，自喜奇觀繞繩牀。", "家人駡笑寧有道，污染黄素敗粉牆。", "誠不如南鄰席明府，蛛網鎖硯蝸書梁。", "懷中探丸起九死，才術頗似漢太倉。", "感君詩句喚夢覺，邯鄲初未熟黄粱。", "身如朝露無牢强，翫此白駒過隙光。", "從此永明書百卷，自公退食一爐香。"]'),
('77ff07f7-dac4-4734-b1bf-1b7eda123333','謝景叔惠冬笋雍酥水梨三物','黄庭堅','宋','宋诗','song-poetry','','[]','玉人憐我長蔬食，走送厨珍自不嘗。',64,'全唐诗/poet.song.56000.json','["玉人憐我長蔬食，走送厨珍自不嘗。", "秦牛肥膩酥勝雪，漢苑甘泉梨得霜。", "冰底斲春生笋束，豹文解籜饌寒玉。", "見他桃李憶故園，饞獠應殘遶窗竹。"]'),
('1da41806-46e1-4318-aeff-6e8494e54018','再答景叔','黄庭堅','宋','宋诗','song-poetry','','[]','女三爲粲當獻王，三珍同盤乃得嘗。',64,'全唐诗/poet.song.56000.json','["女三爲粲當獻王，三珍同盤乃得嘗。", "甘泉下澆藜莧腸，令我詩句挾風霜。", "小人食珍敢取足，都城一飯炊白玉。", "賜錢千萬民猶饑，雪後排簷凍銀竹。"]'),
('9a2e6e6a-7fca-41e4-9911-9e12da5e5610','次韵幾復和答所寄','黄庭堅','宋','宋诗','song-poetry','','[]','海南海北夢不到，會合乃非人力能。',64,'全唐诗/poet.song.56000.json','["海南海北夢不到，會合乃非人力能。", "地褊未堪長袖舞，夜寒空對短檠燈。", "相看鬢髮時窺鏡，曾共詩書更曲肱。", "作箇生涯終未是，故山松長到天藤。"]'),
('e583034b-5d08-4aec-96c4-9dac38b8987b','寄上叔父夷仲三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','少年有功翰墨林，中歲作吏幾陸沉。',64,'全唐诗/poet.song.56000.json','["少年有功翰墨林，中歲作吏幾陸沉。", "庖丁解牛妙世故，監市履狶知民心。", "萬里書來兒女瘦，十月山行冰雪深。", "夢魂和月繞秦隴，漢節落毛何處尋。"]'),
('8aa39e7f-b9f6-4b4a-987b-acb90ec20300','寄上叔父夷仲三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','艱難聞道有歸音，部曲霜行璧月沉。',64,'全唐诗/poet.song.56000.json','["艱難聞道有歸音，部曲霜行璧月沉。", "王春正月調玉燭，使星萬里朝天心。", "頗令山海藏國用，乃見縣官恤民深。", "經心隴蜀封疆守，必有人材備訪尋。"]'),
('d79a0354-4571-42e0-bcb1-e5c4e9fea756','寄上叔父夷仲三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','關寒塞雪欲嗣音，燕雁拂天河鯉沉。',64,'全唐诗/poet.song.56000.json','["關寒塞雪欲嗣音，燕雁拂天河鯉沉。", "百書不如一見面，幾日歸來兩慰心。", "弓刀陌上望行色，兒女燈前語夜深。", "更懷父子東歸得，手種江頭柳十尋。"]'),
('c4033d8f-c53c-4a37-b128-2fdd982924e4','考試局與孫元忠博士竹間對窗夜聞元忠誦書聲調悲壯戲作竹枝歌三章和之  其一','黄庭堅','宋','宋诗','song-poetry','','[]','南窗讀書聲吾伊，北窗見月歌竹枝。',32,'全唐诗/poet.song.56000.json','["南窗讀書聲吾伊，北窗見月歌竹枝。", "我家白髮問烏鵲，他家紅妝占蛛絲。"]'),
('c6207fa4-a509-4029-b82b-d4b8b7c82ab6','考試局與孫元忠博士竹間對窗夜聞元忠誦書聲調悲壯戲作竹枝歌三章和之  其二','黄庭堅','宋','宋诗','song-poetry','','[]','屋山啼烏兒當歸，玉釵罥蛛郎馬嘶。',32,'全唐诗/poet.song.56000.json','["屋山啼烏兒當歸，玉釵罥蛛郎馬嘶。", "去時燈火正月半，階前雪消萱草齊。"]'),
('2fc6586f-f82d-433c-8ccf-73cdb3679687','考試局與孫元忠博士竹間對窗夜聞元忠誦書聲調悲壯戲作竹枝歌三章和之  其三','黄庭堅','宋','宋诗','song-poetry','','[]','勃姑夫婦喜相喚，街頭雪泥即漸乾。',32,'全唐诗/poet.song.56000.json','["勃姑夫婦喜相喚，街頭雪泥即漸乾。", "已放游絲高百尺，不應桃李尚春寒。"]'),
('5da0bc56-0a3e-47ad-a7b2-45f13a6b7034','觀伯時畫馬','黄庭堅','宋','宋诗','song-poetry','','[]','儀鸞供帳饕蝨行，翰林濕薪爆竹聲，風簾官燭淚縱橫。',72,'全唐诗/poet.song.56000.json','["儀鸞供帳饕蝨行，翰林濕薪爆竹聲，風簾官燭淚縱橫。", "木穿石槃未渠透，坐窗不遨令人瘦，貧馬百藖逢一豆。", "眼明見此玉花驄，徑思著鞭隨詩翁，城西野桃尋小紅。"]'),
('35c98b5c-297f-4a8d-8d72-ba2fbc456daa','題伯時畫揩痒虎','黄庭堅','宋','宋诗','song-poetry','','[]','猛虎肉醉初醒時，揩磨苛痒風助威。',32,'全唐诗/poet.song.56000.json','["猛虎肉醉初醒時，揩磨苛痒風助威。", "枯楠未覺草先低，木末應有行人知。"]'),
('e6c51e73-2528-4286-9a3a-74a843b3b14b','題伯時畫觀魚僧','黄庭堅','宋','宋诗','song-poetry','','[]','橫波一網腥城市，日暮江空煙水寒。',32,'全唐诗/poet.song.56000.json','["橫波一網腥城市，日暮江空煙水寒。", "當時萬事心已死，猶恐魚作故時看。"]'),
('7ab5dac7-024f-4d4f-a5ba-95fa79024872','題伯時畫頓塵馬','黄庭堅','宋','宋诗','song-poetry','','[]','竹頭搶地風不舉，文書堆案睡自語。',32,'全唐诗/poet.song.56000.json','["竹頭搶地風不舉，文書堆案睡自語。", "忽看高馬頓風塵，亦思歸家洗袍袴。"]'),
('8b9f7f94-8311-4566-a356-80e5398b883c','題伯時畫嚴子陵釣灘','黄庭堅','宋','宋诗','song-poetry','','[]','平生久要劉文叔，不肯爲渠作三公。',32,'全唐诗/poet.song.56000.json','["平生久要劉文叔，不肯爲渠作三公。", "能令漢家重九鼎，桐江波上一絲風。"]'),
('962e6688-ff88-4e40-8d06-9e460b46a5d3','題伯時畫松下淵明','黄庭堅','宋','宋诗','song-poetry','','[]','南渡誠草草，長沙慰艱難。',72,'全唐诗/poet.song.56000.json','["南渡誠草草，長沙慰艱難。", "終風霾八表，半夜失前山。", "遠公香火社，遺民文字禪。", "雖非老翁事，幽尚亦可觀。", "松風自度曲，我琴不須彈。", "客來欲開說，觴至不得言。"]'),
('9b77810c-a5e8-4dd4-b5af-269551ac7a42','出禮部試院王才元惠梅花三種皆妙絕戲答三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','城南名士遣春來，三月乃見臘前梅。',32,'全唐诗/poet.song.56000.json','["城南名士遣春來，三月乃見臘前梅。", "定知鎖著江南客，故放綠陰春晚回。"]'),
('46845e29-9882-4126-9ae9-940fd36183cc','出禮部試院王才元惠梅花三種皆妙絕戲答三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','舍人梅塢無關鎖，携酒俗人來未曾。',32,'全唐诗/poet.song.56000.json','["舍人梅塢無關鎖，携酒俗人來未曾。", "舊時愛菊陶彭澤，今作梅花樹下僧。"]'),
('c1f86628-6f33-4e8d-a3bb-3b454a7704e7','出禮部試院王才元惠梅花三種皆妙絕戲答三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','病夫中歲屏杯杓，百葉緗梅觸撥人。',32,'全唐诗/poet.song.56000.json','["病夫中歲屏杯杓，百葉緗梅觸撥人。", "拂殺官黄春有思，滿城桃李不能春。"]'),
('250a0a96-da6d-4afd-9ae7-5f14578bc389','王立之承奉詩報梅花已落盡次韵戲答','黄庭堅','宋','宋诗','song-poetry','','[]','南枝北枝春事休，榆錢可穿柳带柔。',32,'全唐诗/poet.song.56000.json','["南枝北枝春事休，榆錢可穿柳带柔。", "定是沈郎作詩瘦，不應春能生許愁。"]'),
('27e6fef7-ad4e-4282-bd8b-3cb0c53d2630','乞姚花二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','正是風光嬾困時，姚黄開晚落應遲。',32,'全唐诗/poet.song.56000.json','["正是風光嬾困時，姚黄開晚落應遲。", "欲雕好句乞春色，日歷如山不到詩。"]'),
('f520ecbd-57d6-487f-861b-aad3b1334140','乞姚花二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','青春日月鳥飛過，汗簡文書山疊重。',32,'全唐诗/poet.song.56000.json','["青春日月鳥飛過，汗簡文書山疊重。", "乞取好花天上看，宮衣黄带御爐烘。"]'),
('99f39aaa-2948-4a61-91ea-589645c93836','效王仲至少監詠姚花用其韵四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','映日低風整復斜，綠玉眉心黄袖遮。',32,'全唐诗/poet.song.56000.json','["映日低風整復斜，綠玉眉心黄袖遮。", "大梁城裏雖罕見，心知不是牛家花。"]'),
('78556485-19a2-48ce-8fd2-78cc0d1f6c1b','效王仲至少監詠姚花用其韵四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','九疑山中萼綠華，黄雲承襪到羊家。',32,'全唐诗/poet.song.56000.json','["九疑山中萼綠華，黄雲承襪到羊家。", "真筌蟲蝕詩句斷，猶託餘情開此花。"]'),
('4e4df7d3-f400-4e00-adf1-4d0570792772','效王仲至少監詠姚花用其韵四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','仙衣襞積駕黄鵠，草木無光一笑開。',32,'全唐诗/poet.song.56000.json','["仙衣襞積駕黄鵠，草木無光一笑開。", "人間風日不可奈，故待成陰葉下來。"]'),
('5555f605-a75c-4c70-931f-afa889a9632c','效王仲至少監詠姚花用其韵四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','湯沐冰肌照春色，海牛壓簾風不開。',32,'全唐诗/poet.song.56000.json','["湯沐冰肌照春色，海牛壓簾風不開。", "直言紅塵無路入，猶傍蜂鬚蝶翅來。"]'),
('6c64a7d7-cad1-4caf-aef6-eeddc8932df1','寄杜家父二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','紅紫爭春觸處開，九衢終日犢車雷。',32,'全唐诗/poet.song.56000.json','["紅紫爭春觸處開，九衢終日犢車雷。", "閒情欲被春將去，鳥喚花驚只麽回。"]'),
('7f1eb1cd-3756-474e-8f1f-aea1efcce654','寄杜家父二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','風塵點汙青春面，自汲寒泉洗醉紅。',32,'全唐诗/poet.song.56000.json','["風塵點汙青春面，自汲寒泉洗醉紅。", "徑欲題詩嫌浪許，杜郎覓句有新功。"]'),
('dfa55711-93a4-4f9e-a47c-10dbf27d8ba3','王才元舍人許牡丹求詩','黄庭堅','宋','宋诗','song-poetry','','[]','聞道潛溪千葉紫，主人不剪要題詩。',32,'全唐诗/poet.song.56000.json','["聞道潛溪千葉紫，主人不剪要題詩。", "欲搜佳句恐春老，試遣七言賒一枝。"]'),
('ab41b32f-067a-487a-926b-61c67b225b59','謝王舍人剪送狀元紅','黄庭堅','宋','宋诗','song-poetry','','[]','清香拂袖剪來紅，似繞名園曉露叢。',32,'全唐诗/poet.song.56000.json','["清香拂袖剪來紅，似繞名園曉露叢。", "欲作短章憑阿素，緩歌誇與落花風。"]'),
('ad304a1b-1017-4ccc-8f55-e5b1757a25c6','戲答陳季常寄黄州山中連理松枝二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','故人折松寄千里，想聽萬壑風泉音。',32,'全唐诗/poet.song.56000.json','["故人折松寄千里，想聽萬壑風泉音。", "誰言五鬣蒼煙面，猶作人間兒女心。"]'),
('a19e350f-d3b5-4948-a8f7-614258a19e1d','戲答陳季常寄黄州山中連理松枝二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','老松連枝亦偶然，紅紫事退獨參天。',32,'全唐诗/poet.song.56000.json','["老松連枝亦偶然，紅紫事退獨參天。", "金沙灘頭鎖子骨，不妨隨俗暫嬋娟。"]'),
('531284ea-4f81-4bf0-bb80-8888a8aa07b8','次韵子瞻送李廌','黄庭堅','宋','宋诗','song-poetry','','[]','驥子墮地追風日，未試千里誰能識。',96,'全唐诗/poet.song.56000.json','["驥子墮地追風日，未試千里誰能識。", "習之實錄葬皇祖，斯文如女有正色。", "今年持橐佐春官，遂失此人難塞責。", "雖然一鬨有奇偶，博懸于投不在德。", "君看巨浸朝百川，此豈有意潢潦前。", "願爲霧豹懷文隠，莫愛風蟬蛻骨仙。"]'),
('e83f8ef3-fe44-43be-a726-835b7c33bc97','次韵宋懋宗三月十四日到西池都人盛觀翰林公出遨','黄庭堅','宋','宋诗','song-poetry','','[]','金狨繫馬曉鶑邊，不比春江上水船。',64,'全唐诗/poet.song.56000.json','["金狨繫馬曉鶑邊，不比春江上水船。", "人語車聲喧法曲，花光樓影倒晴天。", "人間化鶴三千歲，海上看羊十九年。", "還作遨頭驚俗眼，風流文物屬蘇仙。"]'),
('903ef739-be1e-4eb6-9e79-4aaea164dd43','韓獻肅公挽詞三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','鬰鬰高陽里，生才世不孤。',48,'全唐诗/poet.song.56000.json','["鬰鬰高陽里，生才世不孤。", "八龍歸月旦，三鳳繼天衢。", "梁壞吾安仰，人亡道固癯。", "空令湖海士，愁絕奠生芻。"]'),
('195b56c1-efc3-4719-b99a-ba36eb6aa88d','韓獻肅公挽詞三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','物産原希世，風流更折衝。',48,'全唐诗/poet.song.56000.json','["物産原希世，風流更折衝。", "决疑京兆尹，富國大司農。", "遠業終三事，仁聲達九宗。", "方祈酌周斗，何意輟秦舂。"]'),
('e537abcd-575f-46df-980f-60ddfa65c543','韓獻肅公挽詞三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','淚盡才難日，斯人遽隕傾。',48,'全唐诗/poet.song.56000.json','["淚盡才難日，斯人遽隕傾。", "冰枝憂木稼，食昴恨長庚。", "名與具茨重，心如潁水清。", "堂堂萬夫表，直作閉佳城。"]'),
('0d0f75a5-8941-49d6-adc3-6a5dda966a2b','次韵子瞻以紅带寄王宣義','黄庭堅','宋','宋诗','song-poetry','','[]','參軍但有四立壁，初無臨江千木奴。',160,'全唐诗/poet.song.56000.json','["參軍但有四立壁，初無臨江千木奴。", "白頭不是折腰具，桐帽棕鞋稱老夫。", "滄江鷗鷺野心性，陰壑虎豹雄牙鬚。", "鷫鷞作裘初服在，猩血染带鄰翁無。", "昨來杜鵑勸歸去，更待把酒聽提壺。", "當今人材不乏使，天上二老須人扶。", "兒無飽飯尚勤書，婦無複褌且著襦。", "社甕可漉溪可漁，更問黄雞肥與癯。", "林間醉著人伐木，猶夢官下聞追呼。", "萬釘圍腰莫愛渠，富貴安能潤黄壚。"]'),
('87de952e-27e0-4f3c-846a-148e35f6335f','聽宋宗儒摘阮歌','黄庭堅','宋','宋诗','song-poetry','','[]','翰林尚書宋公子，文采風流今尚爾。',216,'全唐诗/poet.song.56000.json','["翰林尚書宋公子，文采風流今尚爾。", "自疑耆域是前身，囊中探丸起人死。", "貌如千歲枯松枝，落魄酒中無定止。", "得錢百萬送酒家，一笑不問今餘幾。", "手揮琵琶送飛鴻，促絃聒醉驚客起。", "寒蟲催織月籠秋，獨雁叫羣天拍水。", "楚國羈臣放十年，漢宮佳人嫁千里。", "深閨洞房語恩怨，紫燕黄鸝韵桃李。", "楚狂行歌驚市人，漁父拏舟在葭葦。", "問君枯木著朱繩，何能道人意中事。", "君言此物傳數姓，玄璧庚庚有橫理。", "閉門三月傳國工，身今親見阮仲容。", "我有江南一丘壑，安得與君醉其中，曲肱聽君寫松風。"]'),
('c7cb328a-69d0-4b4a-8f08-92d708e6569c','自門下後省歸卧酺池寺觀盧鴻草堂圖','黄庭堅','宋','宋诗','song-poetry','','[]','黄塵逆帽馬辟易，歸來下簾卧書空。',32,'全唐诗/poet.song.56000.json','["黄塵逆帽馬辟易，歸來下簾卧書空。", "不知繡鞍萬人立，何如盧郎駕飛鴻。"]'),
('c7e1a616-064d-447c-b194-ee0a5b2a6c72','題子瞻寺壁小山枯木二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','爛腸五斗對獄吏，白髮千丈濯滄浪。',32,'全唐诗/poet.song.56000.json','["爛腸五斗對獄吏，白髮千丈濯滄浪。", "却來獻納雲臺表，小山桂枝不相忘。"]'),
('e562e82e-7bc4-44dd-aecf-45a242fbd4be','題子瞻寺壁小山枯木二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','海內文章非畫師，能回筆力作枯枝。',32,'全唐诗/poet.song.56000.json','["海內文章非畫師，能回筆力作枯枝。", "豫章從小有梁棟，也似鄭公雙鬢絲。"]'),
('ee494016-e7b8-4def-9973-1dcaa0724f1b','題子瞻枯木','黄庭堅','宋','宋诗','song-poetry','','["\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','折衝儒墨陣堂堂，書入顔楊鴻雁行。',32,'全唐诗/poet.song.56000.json','["折衝儒墨陣堂堂，書入顔楊鴻雁行。", "胸中元自有丘壑，故作老木蟠風霜。"]'),
('2c995d08-02e9-4edf-9610-ae82091562ff','和子瞻戲書伯時畫好頭赤','黄庭堅','宋','宋诗','song-poetry','','[]','李侯畫骨不畫肉，筆下馬生如破竹。',64,'全唐诗/poet.song.56000.json','["李侯畫骨不畫肉，筆下馬生如破竹。", "秦駒雖入天仗圖，猶恐真龍在空谷。", "精神權奇汗溝赤，有頭赤烏能逐日。", "安得身爲漢都護，三十六城看歷歷。"]'),
('4cef1f01-0172-41c5-8986-78e9fcd9560e','詠伯時畫太初所獲大宛虎脊天馬圖','黄庭堅','宋','宋诗','song-poetry','','[]','筆端那有此，千里在胸中。',48,'全唐诗/poet.song.56000.json','["筆端那有此，千里在胸中。", "四蹄雷電去，一顧馬羣空。", "誰能乘此物，超俗駕長風。", "逸材歸轡勒，歲在執徐同。"]'),
('597f61da-da4a-4967-bf7e-609d87e8532c','詠伯時畫馮奉世所獲大宛象龍圖','黄庭堅','宋','宋诗','song-poetry','','[]','上黨良家子，挽强如屈肘。',48,'全唐诗/poet.song.56000.json','["上黨良家子，挽强如屈肘。", "三十學春秋，豈爲莎車首。", "誰言馮光祿，不如甘延壽。", "雖無千戶封，乃得六龍友。"]'),
('1b083027-dbfe-469f-aed5-853c51d4ba82','題竹石牧牛','黄庭堅','宋','宋诗','song-poetry','','[]','野次小崢嶸，幽篁相倚綠。',48,'全唐诗/poet.song.56000.json','["野次小崢嶸，幽篁相倚綠。", "阿童三尺箠，御此老觳觫。", "石吾甚愛之，勿遣牛礪角。", "牛礪角尚可，牛鬭殘我竹。"]'),
('96bf81b7-f10c-4a89-ad31-4df2d7a4ba81','題伯時天育驃騎圖二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','玉花照夜今無種，櫪上追風亦不傳。',32,'全唐诗/poet.song.56000.json','["玉花照夜今無種，櫪上追風亦不傳。", "想見真龍如此筆，蒺藜沙晚草迷川。"]'),
('f5912ebd-a8ce-4f66-aa1e-2a8bf5a3da78','題伯時天育驃騎圖二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','明窗槃礴萬物表，寫出人間真乘黄。',32,'全唐诗/poet.song.56000.json','["明窗槃礴萬物表，寫出人間真乘黄。", "邂逅今身猶姓李，可非前世江都王。"]'),
('6c95eff1-bd0a-43b2-9594-98933e06b18d','姨母李夫人墨竹二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','深閨靜几試筆墨，白頭腕中百斛力。',32,'全唐诗/poet.song.56000.json','["深閨靜几試筆墨，白頭腕中百斛力。", "榮榮枯枯皆本色，懸之高堂風動壁。"]'),
('3f07b4d0-832c-4e8d-85c5-6b1ee57b203a','姨母李夫人墨竹二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','小竹扶疏大竹枯，筆端真有造化爐。',32,'全唐诗/poet.song.56000.json','["小竹扶疏大竹枯，筆端真有造化爐。", "人間俗氣一點無，健婦果勝大丈夫。"]'),
('6827ecf3-fa40-4536-a500-72762af8523d','次韵子瞻子由題憩寂圖二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','松寒風雨石骨瘦，法窟寂寥僧定時。',32,'全唐诗/poet.song.56000.json','["松寒風雨石骨瘦，法窟寂寥僧定時。", "李侯有句不肯吐，淡墨寫出無聲詩。"]'),
('363dd643-35b4-4de2-b20d-809dcb381a0d','次韵子瞻子由題憩寂圖二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','龍眠不似虎頭癡，筆妙天機可並時。',32,'全唐诗/poet.song.56000.json','["龍眠不似虎頭癡，筆妙天機可並時。", "蘇仙漱墨作蒼石，應解種花開此詩。"]'),
('b9247d1a-adbe-4afa-b536-976ddff882f5','次韵答曹子方雜言','黄庭堅','宋','宋诗','song-poetry','','[]','酺池寺，湯餠一齋盂，曲肱懶著書。',180,'全唐诗/poet.song.56000.json','["酺池寺，湯餠一齋盂，曲肱懶著書。", "騎馬天津看逝水，滿船風月憶江湖。", "往時盡醉冷卿酒，侍兒琵琶春風手。", "竹間一夜鳥聲春，明朝醉起雪塞門。", "當年聞說冷卿客，黄鬚鄴下曹將軍。", "挽弓石八不好武，讀書卧看三峰雲。", "誰憐相逢十載後，釜裏生魚甑生塵。", "冷卿白首大官寺，樽前不復如花人。", "曹將軍，江湖之上可相忘，舂鉏對立鴛鴦雙。", "無機與游不亂行，何時解纓濯滄浪。", "喚取張侯來平章，烹茶煮餠坐僧房。"]'),
('38c7bf87-68a9-4044-a85f-c79920e688fe','次韵子瞻和王子立風雨敗書屋有感','黄庭堅','宋','宋诗','song-poetry','','[]','婦翁不可撾，王郎非嬌客。',144,'全唐诗/poet.song.56000.json','["婦翁不可撾，王郎非嬌客。", "十年爲從學，苦淡共陻厄。", "燕雀嗤鴻漸，犬羊睨麟獲。", "遇逢涇渭分，昨夢春冰釋。", "平生五車書，才吐二三策。", "已作謗薰天，金朱果何益。", "君窮一窗下，風雨更削跡。", "詩工知學進，詞苦見意迫。", "俗情傲秦贅，婦舍不煖席。", "南冶從東家，不聞被嘲劇。", "師儒並世難，日月過箭疾。", "公今未有田，把筆耕六籍。"]'),
('a4d31b8d-54d6-4d82-aa2d-75b3e1c85080','嘲小德','黄庭堅','宋','宋诗','song-poetry','','[]','中年舉兒子，漫種老生涯。',48,'全唐诗/poet.song.56000.json','["中年舉兒子，漫種老生涯。", "學語囀春鳥，塗窗行暮鴉。", "欲嗔王母惜，稍慧女兄誇。", "解著潛夫論，不妨無外家。"]'),
('281405cd-31d6-416b-89f4-06629581fcb6','戲答張祕監饋羊','黄庭堅','宋','宋诗','song-poetry','','[]','細肋柔毛飽卧沙，煩公遣騎送寒家。',32,'全唐诗/poet.song.56000.json','["細肋柔毛飽卧沙，煩公遣騎送寒家。", "忍令無罪充庖宰，留與兒童駕小車。"]'),
('e4d951bb-ba5b-47db-9d0b-bb5a17de1970','戲答王定國題門兩絕句  其一','黄庭堅','宋','宋诗','song-poetry','','[]','非復三五少年日，把酒償春頰生紅。',32,'全唐诗/poet.song.56000.json','["非復三五少年日，把酒償春頰生紅。", "白鷗入羣頗相委，不謂驚起來賓鴻。"]'),
('41fd28d0-6eb3-4190-92c9-fab4a744fed8','戲答王定國題門兩絕句  其二','黄庭堅','宋','宋诗','song-poetry','','[]','頗知歌舞無竅鑿，我心塊然如帝江。',32,'全唐诗/poet.song.56000.json','["頗知歌舞無竅鑿，我心塊然如帝江。", "花裏雄蜂雌蛺蝶，同時本自不作雙。"]'),
('25f9ac3c-d83e-4f87-8a46-6b4d50ca3821','情人怨戲效徐庾慢體三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','秋水無言度，荷花稱意紅。',48,'全唐诗/poet.song.56000.json','["秋水無言度，荷花稱意紅。", "主人敬愛客，催喚出房籠。", "一斛明珠曲，何時落塞鴻。", "莫藏春笋手，且爲剝蓮蓬。"]'),
('4026b801-d51a-4c93-9e04-ff504beb539c','情人怨戲效徐庾慢體三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','翡翠釵梁碧，石榴裙摺紅。',48,'全唐诗/poet.song.56000.json','["翡翠釵梁碧，石榴裙摺紅。", "隙光斜斗帳，香字冷薰籠。", "聞道西飛燕，將隨北固鴻。", "鴛鴦會獨宿，風雨打船蓬。"]'),
('62fac7ea-8577-4d60-8bb2-1b93b896af73','情人怨戲效徐庾慢體三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','障羞羅袂薄，承汗領巾紅。',48,'全唐诗/poet.song.56000.json','["障羞羅袂薄，承汗領巾紅。", "晚風斜蠆髮，逸艷照窗籠。", "胡琴抱明月，寶瑟陣歸鴻。", "倚壁生蛛網，年光如轉蓬。"]'),
('5ce73044-5e8b-47c6-a0d1-641939a9aca3','呈外舅孫莘老二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','九陌黄塵烏帽底，五湖春水白鷗前。',32,'全唐诗/poet.song.56000.json','["九陌黄塵烏帽底，五湖春水白鷗前。", "扁舟不爲鱸魚去，收取聲名四十年。"]');
